-- ----------------------------
-- Table structure for ai_interaction
-- ----------------------------
DROP TABLE IF EXISTS `ai_interaction`;
CREATE TABLE `ai_interaction`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL,
  `session_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会话ID',
  `context_work_id` bigint(0) NULL DEFAULT NULL COMMENT '关联作品ID',
  `question` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户问题(ASR)',
  `answer` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'AI回答',
  `answer_audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '回答音频URL',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_session`(`user_id`, `session_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI交互记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of ai_interaction
-- ----------------------------

-- ----------------------------
-- Table structure for ai_prompt_category
-- ----------------------------
DROP TABLE IF EXISTS `ai_prompt_category`;
CREATE TABLE `ai_prompt_category`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分类名称 (如: 广播剧)',
  `icon` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分类图标 (如: fas fa-headphones-alt)',
  `sort_order` int(0) NULL DEFAULT 0 COMMENT '排序权重',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `update_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI指令库-分类表' ROW_FORMAT = Dynamic;

