-- ----------------------------
-- Table structure for ai_prompt_role
-- ----------------------------
DROP TABLE IF EXISTS `ai_prompt_role`;
CREATE TABLE `ai_prompt_role`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `category_id` bigint(0) NOT NULL COMMENT '归属分类的ID',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '角色名称 (如: 悬疑惊悚)',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '前端UI展示的短描述 (如: 压低声音、带点气声、放缓、偶尔颤音)',
  `tags` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '实际传给大模型的详细Prompt Tags',
  `sort_order` int(0) NULL DEFAULT 0 COMMENT '排序权重',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `update_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category_id`(`category_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 31 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI指令库-角色设定表' ROW_FORMAT = Dynamic;

