-- Records of ai_prompt_role
-- ----------------------------

-- ----------------------------
-- Table structure for cloned_voice
-- ----------------------------
DROP TABLE IF EXISTS `cloned_voice`;
CREATE TABLE `cloned_voice`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL,
  `sample_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'R2样本存储路径',
  `cloned_voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '克隆后音色ID',
  `voice_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '自定义音色名',
  `sample_duration` int(0) NULL DEFAULT NULL COMMENT '样本时长(秒)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'uploaded' COMMENT 'uploaded/training/ready/failed',
  `quality_score` int(0) NULL DEFAULT NULL COMMENT 'AI质量评分(0-100)',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '克隆音色表' ROW_FORMAT = Dynamic;

