-- ----------------------------
-- Table structure for creative_template
-- ----------------------------
DROP TABLE IF EXISTS `creative_template`;
CREATE TABLE `creative_template`  (
  `id` int(0) NOT NULL AUTO_INCREMENT,
  `type_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '类型编码: novel/drama/podcast/radio/lecture/ad/picture_book/news',
  `type_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '类型名称',
  `icon` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '?' COMMENT '图标 emoji',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '类型描述',
  `ai_role` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'AI 角色 System Prompt',
  `output_format` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'text' COMMENT '输出格式: text/dialogue/script',
  `default_voices` json NULL COMMENT '推荐音色配置 JSON',
  `settings_schema` json NULL COMMENT '该类型支持的设置项 (角色数/风格/时长等)',
  `sort_order` int(0) NULL DEFAULT 0,
  `enabled` tinyint(0) NULL DEFAULT 1,
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `type_code`(`type_code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '创作类型模板 (运营可配)' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of creative_template
