-- ----------------------------
-- Table structure for music_task
-- ----------------------------
DROP TABLE IF EXISTS `music_task`;
CREATE TABLE `music_task`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL COMMENT '用户ID',
  `task_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '任务类型: song/instrumental/lyrics',
  `mureka_task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Mureka任务ID',
  `title` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '作品标题',
  `prompt` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '风格提示词',
  `lyrics` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '歌词(song类型)',
  `model` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '使用的模型',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'pending' COMMENT 'pending/processing/succeeded/failed',
  `result_url` varchar(2048) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '生成的音频URL(R2永久链接)',
  `stream_url` varchar(2048) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '流式播放URL(HLS m3u8)',
  `duration` int(0) NULL DEFAULT NULL COMMENT '时长(毫秒)',
  `error_msg` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '错误信息',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0),
  `finished_at` datetime(0) NULL DEFAULT NULL COMMENT '完成时间',
  `deleted` tinyint(0) NULL DEFAULT 0,
  `lyric_timings` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '歌词时间戳 JSON',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_status`(`user_id`, `status`, `created_at`) USING BTREE,
  INDEX `idx_pending`(`status`, `created_at`) USING BTREE,
  INDEX `idx_music_user_status`(`user_id`, `status`) USING BTREE,
  INDEX `idx_music_status_created`(`status`, `created_at`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI音乐生成任务' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of music_task
-- ----------------------------

-- ----------------------------
-- Table structure for novel_chapter
-- ----------------------------
DROP TABLE IF EXISTS `novel_chapter`;
CREATE TABLE `novel_chapter`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `project_id` bigint(0) NOT NULL,
  `chapter_index` int(0) NOT NULL COMMENT '章节序号(从1开始)',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '章节标题',
  `raw_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '原始文本',
  `char_count` int(0) NULL DEFAULT 0 COMMENT '字符数',
  `total_segments` int(0) NULL DEFAULT 0 COMMENT '分段总数',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT 'pending/splitting/annotating/synthesizing/completed/failed',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '本章音频URL',
  `audio_duration` int(0) NULL DEFAULT 0 COMMENT '本章时长(秒)',
  `emotion_summary` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'AI本章主情绪',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_project_index`(`project_id`, `chapter_index`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '有声书章节表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of novel_chapter
-- ----------------------------

-- ----------------------------
-- Table structure for novel_project
-- ----------------------------
DROP TABLE IF EXISTS `novel_project`;
CREATE TABLE `novel_project`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '项目名称',
  `cover_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面',
  `voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主音色ID',
  `total_chars` int(0) NULL DEFAULT 0 COMMENT '原文总字数',
  `total_chapters` int(0) NULL DEFAULT 0 COMMENT '总章节数',
  `total_duration` int(0) NULL DEFAULT 0 COMMENT '合成总时长(秒)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'draft' COMMENT 'draft/analyzing/annotating/synthesizing/completed/failed',
  `progress` int(0) NULL DEFAULT 0 COMMENT '进度 0~100',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '完整音频URL',
  `subtitle_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '完整字幕URL',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  `deleted` tinyint(0) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_status`(`user_id`, `status`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '有声书项目表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of novel_project
-- ----------------------------

-- ----------------------------
-- Table structure for novel_segment
-- ----------------------------
DROP TABLE IF EXISTS `novel_segment`;
CREATE TABLE `novel_segment`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `chapter_id` bigint(0) NOT NULL,
  `segment_index` int(0) NOT NULL COMMENT '段内序号(从1开始)',
  `raw_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '原始文本片段',
  `annotated_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'AI标注文本(含cot标签)',
  `context_texts` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'context_texts(JSON数组)',
  `emotion_label` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '情感标签',
  `tension_level` int(0) NULL DEFAULT 5 COMMENT '紧张度1~10',
  `char_count` int(0) NULL DEFAULT 0 COMMENT '字符数',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT 'pending/annotated/synthesizing/completed/failed',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '本段音频URL',
  `audio_duration` int(0) NULL DEFAULT 0 COMMENT '本段时长(ms)',
  `section_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'TTS session_id',
  `subtitle_json` json NULL COMMENT '逐字时间戳',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_chapter_index`(`chapter_id`, `segment_index`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '有声书分段表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of novel_segment
-- ----------------------------

-- ----------------------------
-- Table structure for studio_project
-- ----------------------------
DROP TABLE IF EXISTS `studio_project`;
CREATE TABLE `studio_project`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `user_id` bigint(0) NOT NULL COMMENT '用户ID',
  `template_id` int(0) NOT NULL COMMENT '关联 creative_template.id',
  `type_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '冗余: 类型编码',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '项目标题',
  `inspiration` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '用户输入的灵感/大纲',
  `outline` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'AI 生成的大纲 (JSON)',
  `characters` json NULL COMMENT '角色设定 (JSON数组: [{name,desc,voiceId}])',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'draft' COMMENT 'draft/creating/editing/completed',
  `total_sections` int(0) NULL DEFAULT 0 COMMENT '总段/章/幕数',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '最终合成音频URL',
  `audio_duration` int(0) NULL DEFAULT NULL COMMENT '音频时长(秒)',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  `deleted` tinyint(0) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_type_code`(`type_code`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_project_user_created`(`user_id`, `created_at`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 50 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '创作项目' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of studio_project
-- ----------------------------

-- ----------------------------
-- Table structure for studio_section
-- ----------------------------
DROP TABLE IF EXISTS `studio_section`;
CREATE TABLE `studio_section`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `project_id` bigint(0) NOT NULL COMMENT '关联 studio_project.id',
  `section_index` int(0) NOT NULL DEFAULT 0 COMMENT '段序号 (0-based)',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '段标题 (如: 第一章/第一幕)',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '文本内容',
  `character_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '角色名 (多角色时)',
  `voice_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '绑定的音色ID',
  `emotion_tag` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '情感标签 (happy/sad/angry...)',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '该段音频URL',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'pending' COMMENT 'pending/generated/synthesized',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `summary` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'AI摘要（摘要压缩记忆链）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_project_id`(`project_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 84 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '创作内容分段' ROW_FORMAT = Dynamic;

