-- ----------------------------
-- Table structure for sys_tier_policy
-- ----------------------------
DROP TABLE IF EXISTS `sys_tier_policy`;
CREATE TABLE `sys_tier_policy`  (
  `id` int(0) NOT NULL AUTO_INCREMENT,
  `tier_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '等级代号',
  `tier_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '等级名称',
  `feature_flags` json NOT NULL COMMENT '功能开关',
  `quota_limits` json NOT NULL COMMENT '配额限制',
  `resource_rules` json NOT NULL COMMENT '资源分配规则',
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_tier_code`(`tier_code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '会员等级策略字典表' ROW_FORMAT = Dynamic;

