-- ----------------------------
-- Table structure for sys_voice
-- ----------------------------
DROP TABLE IF EXISTS `sys_voice`;
CREATE TABLE `sys_voice`  (
  `id` int(0) NOT NULL AUTO_INCREMENT,
  `voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '底层模型调用ID, 如 BV002_streaming',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '前台展示名称，如：通用男声',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '大类(如: 中文场景, 特色方言, 外语多语种, 特色声音)',
  `language` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'zh-CN' COMMENT '支持语种(zh-CN, en-US等)',
  `gender` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'Female' COMMENT '发音人性别(Male/Female/Child)',
  `tags` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '特点/场景标签',
  `supported_engines` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'tts-1.0,tts-2.0,podcast' COMMENT '模块可用范围标识',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注或试听文案',
  `preview_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '前台试听音频的 URL',
  `price` decimal(10, 2) NULL COMMENT '购买价格(0表示完全免费)',
  `is_vip_free` tinyint(0) NULL DEFAULT 0 COMMENT '是否针对 VIP 用户免费(1:VIP免费 0:必须单独购买)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'active' COMMENT '上架状态(active, offline)',
  `sort_order` int(0) NULL DEFAULT 0 COMMENT '排序权重',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_voice_id`(`voice_id`) USING BTREE,
  INDEX `idx_category`(`category`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 78 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统标准音色字典库' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_voice
-- ----------------------------

-- ----------------------------
-- Table structure for tts_task
-- ----------------------------
DROP TABLE IF EXISTS `tts_task`;
CREATE TABLE `tts_task`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL,
  `input_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '输入文本',
  `voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '音色ID',
  `task_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'short' COMMENT 'short/long/emotion/ai_script',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT 'pending/processing/completed/failed',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '合成音频URL (R2)',
  `audio_duration` int(0) NULL DEFAULT NULL COMMENT '音频时长(秒)',
  `external_task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '火山引擎任务ID',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `completed_at` datetime(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_status`(`user_id`, `status`) USING BTREE,
  INDEX `idx_tts_user_status`(`user_id`, `status`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'TTS异步任务表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of tts_task
-- ----------------------------

-- ----------------------------
-- Table structure for user
-- ----------------------------
DROP TABLE IF EXISTS `user`;
CREATE TABLE `user`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手机号',
  `password_hash` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'SHA-256密码哈希',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '声读用户' COMMENT '昵称',
  `avatar_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '头像URL',
  `vip_level` int(0) NULL DEFAULT 0 COMMENT 'VIP等级: 0免费 1月度 2年度 3终身',
  `vip_expire_time` datetime(0) NULL DEFAULT NULL COMMENT 'VIP过期时间',
  `tier_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'user' COMMENT '当前等级代号, 关联 sys_tier_policy.tier_code',
  `role` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'user' COMMENT '系统角色(user/admin)',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  `deleted` tinyint(0) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_phone`(`phone`) USING BTREE,
  INDEX `idx_phone`(`phone`) USING BTREE,
  INDEX `idx_tier_code`(`tier_code`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user
-- ----------------------------

-- ----------------------------
-- Table structure for user_creation
-- ----------------------------
DROP TABLE IF EXISTS `user_creation`;
CREATE TABLE `user_creation`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL,
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'tts/emotion/drama/podcast/novel',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '标题',
  `input_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '输入文本(回看)',
  `voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '音色ID',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '音频URL(R2)',
  `audio_duration` int(0) NULL DEFAULT 0 COMMENT '时长(秒)',
  `file_size` bigint(0) NULL DEFAULT 0 COMMENT '文件大小(字节)',
  `subtitle_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '字幕URL',
  `extra_json` json NULL COMMENT '扩展(情感标签/AI prompt等)',
  `is_published` tinyint(0) NULL DEFAULT 0 COMMENT '是否已发布到发现页',
  `work_id` bigint(0) NULL DEFAULT NULL COMMENT '关联的work.id(发布后回填)',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `deleted` tinyint(0) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_type`(`user_id`, `type`) USING BTREE,
  INDEX `idx_user_created`(`user_id`, `created_at`) USING BTREE,
  INDEX `idx_user_type_created`(`user_id`, `type`, `created_at`) USING BTREE,
  INDEX `idx_is_published_created`(`is_published`, `created_at`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户创作记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user_creation
-- ----------------------------

-- ----------------------------
-- Table structure for user_storage
-- ----------------------------
DROP TABLE IF EXISTS `user_storage`;
CREATE TABLE `user_storage`  (
  `user_id` bigint(0) NOT NULL,
  `used_bytes` bigint(0) NULL DEFAULT 0 COMMENT '已用字节',
  `file_count` int(0) NULL DEFAULT 0 COMMENT '文件数',
  `quota_override_mb` int(0) NULL DEFAULT NULL COMMENT '运营手动覆盖的容量上限(NULL=按策略)',
  `last_calculated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`user_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户存储计量表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user_storage
-- ----------------------------

-- ----------------------------
-- Table structure for user_voice
-- ----------------------------
DROP TABLE IF EXISTS `user_voice`;
CREATE TABLE `user_voice`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL COMMENT '购买者ID',
  `voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '购买的音色ID',
  `obtain_way` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'purchased' COMMENT '获取途径: purchased(购买), gift(赠送), activity(活动)',
  `expire_time` datetime(0) NULL DEFAULT NULL COMMENT '过期时间(NULL表示永久专属)',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_voice`(`user_id`, `voice_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户音色私有资产表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user_voice
-- ----------------------------

-- ----------------------------
-- Table structure for vip_order
-- ----------------------------
DROP TABLE IF EXISTS `vip_order`;
CREATE TABLE `vip_order`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `order_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `user_id` bigint(0) NOT NULL,
  `plan_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'month/year/lifetime',
  `plan_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `duration_days` int(0) NOT NULL DEFAULT 30,
  `amount` decimal(10, 2) NOT NULL COMMENT '订单金额',
  `pay_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'wechat/alipay',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT 'pending/paid/cancelled/refunded',
  `alipay_trade_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `pay_time` datetime(0) NULL DEFAULT NULL,
  `notify_raw` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `trade_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第三方交易号',
  `paid_at` datetime(0) NULL DEFAULT NULL,
  `expire_at` datetime(0) NULL DEFAULT NULL,
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_no`(`order_no`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_vip_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'VIP订单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of vip_order
-- ----------------------------

-- ----------------------------
-- Table structure for voice_order
-- ----------------------------
DROP TABLE IF EXISTS `voice_order`;
CREATE TABLE `voice_order`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID(订单号)',
  `user_id` bigint(0) NOT NULL,
  `voice_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '关联购买音色ID',
  `amount` decimal(10, 2) NOT NULL COMMENT '实际支付金额',
  `pay_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '支付通道(wechat/alipay)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT 'pending/paid/cancelled/refunded',
  `trade_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第三方支付系统流水号',
  `paid_at` datetime(0) NULL DEFAULT NULL,
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '独立音色购买交易订单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of voice_order
-- ----------------------------

-- ----------------------------
-- Table structure for work
-- ----------------------------
DROP TABLE IF EXISTS `work`;
CREATE TABLE `work`  (
  `id` bigint(0) NOT NULL COMMENT '雪花ID',
  `user_id` bigint(0) NOT NULL,
  `creation_id` bigint(0) NULL DEFAULT NULL COMMENT '关联创作记录ID',
  `source_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'tts' COMMENT '来源',
  `content_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'audio' COMMENT '内容类型: audio/novel/podcast/music',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '作品标题',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '内容描述/摘要',
  `word_count` int(0) NULL DEFAULT 0 COMMENT '字数（小说用）',
  `chapter_count` int(0) NULL DEFAULT 0 COMMENT '章节数（小说用）',
  `source_project_id` bigint(0) NULL DEFAULT NULL COMMENT '关联的 studio_project.id',
  `extra_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '扩展字段JSON',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'hot' COMMENT 'hot/latest/emotion/story/news',
  `cover_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面URL',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '音频URL (R2)',
  `audio_duration` int(0) NULL DEFAULT 0 COMMENT '音频时长(秒)',
  `play_count` int(0) NULL DEFAULT 0,
  `like_count` int(0) NULL DEFAULT 0,
  `share_count` int(0) NULL DEFAULT 0 COMMENT '分享数',
  `comment_count` int(0) NULL DEFAULT 0 COMMENT '评论数',
  `ai_summary` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'AI摘要(语义推荐)',
  `vector_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '向量库ID',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'draft' COMMENT 'draft/published/moderation/rejected',
  `review_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'pending' COMMENT 'pending/approved/rejected/featured',
  `review_note` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核备注',
  `reviewed_at` datetime(0) NULL DEFAULT NULL COMMENT '审核时间',
  `reviewed_by` bigint(0) NULL DEFAULT NULL COMMENT '审核人ID',
  `is_featured` tinyint(0) NULL DEFAULT 0 COMMENT '运营精选',
  `heat_score` decimal(10, 2) NULL COMMENT '热度分',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0),
  `deleted` tinyint(0) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category_play`(`category`, `play_count`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  INDEX `idx_review_heat`(`review_status`, `heat_score`) USING BTREE,
  INDEX `idx_review_type_heat`(`review_status`, `content_type`, `heat_score`) USING BTREE,
  INDEX `idx_user_review`(`user_id`, `review_status`) USING BTREE,
  INDEX `idx_review_created`(`review_status`, `created_at`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '作品表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of work
-- ----------------------------

SET FOREIGN_KEY_CHECKS = 1;
