INSERT INTO `music_task` VALUES (2028150977697181697, 2026229317599551489, 'song', '125211401781249', 'Chinese, r&b', 'Chinese, r&b', '[Intro]\n夜色如绸 缓缓铺开\n\n[Verse]\n霓虹在车窗流淌成河\n副驾座位还留着你的温热\n电台情歌 太老旧煽情\n却字字击中 我软肋的缝隙\n\n[Chorus]\n就让节奏带着身体 sway\n呼吸在靠近 零点零三公分以外\n这未完成的告白 在齿间徘徊\n像慢动作回放 心跳节拍\n\n[Verse]\n香气是昨夜你用的香水尾调\n混着我思绪 在空气中发酵\n对话都变成 模糊的拟声词\n比如心跳 比如叹息 比如欲言又止\n\n[Chorus]\n就让节奏带着身体 sway\n呼吸在靠近 零点零三公分以外\n这未完成的告白 在齿间徘徊\n像慢动作回放 心跳节拍\n\n[Bridge]\n也许不必说破 这层磨砂的玻璃\n朦胧的倒影 已足够美丽\n让猜测继续 在沉默里游弋\n保持这危险的 完美距离\n\n[Outro]\nJust sway…\n跟着这拍子 坠入深蓝里\nJust sway…', 'mureka-7.5', 'succeeded', 'https://r2.joyoai.xyz/audio/tts1/music_2028150977697181697_1772383908460.mp3', NULL, 193790, NULL, '2026-03-02 00:50:49', '2026-03-02 00:52:03', 0, NULL);
INSERT INTO `music_task` VALUES (2028161670089666562, 2026229317599551489, 'song', '125216747421697', 'r&b', 'r&b', '[Intro]\nWhisper my name in the velvet dark\nBefore the dawn begins to spark\n\n[Verse]\nCandlelight dancin\' on the wall\nSoft rain is startin\' to fall\nYour perfume lingers on my shirt\nA melody before the hurt\n\n[Chorus]\nWe move in slow motion, a timeless groove\nGot nothin\' to lose and everything to prove\nYour skin like honey under neon lights\nWe\'re rewriting wrongs on these long, slow nights\n\n[Verse]\nRemember the drive, the midnight air\nYour fingers tangled in my hair\nA silent promise, a stolen glance\nLeadin\' us into this fragile dance\n\n[Chorus]\nWe move in slow motion, a timeless groove\nGot nothin\' to lose and everything to prove\nYour skin like honey under neon lights\nWe\'re rewriting wrongs on these long, slow nights\n\n[Bridge]\nThe world outside is fadin\' fast\nBut this moment, baby, this moment\'s built to last\nA sanctuary just for two\nIn this rhythm between me and you\n\n[Outro]\nJust a whisper in the velvet dark\nBefore the dawn begins to... spark', 'mureka-7.6', 'succeeded', 'https://r2.joyoai.xyz/audio/music/music_2028161670089666562_1772386463595.mp3', NULL, 190630, NULL, '2026-03-02 01:33:18', '2026-03-02 01:34:32', 1, NULL);
