INSERT INTO `music_task` VALUES (2028474683929669633, 2026229317599551489, 'song', '125373255778306', 'electronic', 'electronic', '[Intro]\n窗外的麻雀 在电线杆上多嘴\n\n[Verse]\n你说这一句 很有夏天的感觉\n手中的铅笔 在纸上来来回回\n我用几行字形容你是我的谁\n\n[Verse]\n秋刀鱼的滋味 猫跟你都想了解\n初恋的香味就这样被我们寻回\n那温暖的阳光 像刚摘的鲜艳草莓\n你说你舍不得吃掉这一种感觉\n\n[Chorus]\n雨下整夜 我的爱溢出就像雨水\n院子落叶 跟我的思念厚厚一叠\n几句是非 也无法将我的热情冷却\n你出现在我诗的每一页\n\n[Verse]\n整夜 我的爱溢出就像雨水\n窗台蝴蝶 像诗里纷飞的美丽章节\n我接着写 把永远爱你写进诗的结尾\n你是我唯一想要的了解\n\n[Chorus]\n雨下整夜 我的爱溢出就像雨水\n院子落叶 跟我的思念厚厚一叠\n几句是非 也无法将我的热情冷却\n你出现在我诗的每一页\n\n[Bridge]\n那饱满的稻穗 幸福了这个季节\n而你的脸颊像田里熟透的番茄\n你突然对我说 七里香的名字很美\n我此刻却只想亲吻你倔强的嘴\n\n[Outro]\n雨下整夜\n我的爱溢出就像雨水', 'mureka-7.6', 'succeeded', 'https://r2.joyoai.xyz/audio/music/music_2028474683929669633_1772461096361.mp3', NULL, 192870, NULL, '2026-03-02 22:17:07', '2026-03-02 22:18:36', 0, NULL);
INSERT INTO `music_task` VALUES (2028484965565472770, 2026229317599551489, 'song', '125378395897858', 'electronic', 'electronic', '[Intro]\nElectronic beats rising high.\n\n[Verse]\nSilicon heart, digital soul.\nStreaming data, losing control.\n\n[Chorus]\nWe are the robots of the night.\nDancing under neon light.', 'mureka-7.6', 'succeeded', 'https://r2.joyoai.xyz/audio/music/music_2028484965565472770_1772463531573.mp3', 'https://api.mureka.cn/v1/live/stream/CaHmztkTJuE712nfbpgtYJ.aac', 159790, NULL, '2026-03-02 22:57:58', '2026-03-02 23:01:03', 1, NULL);
INSERT INTO `music_task` VALUES (2028800257080438786, 2026263446605094913, 'song', '125536043008002', 'keshi', 'keshi', '[Verse]\nYou left your mark on the pillowcase\nSilence fills up the empty space\nI check the phone but there\'s no light\nJust pixels glowing in the night\nThe temperature dropped down below\nWatching the colors start to go\n\n[Chorus]\nHold me tight until the morning comes\nBefore the sun blinds us from the drums\nDrifting off in a soft refrain\nLost again inside the rain\nTouch me once before you fade\nLeave the heavy thoughts behind\n\n[Verse]\nType the message hit send then stop\nDon\'t want to hear another word drop\nIt\'s easier when I pretend\nThat you aren\'t gone and I am lonely\nThe silence screams so loud and clear\nWashing out the things we fear\n\n[Chorus]\nHold me tight until the morning comes\nBefore the sun blinds us from the drums\nDrifting off in a soft refrain\nLost again inside the rain\nTouch me once before you fade\nLeave the heavy thoughts behind\n\n[Bridge]\nFade out slow like a video\nWhere do we go when the signal goes?\nNo reception in this hollow chest\nPut the fragile pieces to rest\n\n[Outro]\nYeah we drift away\nIn the gray of day\nCan\'t say goodbye today', 'mureka-7.6', 'succeeded', 'https://r2.joyoai.xyz/audio/music/music_2028800257080438786_1772538713673.mp3', 'https://api.mureka.cn/v1/live/stream/PiEERKd9EDeR9dqcZCv1MQ.aac', 215670, NULL, '2026-03-03 19:50:49', '2026-03-03 19:52:20', 0, '[{\"start\":14954,\"end\":215723,\"lines\":[{\"start\":14954,\"end\":17234,\"text\":\"You left your mark on the payload case;\",\"words\":[{\"start\":14954,\"end\":15014,\"text\":\"You \"},{\"start\":15174,\"end\":15394,\"text\":\"left \"},{\"start\":15434,\"end\":15514,\"text\":\"your \"},{\"start\":15614,\"end\":16033,\"text\":\"mark \"},{\"start\":16114,\"end\":16213,\"text\":\"on \"},{\"start\":16254,\"end\":16314,\"text\":\"the \"},{\"start\":16434,\"end\":16854,\"text\":\"payload \"},{\"start\":16934,\"end\":17234,\"text\"