INSERT INTO `music_task` VALUES (2031402243688857602, 2026229317599551489, 'instrumental', '126837042905089', 'classical', 'classical', NULL, 'mureka-7.6', 'succeeded', 'https://r2.joyoai.xyz/audio/music/music_2031402243688857602_1773159064584.mp3', 'https://api.mureka.cn/v1/live/stream/H5VNY2k5o9t12UN7BCFVTt.aac', 171710, NULL, '2026-03-11 00:10:11', '2026-03-11 00:11:11', 0, NULL);
INSERT INTO `music_task` VALUES (2031719709581287426, 2031691539389915138, 'song', '126995763560449', '容不下的抱歉', 'r&b，keshi风格，忧郁，暖心', '[Verse]\n凌晨三点的窗 雨在玻璃上流浪\n你的毛衣还留着 柑橘香\n我数着天花板裂缝 像数着过往\n有些话卡在喉咙 比沉默更响\n\n[Chorus]\n像一首没写完的歌 旋律卡在半空\n你是我舍不得按掉的 未接来电\n房间太安静了 连回声都太重\n可你的影子还在 陪我等天明\n\n[Verse]\n冰箱里的啤酒 过期了整个夏天\n我学着你的样子 把柠檬切成片\n阳台的绿萝枯了 我没舍得换\n也许某天你会来 浇浇水看看\n\n[Chorus]\n像一首没写完的歌 旋律卡在半空\n你是我舍不得按掉的 未接来电\n房间太安静了 连回声都太重\n可你的影子还在 陪我等天明\n\n[Bridge]\n也许该把门锁换了 把号码换了\n把回忆折成纸船 放进河流\n可你送我的那把伞 还在门后站着\n像一句没说出口的 别走\n\n[Outro]\n天快亮了 雨停了 城市在苏醒\n我把你的毛衣 又穿紧了一些\n像你还在这 像一切都没发生', 'mureka-7.6', 'succeeded', 'https://r2.joyoai.xyz/audio/music/music_2031719709581287426_1773234756390.mp3', 'https://api.mureka.cn/v1/live/stream/PqMiZUWhCrCSpjrugshddu.aac', 189310, NULL, '2026-03-11 21:11:41', '2026-03-11 21:12:38', 0, NULL);
INSERT INTO `studio_project` VALUES (2, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"商业天才苏清月重生回到被男友背叛的破产前夕。她果断切割恋爱脑,利用前世记忆抢占商机。从摆地摊到创立科技公司,她一步步建立商业帝国。面对前男友的纠缠和商业对手的打压,她以雷霆手段反击。最终成为叱咤风云的女企业家,实现自我价值。\",\"characters\":[{\"name\":\"苏清月\",\"desc\":\"重生归来的商业天才,冷静果断,目标明确,拒绝恋爱脑专注事业\"},{\"name\":\"陈浩\",\"desc\":\"前世背叛苏清月的男友,虚伪贪婪,试图继续利用女主\"},{\"name\":\"林墨\",\"desc\":\"科技新贵,欣赏女主能力的合作伙伴,保持纯粹商业关系\"},{\"name\":\"赵雅\",\"desc\":\"苏清月的商业对手,不择手段打压女主\"},{\"name\":\"王叔\",\"desc\":\"苏清月创业初期的贵人,经验丰富的老商人\"}],\"chapters\":[\"第1章:苏清月重生回到破产前夜,果断与男友决裂并制定翻身计划\",\"第2章:利用前世记忆抢占夜市商机,第一桶金遭前男友觊觎\",\"第3章:转型科技领域遭遇打压,与合作伙伴林墨建立商业联盟\",\"第4章:商业帝国初具规模,面临对手赵雅的恶意收购战\",\"第5章:完成对前男友公司的反向收购,登顶行业巅峰实现自我价值\"],\"chapterOutlines\":[{\"plot\":\"苏清月从2018年重生回到2015年破产前夜。她躺在熟悉的出租屋里,耳边是男友陈浩虚伪的承诺电话。记忆如潮水涌来——前世她被陈浩骗走所有积蓄,最终在债务中绝望死去。此刻她冷静挂断电话,清点仅剩的五百元现金和一部老旧手机。窗外霓虹闪烁,她摊开笔记本写下三个关键日期:下周二的股市黑天鹅事件、月底的城中村拆迁消息、三个月后的共享单车风口。凌晨三点,她删光陈浩所有联系方式,将\'恋爱脑\'彻底埋葬。\",\"keyEvents\":\"重生觉醒,与陈浩电话决裂,写下关键商机时间表,彻底删除前任痕迹。\",\"characters\":\"苏清月（独白式觉醒）,陈浩（电话中虚伪形象）。\",\"foreshadowing\":\"笔记本上\'共享单车\'四字被圈红,暗示首个创业方向。\"},{\"plot\":\"苏清月用五百元本金批发发光头饰,在大学生夜市摆摊。她精准抓住年轻情侣消费心理,单晚净赚两千元。第三天,陈浩突然出现在摊位前,试图以\'帮忙\'名义插手财务。苏清月当众揭穿他劈腿事实,引来围观学生拍照。当晚她在校园论坛发布《独立女孩摆摊日记》,意外爆红。利用流量接洽首个广告时,发现陈浩暗中注册同名商标。\",\"keyEvents\":\"夜市摆摊首战告捷,陈浩当众纠缠被反杀,论坛爆红获商机,发现商标被抢注。\",\"characters\":\"苏清月vs陈浩（公开对峙）,大学生顾客群体（流量来源）。\",\"foreshadowing\":\"陈浩阴狠眼神暗示后续报复,商标抢注埋下法律战伏笔。\"},{\"plot\":\"苏清月用第一桶金租下共享单车仓库,却遭赵雅控股的物业公司恶意涨租。她在谈判桌上偶遇科技新贵林墨,两人发现彼此都研究过智能锁方案。林墨提出技术入股合作,苏清月以市场数据说服其接受49%股权结构。首批五百辆单车投放高校当日,赵雅派人批量破坏二维码。苏清月连夜推出\'举报有奖\'系统破局。\",\"keyEvents\":\"遭遇赵雅商业打压,与林墨达成技术合作,首投遇破坏,用众筹监管破局。\",\"characters\":\"苏清月&林墨（技术+市场联盟）,赵雅（未露面的阴影对手）。\",\"foreshadowing\":\"林墨实验室的AI调度系统草图,暗示下一阶段技术升级。\"},{\"plot\":\"公司估值破亿时,赵雅通过二级市场收购21%股份,联合三位小股东发起恶意收购。苏清月查出其中两位股东有税务问题,以举报材料逼其退股。关键时刻林墨质押专利注入资金,但持股比例降至34%。苏清月飞往香港接触对冲基金,归国航班上收到神秘短信:\'你父亲当年的车祸不是意外\'。\",\"keyEvents\":\"赵雅发起恶意收购,清退问题股东,林墨注资但股权稀释,收到父亲车祸疑云短信。\",\"characters\":\"苏清月vs赵雅（资本对决）,林墨（关键援手）,神秘信息源（新线索）。\",\"foreshadowing\":\"父亲车祸线索将商业战引向更深层恩怨,短信来自未知号码。\"},{\"plot\":\"苏清月调查发现陈浩已成为赵雅的棋子,其公司核心数据早已被林墨植入后门。在收购表决大会上,她播放陈浩受贿录音,同时启动数据清洗程序。赵雅席位瞬间蒸发三亿市值。当晚庆功宴,苏清月独自站在大厦顶层,手机亮起纳斯达克邀请函。她拨通林墨电话:\'下一个项目,我要做新能源电池\'。\",\"keyEvents\":\"双线反击:曝光陈浩受贿,触发数据后门击溃赵雅,收到上市邀请,布局新赛道。\",\"characters\":\"苏清月完成对陈浩/赵雅的终极反杀,与林墨确立长期伙伴关系。\",\"foreshadowing\":\"新能源电池领域暗示更大棋盘,林墨电话中背景音有实验室爆炸声。\"}]}', NULL, 'editing', 3, NULL, NULL, NULL, '2026-03-01 20:39:11', 1);
INSERT INTO `studio_project` VALUES (3, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"商业天才林薇重生回二十岁,被恋爱脑害死的前夜。她果断踹掉渣男,夺回被窃取的家传商业计划书。凭借前世记忆与卓越手腕,她从摆地摊起步,精准布局未来风口,在股市、房地产、互联网浪潮中完成原始积累。面对来自家族、对手与男性的围剿,她以认知差一次次反杀,建立横跨多个领域的商业帝国,最终成为投资教母,定义属于自己的成功法则。\",\"characters\":[{\"name\":\"林薇\",\"desc\":\"重生女主,外表清冷,内心果决狠厉。拥有前世记忆与顶级商业嗅觉,目标明确:建立商业帝国并复仇。\"},{\"name\":\"周明轩\",\"desc\":\"前世渣男,虚伪的凤凰男,窃取林薇创意上位的商业对手,是本阶段主要复仇对象。\"},{\"name\":\"沈确\",\"desc\":\"亦敌亦友的顶尖投资人,冷静理智,欣赏林薇的能力,是前期重要的合作者与磨刀石。\"},{\"name\":\"苏曼\",\"desc\":\"林薇的合伙人兼挚友,技术天才,性格飒爽,是事业上最可靠的盟友。\"},{\"name\":\"林振业\",\"desc\":\"林薇父亲,传统商人,重男轻女,是女主需要克服的内部障碍与证明对象。\"}],\"chapters\":[\"第1章:重生归来,林薇在订婚宴上当场揭穿周明轩窃取商业计划书的阴谋,果断退婚,夺回核心资料,立下事业Flag。\",\"第2章:利用微薄本金摆摊积累第一桶金,凭借前世记忆在股市完成惊险一击,引起沈确的初步关注。\",\"第3章:进军房地产,以超前眼光拿下未来核心地块,与周明轩正面对抗并小胜,商业版图初具雏形。\",\"第4章:抓住互联网萌芽期,与苏曼合作创建首个电商平台,遭遇周明轩与家族联合打压,绝地反杀。\",\"第5章:商业帝国基石奠定,在巅峰论坛上以认知差彻底击溃周明轩,接受沈确的挑战书,迈向更广阔战场。\"],\"chapterOutlines\":[{\"plot\":\"二十岁订婚宴上,林薇从死亡中重生。她亲眼看着周明轩正拿着她的家传商业计划书夸夸其谈。前世被这男人窃取创意、榨干价值后推下楼的记忆汹涌而来。林薇当众揭穿周明轩抄袭,亮出计划书原稿与修改痕迹。她撕毁订婚协议,夺回核心资料,在满场哗然中宣告将独立创业。父亲林振业怒斥她胡闹,周明轩脸色铁青试图挽回。林薇头也不回地离开宴会厅,月光下攥紧计划书——这一世,她要亲手建立商业帝国。\",\"keyEvents\":\"重生觉醒,当众揭穿抄袭,撕毁婚约夺回计划书,立下事业宣言。\",\"characters\":\"林薇vs周明轩（正面冲突）,林振业（施压）,宾客（围观见证）。\",\"foreshadowing\":\"计划书最后一页夹着未来十年关键风口的时间节点表。\"},{\"plot\":\"林薇用仅有的八百元本金,在大学城夜市摆摊卖手工饰品。她精准把握学生审美,三天回本。同时她紧盯股市,凭借前世记忆锁定一支即将暴涨的冷门股。在资金最紧张时,她押上全部积蓄购入。股价剧烈波动时她镇定持有,最终在最高点抛售,获利二十倍。这笔操作引起暗中观察的顶尖投资人沈确注意。他派人递来名片,林薇看着烫金字体轻笑——鱼儿上钩了。\",\"keyEvents\":\"摆摊积累第一桶金,股市惊险操作获利二十倍,引起沈确关注。\",\"characters\":\"林薇（单打独斗）,沈确（暗中观察）,学生顾客（群体互动）。\",\"foreshadowing\":\"沈确的名片背面印着未来将爆发互联网革命的科技园区地址。\"},{\"plot\":\"林薇用股市收益瞄准尚未开发的城西荒地。她通过复杂产权交易,以极低价格拿下三块相连地块。周明轩此时已窃取部分计划书内容,抢先开发相邻区域试图围剿。林薇反手将其中一块地规划为未来地铁枢纽的消息\'泄露\'给周明轩,诱使他高价接盘。当官方规划正式公布——地铁站恰恰在林薇保留的两块地之间。周明轩资金链断裂,林薇的地价暴涨五倍,商业版图初具雏形。\",\"keyEvents\":\"超前布局城西地块,设局诱使周明轩高价接盘,利用信息差反杀。\",\"characters\":\"林薇vs周明轩（正面对抗）,土地中介（工具人）,规划部门（背景势力）。\",\"foreshadowing\":\"地块合同中隐藏着未来电商物流中心的优先开发权条款。\"},{\"plot\":\"林薇找到技术天才苏曼,两人一拍即合创建\'薇曼网\'。她们瞄准服装垂直领域,首创七天无理由退货。周明轩联合林振业切断林薇的供应链与资金流,更买通媒体抹黑平台售假。危机时刻,林薇亮出与质检机构的全程录像,苏曼则黑进对方服务器找到水军交易记录。反转舆论后,薇曼网单日销售额破百万。庆功宴上,林薇收到父亲断绝关系的律师函——她笑着撕碎,转头与苏曼碰杯。\",\"keyEvents\":\"与苏曼创建电商平台,遭周明轩与家族联合打压,绝地反杀逆转舆论。\",\"characters\":\"林薇&苏曼（盟友建立）,vs周明轩&林振业（联合打压）,媒体（舆论战场）。\",\"foreshadowing\":\"苏曼在对方服务器里发现了指向更高层势力的加密通信记录。\"},{\"plot\":\"行业巅峰论坛上,周明轩做压轴演讲,展示所谓\'十年战略蓝图\'。林薇作为神秘嘉宾登台,用十分钟逐条拆解其漏洞——那些创意全都来自她前世被窃的心血。她当场展示更完整的商业生态闭环方案,认知差形成碾压。周明轩当场崩溃离席。论坛结束后,沈确拦住林薇,递上一份对赌协议:\'敢不敢用三年时间,做到我估值的一半？\'林薇签字时微笑——真正的战场,现在才开始。\",\"keyEvents\":\"论坛公开击溃周明轩,接受沈确的对赌协议,迈向更广阔商业战场。\",\"characters\":\"林薇vs周明轩（终极对决）,沈确（提出挑战）,全场精英（见证者）。\",\"foreshadowing\":\"对赌协议的最后一项条款,涉及林薇前世死亡真相的关键人物。\"}]}', NULL, 'editing', 3, NULL, NULL, NULL, '2026-03-01 20:46:49', 1);
INSERT INTO `studio_project` VALUES (4, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"商业天才苏清雪前世被丈夫和闺蜜联手陷害,公司破产后惨死。重生回23岁创业初期,她撕毁婚约,断绝吸血亲戚,凭借前世记忆和商业嗅觉,从一家濒临倒闭的服装厂起步。在金融危机中逆势收购,打造时尚品牌,进军互联网,每一步都精准踩中时代风口。当仇人们发现时,她早已站在他们无法企及的高度。\",\"characters\":[{\"name\":\"苏清雪\",\"desc\":\"重生归来的商业天才,外表温婉内心果决,擅长战略布局和人性博弈\"},{\"name\":\"陆明轩\",\"desc\":\"前世丈夫/今生对手,虚伪的豪门继承人,擅长表面功夫\"},{\"name\":\"林薇\",\"desc\":\"前世闺蜜/商业间谍,善于伪装和情感操纵\"},{\"name\":\"周慕白\",\"desc\":\"顶尖投行合伙人,欣赏苏清雪能力的商业伙伴\"},{\"name\":\"苏母\",\"desc\":\"传统母亲,最初不理解女儿退婚\"}],\"chapters\":[\"第1章:重生撕婚约,苏清雪在订婚宴当场揭穿陆明轩与林薇的暧昧,宣布退婚并索回创业资金\",\"第2章:接手烂摊子,用前世记忆盘活濒临倒闭的服装厂,设计出爆款连衣裙打响第一枪\",\"第3章:金融危机中逆势操作,抵押全部资产收购竞争对手工厂,布局完整产业链\",\"第4章:创建自主品牌\'雪溯\',借电商风口打造现象级营销,线下门店全国扩张\",\"第5章:陆林联盟反扑却落入圈套,苏清雪公开前世部分真相,宣布进军科技领域新篇章\"],\"chapterOutlines\":[{\"plot\":\"苏清雪在订婚宴上重生,面对虚伪的未婚夫陆明轩和闺蜜林薇的假意祝福。她当众播放偷录的两人暧昧对话,撕毁婚约并索回创业资金。面对陆家的威胁和母亲的劝阻,她冷静揭露前世部分真相,毅然离开宴会厅。在酒店门口遇见前来考察的投行合伙人周慕白,对方目睹全程后递上名片。\",\"keyEvents\":\"重生觉醒→当众揭穿→撕毁婚约→索回资金→偶遇周慕白\",\"characters\":\"苏清雪vs陆明轩/林薇（正面冲突）；苏清雪vs苏母（观念碰撞）；周慕白（旁观者）\",\"foreshadowing\":\"周慕白名片暗示后续合作；陆明轩阴冷眼神预示报复\"},{\"plot\":\"苏清雪用索回的资金接手濒临倒闭的\'晨曦服装厂\'。她凭借前世记忆调整生产线,亲自设计改良版碎花连衣裙。通过精准定位大学生市场和小红书初期种草,三天内订单爆仓。在工厂加班赶工时,发现有人暗中破坏布料仓库。\",\"keyEvents\":\"接手服装厂→设计爆款→营销引爆→订单爆仓→发现破坏\",\"characters\":\"苏清雪vs老厂长（说服合作）；苏清雪vs工人们（建立信任）；暗处破坏者\",\"foreshadowing\":\"布料破坏事件指向陆林指使；爆款设计引起同行关注\"},{\"plot\":\"金融危机席卷,同行纷纷抛售资产。苏清雪抵押全部身家,以极低价格收购三家竞争对手工厂。周慕雪提供专业并购建议,帮她整合产业链。陆明轩试图用家族势力阻挠收购,却因资金链紧张被迫放弃。收购完成后,苏清雪在新建的流水线旁发现窃听器。\",\"keyEvents\":\"金融危机爆发→逆势收购→周慕白协助→陆明轩阻挠失败→发现窃听器\",\"characters\":\"苏清雪&周慕白（首次正式合作）；苏清雪vs陆明轩（商业博弈）\",\"foreshadowing\":\"窃听器揭示商业间谍存在；金融危机后时代风口显现\"},{\"plot\":\"苏清雪创立品牌\'雪溯\',借双十一风口打造\'国风新中式\'概念。与头部主播合作直播带货,单日销售额破千万。线下门店在全国一线城市快速扩张。庆功宴上,林薇伪装成记者混入,试图套取商业机密被识破。\",\"keyEvents\":\"品牌创立→电商营销→销售额破纪录→门店扩张→林薇潜入被识破\",\"characters\":\"苏清雪vs消费者（品牌建立）；苏清雪vs林薇（正面交锋）；团队庆祝\",\"foreshadowing\":\"林薇失败后陆明轩启动B计划；电商数据异常暗示刷单攻击\"},{\"plot\":\"陆林联盟买通媒体抹黑\'雪溯\'质量,同时做空关联公司股票。苏清雪早有准备,公开全部质检报告和生产线视频,并曝光陆氏集团财务造假证据。在新闻发布会中,她隐晦提及\'前世遭遇\',宣布成立科技子公司进军智能穿戴领域。周慕白当场宣布战略投资。\",\"keyEvents\":\"陆林抹黑攻击→苏清雪全面反击→曝光陆氏造假→宣布科技转型→周慕白投资\",\"characters\":\"苏清雪vs陆林联盟（终极对决）；苏清雪&周慕白（深度绑定）；媒体公众\",\"foreshadowing\":\"智能穿戴领域埋下第二部主线；陆明轩入狱前留下狠话\"}]}', NULL, 'editing', 3, NULL, NULL, NULL, '2026-03-01 21:00:54', 1);
INSERT INTO `studio_project` VALUES (5, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"商业天才林晚舟重生回二十岁。前世她被渣男欺骗、家族夺权,最终惨死。这一世她斩断情丝,凭借前世记忆与商业嗅觉,从股市第一桶金开始,一步步创立科技公司、收购竞争对手、建立商业帝国。在复仇路上,她揭开家族阴谋,结识志同道合的伙伴,最终成为商界传奇。\",\"characters\":[{\"name\":\"林晚舟\",\"desc\":\"重生归来的商业天才。外表冷艳,手段凌厉,目标明确。对背叛者绝不手软,对伙伴真诚以待。\"},{\"name\":\"陆明轩\",\"desc\":\"前世渣男,虚伪的豪门公子。表面温柔体贴,实则觊觎林家产业。今生成为林晚舟首要复仇对象。\"},{\"name\":\"周衍\",\"desc\":\"投行精英,林晚舟的商业伙伴。欣赏她的才能,提供资金与人脉支持。纯粹的事业搭档关系。\"},{\"name\":\"林父\",\"desc\":\"传统企业家,重男轻女。前世默许儿子夺权,今生成为林晚舟需要跨越的障碍。\"},{\"name\":\"苏晴\",\"desc\":\"林晚舟助理兼好友。前世唯一真心待她的人。今生成为她最信任的左膀右臂。\"}],\"chapters\":[\"林晚舟从死亡中惊醒,发现重生回二十岁生日宴。她当众撕毁与陆明轩的婚约,宣布断绝恋爱脑,开启复仇之路。\",\"利用前世记忆在股市赚取第一桶金,同时暗中调查陆明轩与林家内部的勾结证据,建立自己的情报网。\",\"创立科技公司,用超前理念开发新产品。在商业谈判中碾压竞争对手,结识重要伙伴周衍,获得关键投资。\",\"公司遭遇陆明轩联合林家势力的恶意打压。林晚舟巧妙反制,曝光对方商业黑料,完成第一次漂亮的反杀。\",\"公司成功上市,林晚舟成为商界新星。她召开新闻发布会,公开前世部分真相,正式向所有背叛者宣战。\"],\"chapterOutlines\":[{\"plot\":\"\",\"keyEvents\":\"\",\"characters\":\"\",\"foreshadowing\":\"\"},{\"plot\":\"\",\"keyEvents\":\"\",\"characters\":\"\",\"foreshadowing\":\"\"},{\"plot\":\"\",\"keyEvents\":\"\",\"characters\":\"\",\"foreshadowing\":\"\"},{\"plot\":\"\",\"keyEvents\":\"\",\"characters\":\"\",\"foreshadowing\":\"\"},{\"plot\":\"\",\"keyEvents\":\"\",\"characters\":\"\",\"foreshadowing\":\"\"}]}', NULL, 'editing', 2, NULL, NULL, NULL, '2026-03-01 21:51:04', 1);
INSERT INTO `studio_project` VALUES (6, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"商界女王苏晚晴遭丈夫与闺蜜联手谋杀,重生回二十岁婚礼当天。她当场撕毁婚约,用前世记忆抢占先机:低价收购即将拆迁的老街、投资未成名科技团队、截胡对手关键项目。从服装批发到互联网风口,她建立商业帝国,让仇人一步步坠入亲手设计的陷阱。当所有仇敌跪地求饶时,她站在摩天大楼顶端俯瞰城市灯火——这一世,她的归宿只有星辰大海。\",\"characters\":[{\"name\":\"苏晚晴\",\"desc\":\"重生归来的商界女王。冷静果决,善于利用信息差布局,对仇人手段狠辣却保有底线。目标明确:建立商业帝国并复仇。\"},{\"name\":\"陆明轩\",\"desc\":\"前世丈夫/今生首要复仇对象。表面温文儒雅的豪门继承人,实则精于算计的伪君子。擅长用感情操控他人。\"},{\"name\":\"林薇薇\",\"desc\":\"苏晚晴前世闺蜜/商业伙伴。外表甜美柔弱,内心嫉妒贪婪。与陆明轩有隐秘勾结。\"},{\"name\":\"周谨言\",\"desc\":\"天才程序员/未来科技巨头。性格孤僻专注,被苏晚晴早期投资并收为事业伙伴。纯粹的技术崇拜者。\"},{\"name\":\"陈伯\",\"desc\":\"苏家老管家。忠诚睿智的长辈,在苏晚晴父母双亡后成为她唯一可信任的人。掌握部分家族隐秘。\"}],\"chapters\":[{\"plot\":\"婚礼现场,苏晚晴在交换戒指时突然头痛欲裂,前世记忆如潮水涌来——她看见十年后自己躺在血泊中,陆明轩和林薇薇握着手站在病房外冷笑。她猛地抽回手,在满座宾客惊愕目光中撕碎婚纱裙摆,当众宣布解除婚约。离场前她瞥见陆明轩眼中一闪而过的杀意,以及林薇薇来不及收起的得意微笑。\",\"keyEvents\":\"婚礼现场重生并当场悔婚\",\"foreshadowing\":\"陆明轩眼神中的异常杀意\"},{\"plot\":\"苏晚晴回到苏家老宅,从陈伯手中接过母亲遗留的保险箱。里面除房产地契外,还有一本写满未来关键信息的日记——母亲竟是穿越者。她连夜制定计划:抵押老宅获得启动资金,次日清晨直奔城西老街,赶在拆迁公告发布前低价收购七间临街商铺。交易完成时,她看见陆明轩的车停在街角。\",\"keyEvents\":\"获得母亲遗留的未来日记\",\"foreshadowing\":\"母亲穿越者身份的暗示\"},{\"plot\":\"苏晚晴用拆迁补偿款创办\'晴空资本\',第一笔投资锁定大学城旁落魄的\'星火工作室\'。她推开满是泡面盒的房门,对埋头编程的周谨言说出他尚未公开的核心算法构想。周谨言震惊抬头,她微笑着递上合同:\'我要的不是现在的你,是三年后改变世界的你。\'与此同时,陆明轩开始调查她的资金流向。\",\"keyEvents\":\"投资未来科技巨头周谨言\",\"foreshadowing\":\"周谨言未公开的算法被精准预知\"},{\"plot\":\"林薇薇以道歉为名约见苏晚晴,暗中在茶中下药企图制造丑闻。苏晚晴早已调换茶杯,反让林薇薇当众失态。她将录音笔放在桌上:\'去年三月,你在陆氏账目上做的手脚,需要我提醒吗？\'林薇薇脸色煞白。当晚,苏晚晴收到匿名恐吓信,信纸上有陆家特有的熏香味道。\",\"keyEvents\":\"反制林薇薇并揭露其把柄\",\"foreshadowing\":\"恐吓信暴露陆明轩参与\"},{\"plot\":\"苏晚晴截胡陆氏志在必得的城南地块,并在拍卖会上公开质疑陆氏资金链。次日陆氏股价暴跌,陆明轩气急败坏闯入晴空资本。她站在全景落地窗前,俯瞰楼下聚集的记者:\'陆总,这才只是开始。\'手机震动,周谨言发来消息:\'你让我监控的境外账户有动静了。\'她勾起嘴角——鱼,终于要咬钩了。\",\"keyEvents\":\"公开打击陆氏并截胡关键项目\",\"foreshadowing\":\"境外账户暗示更大阴谋\"}],\"chapterOutlines\":[{\"plot\":\"婚礼现场,苏晚晴在交换戒指时突然头痛欲裂,前世记忆如潮水涌来——她看见十年后自己躺在血泊中,陆明轩和林薇薇握着手站在病房外冷笑。她猛地抽回手,在满座宾客惊愕目光中撕碎婚纱裙摆,当众宣布解除婚约。离场前她瞥见陆明轩眼中一闪而过的杀意,以及林薇薇来不及收起的得意微笑。\",\"keyEvents\":\"婚礼现场重生并当场悔婚\",\"characters\":\"\",\"foreshadowing\":\"陆明轩眼神中的异常杀意\"},{\"plot\":\"苏晚晴回到苏家老宅,从陈伯手中接过母亲遗留的保险箱。里面除房产地契外,还有一本写满未来关键信息的日记——母亲竟是穿越者。她连夜制定计划:抵押老宅获得启动资金,次日清晨直奔城西老街,赶在拆迁公告发布前低价收购七间临街商铺。交易完成时,她看见陆明轩的车停在街角。\",\"keyEvents\":\"获得母亲遗留的未来日记\",\"characters\":\"\",\"foreshadowing\":\"母亲穿越者身份的暗示\"},{\"plot\":\"苏晚晴用拆迁补偿款创办\'晴空资本\',第一笔投资锁定大学城旁落魄的\'星火工作室\'。她推开满是泡面盒的房门,对埋头编程的周谨言说出他尚未公开的核心算法构想。周谨言震惊抬头,她微笑着递上合同:\'我要的不是现在的你,是三年后改变世界的你。\'与此同时,陆明轩开始调查她的资金流向。\",\"keyEvents\":\"投资未来科技巨头周谨言\",\"characters\":\"\",\"foreshadowing\":\"周谨言未公开的算法被精准预知\"},{\"plot\":\"林薇薇以道歉为名约见苏晚晴,暗中在茶中下药企图制造丑闻。苏晚晴早已调换茶杯,反让林薇薇当众失态。她将录音笔放在桌上:\'去年三月,你在陆氏账目上做的手脚,需要我提醒吗？\'林薇薇脸色煞白。当晚,苏晚晴收到匿名恐吓信,信纸上有陆家特有的熏香味道。\",\"keyEvents\":\"反制林薇薇并揭露其把柄\",\"characters\":\"\",\"foreshadowing\":\"恐吓信暴露陆明轩参与\"},{\"plot\":\"苏晚晴截胡陆氏志在必得的城南地块,并在拍卖会上公开质疑陆氏资金链。次日陆氏股价暴跌,陆明轩气急败坏闯入晴空资本。她站在全景落地窗前,俯瞰楼下聚集的记者:\'陆总,这才只是开始。\'手机震动,周谨言发来消息:\'你让我监控的境外账户有动静了。\'她勾起嘴角——鱼,终于要咬钩了。\",\"keyEvents\":\"公开打击陆氏并截胡关键项目\",\"characters\":\"\",\"foreshadowing\":\"境外账户暗示更大阴谋\"}]}', NULL, 'editing', 1, NULL, NULL, NULL, '2026-03-01 22:30:51', 1);
INSERT INTO `studio_project` VALUES (7, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"商业天才苏晚晴重生回十八岁,前世她被渣男和闺蜜联手害死,家产被夺。这一世她拒绝恋爱脑,利用前世记忆和商业天赋,从股市赚取第一桶金,创立科技公司,在商界掀起风暴。她将曾经的背叛者一一清算,在博弈中不断壮大,最终建立属于自己的商业帝国,成为叱咤风云的商界女王。\",\"characters\":[{\"name\":\"苏晚晴\",\"desc\":\"重生归来的商业天才,冷静理智,杀伐果断,目标明确,专注事业复仇\"},{\"name\":\"陆明轩\",\"desc\":\"前世渣男,虚伪的富二代,擅长伪装与情感操控,苏晚晴的复仇目标之一\"},{\"name\":\"林薇薇\",\"desc\":\"苏晚晴前世闺蜜,表面单纯实则贪婪,与陆明轩勾结谋夺苏家家产\"},{\"name\":\"周墨\",\"desc\":\"神秘的投资人,眼光毒辣,初期是苏晚晴的对手,后期成为亦敌亦友的伙伴\"},{\"name\":\"苏父\",\"desc\":\"传统实业家,疼爱女儿但观念保守,是苏晚晴需要说服和守护的家人\"}],\"chapters\":[{\"plot\":\"苏晚晴在豪华游轮上醒来,发现自己重生回十八岁生日宴。她冷静接受现实,无视渣男陆明轩的殷勤和闺蜜林薇薇的假意关心。利用前世记忆,她当众揭穿一个即将暴雷的理财骗局,救了父亲的部分资金,并写下几个关键股票代码,作为启动资本的第一步。\",\"keyEvents\":\"苏晚晴重生觉醒,当众揭穿骗局\",\"foreshadowing\":\"她注意到人群中一道审视的目光\"},{\"plot\":\"苏晚晴用零花钱和说服父亲得到的少量资金入市,精准操作,一周内资金翻数倍,引起小范围关注。她注册离岸公司,接触一个濒临倒闭但有核心专利的小团队。同时,陆明轩和林薇薇开始察觉她的变化,试图试探。苏晚晴故意露出一个\'破绽\'引他们入局。\",\"keyEvents\":\"股市首战告捷,接触核心技术团队\",\"foreshadowing\":\"那个小团队的专利,涉及未来关键技术\"},{\"plot\":\"苏晚晴的公司\'晴锐科技\'悄然成立。她利用信息差,在土地拍卖中截胡了陆家志在必得的地块,给了陆明轩第一记重击。陆明轩开始动用家族力量调查。神秘投资人周墨首次正式现身,试图收购晴锐科技,被苏晚晴干脆拒绝,两人展开第一轮商业交锋。\",\"keyEvents\":\"截胡关键地块,与周墨初次交锋\",\"foreshadowing\":\"周墨似乎对苏晚晴的未来了如指掌\"},{\"plot\":\"陆明轩和林薇薇设下商业陷阱,伪造合同企图污蔑苏晚晴抄袭侵权。苏晚晴将计就计,在发布会现场反向曝光他们的阴谋,并亮出早已注册的全套专利和研发日志,令对方身败名裂。周墨在关键时刻提供了部分关键证据,苏晚晴意识到他可能知道更多。\",\"keyEvents\":\"反杀陷害阴谋,晴锐科技一举成名\",\"foreshadowing\":\"周墨暗示他知道\'重生\'相关的秘密\"},{\"plot\":\"苏晚晴的公司获得巨额融资,启动颠覆性项目。她全面反击,收购陆家核心业务,将陆明轩踢出董事会。林薇薇因经济犯罪入狱。苏晚晴站在新落成的集团大厦顶层,俯瞰城市。周墨前来道贺,留下一个意味深长的疑问:\'下一次,你会选择怎样的对手？\' 苏晚晴微笑不答,目光投向更远的未来。\",\"keyEvents\":\"建立商业帝国,完成复仇\",\"foreshadowing\":\"周墨的话暗示世界并非表面那么简单\"}],\"chapterOutlines\":[{\"plot\":\"苏晚晴在豪华游轮上醒来,发现自己重生回十八岁生日宴。她冷静接受现实,无视渣男陆明轩的殷勤和闺蜜林薇薇的假意关心。利用前世记忆,她当众揭穿一个即将暴雷的理财骗局,救了父亲的部分资金,并写下几个关键股票代码,作为启动资本的第一步。\",\"keyEvents\":\"苏晚晴重生觉醒,当众揭穿骗局\",\"characters\":\"\",\"foreshadowing\":\"她注意到人群中一道审视的目光\"},{\"plot\":\"苏晚晴用零花钱和说服父亲得到的少量资金入市,精准操作,一周内资金翻数倍,引起小范围关注。她注册离岸公司,接触一个濒临倒闭但有核心专利的小团队。同时,陆明轩和林薇薇开始察觉她的变化,试图试探。苏晚晴故意露出一个\'破绽\'引他们入局。\",\"keyEvents\":\"股市首战告捷,接触核心技术团队\",\"characters\":\"\",\"foreshadowing\":\"那个小团队的专利,涉及未来关键技术\"},{\"plot\":\"苏晚晴的公司\'晴锐科技\'悄然成立。她利用信息差,在土地拍卖中截胡了陆家志在必得的地块,给了陆明轩第一记重击。陆明轩开始动用家族力量调查。神秘投资人周墨首次正式现身,试图收购晴锐科技,被苏晚晴干脆拒绝,两人展开第一轮商业交锋。\",\"keyEvents\":\"截胡关键地块,与周墨初次交锋\",\"characters\":\"\",\"foreshadowing\":\"周墨似乎对苏晚晴的未来了如指掌\"},{\"plot\":\"陆明轩和林薇薇设下商业陷阱,伪造合同企图污蔑苏晚晴抄袭侵权。苏晚晴将计就计,在发布会现场反向曝光他们的阴谋,并亮出早已注册的全套专利和研发日志,令对方身败名裂。周墨在关键时刻提供了部分关键证据,苏晚晴意识到他可能知道更多。\",\"keyEvents\":\"反杀陷害阴谋,晴锐科技一举成名\",\"characters\":\"\",\"foreshadowing\":\"周墨暗示他知道\'重生\'相关的秘密\"},{\"plot\":\"苏晚晴的公司获得巨额融资,启动颠覆性项目。她全面反击,收购陆家核心业务,将陆明轩踢出董事会。林薇薇因经济犯罪入狱。苏晚晴站在新落成的集团大厦顶层,俯瞰城市。周墨前来道贺,留下一个意味深长的疑问:\'下一次,你会选择怎样的对手？\' 苏晚晴微笑不答,目光投向更远的未来。\",\"keyEvents\":\"建立商业帝国,完成复仇\",\"characters\":\"\",\"foreshadowing\":\"周墨的话暗示世界并非表面那么简单\"}]}', NULL, 'completed', 5, NULL, NULL, NULL, '2026-03-02 15:36:16', 1);
