INSERT INTO `studio_project` VALUES (18, 2026263446605094913, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"沈知微重生回到二十三岁,前世她为爱情放弃家族企业,最终被丈夫与闺蜜联手逼死。这一世她斩断情丝,以毒辣眼光抄底破产地产、做空仇家股票、布局新能源赛道,五年间从负债孤女成长为资本巨鳄。当昔日恋人跪求融资、闺蜜身败名裂时,她只淡淡一句:\\\"我的时间很贵,按秒计费。\\\"\",\"characters\":[{\"name\":\"沈知微\",\"desc\":\"28岁,冷峻果决,拥有前世记忆的商业天才,信奉利益至上,对情感需求极低\"},{\"name\":\"陆辞深\",\"desc\":\"30岁,前世丈夫,伪善的资本操盘手,今生被沈知微反将一军沦为棋子\"},{\"name\":\"苏晚晴\",\"desc\":\"27岁,前世闺蜜,虚荣拜金,今生试图复制前世套路却被全程碾压\"},{\"name\":\"周牧野\",\"desc\":\"35岁,神秘投行大佬,欣赏沈知微的狠辣,两人亦敌亦友互相利用\"},{\"name\":\"沈老爷子\",\"desc\":\"沈知微祖父,唯一真心待她之人,病重成为她加速扩张的导火索\"}],\"chapters\":[{\"plot\":\"沈知微在车祸瞬间重生回2019年,正是她准备签下股权转让书、将沈氏地产交给陆辞深的前一刻。她当着所有人的面撕毁文件,反手以三倍杠杆抄底自家即将暴跌的股票。陆辞深错愕追问,她只笑说\\\"突然想自己玩\\\"。当晚她独自复盘前世记忆,列出三十七个必爆雷的投资标的——这是她的死亡清单,也是发财秘籍。\",\"keyEvents\":\"当众撕毁股权转让书\",\"foreshadowing\":\"死亡清单上的第一个名字:荣盛建材\"},{\"plot\":\"沈知微盯上荣盛建材,这家表面风光的供应商实为陆辞深白手套。她假意接近苏晚晴,套取对方虚增订单的证据,同时匿名向证监会举报。三个月后荣盛暴雷,股价腰斩,沈知微通过做空狂赚两千万。庆功宴上陆辞深试探她是否幕后推手,她将红酒推过去:\\\"陆总高估我了,我只是……运气比较好。\\\"眼底却无半分温度。\",\"keyEvents\":\"做空荣盛建材获利两千万\",\"foreshadowing\":\"陆辞深开始怀疑她知晓未来\"},{\"plot\":\"沈老爷子突发脑溢血,需要天价进口药。沈知微为凑资金,冒险与周牧野合作竞标旧城改造项目。谈判桌上周牧野提出五五分成,她冷笑抛出前世记忆:三年后此地会通地铁,溢价至少八倍。周牧野瞳孔骤缩,改口三七分且垫付全款。项目中标当晚,沈知微在ICU外握紧爷爷的手,第一次露出脆弱——这是她唯一的软肋,也是最后的枷锁。\",\"keyEvents\":\"与周牧野达成合作\",\"foreshadowing\":\"周牧野调查她信息来源\"},{\"plot\":\"陆辞深设局邀请沈知微参加慈善拍卖,实则为套取她投资动向。她明知陷阱却欣然赴约,故意\\\"泄露\\\"看好某支科技股。陆辞深重仓杀入,却不知这是她联合周牧野做的杀猪盘——三周后财报造假曝光,陆辞深亏损过亿。更狠的是,沈知微提前收购了陆氏集团第二大股东的债权,此刻登门\\\"雪中送炭\\\",条件是要他亲手送苏晚晴进监狱。\",\"keyEvents\":\"反向做局让陆辞深巨亏\",\"foreshadowing\":\"苏晚晴手中握有陆辞深洗钱证据\"},{\"plot\":\"苏晚晴狗急跳墙,绑架沈知微索要五亿赎金。沈知微被绑在废弃仓库却异常平静,细数苏晚晴前世如何在她病床前炫耀出轨细节。警方破门瞬间,苏晚晴才发现定位器早被缝进沈知微袖口——这场绑架本就是请君入瓮。尘埃落定,沈知微站在沈氏集团新总部顶层,俯瞰城市灯火。手机弹出陆辞深的求婚短信,她拉黑删除,转头对助理说:\\\"明天飞深圳,宁德时代要定增了。\\\"窗外朝阳正升,她的时代才刚刚开始。\",\"keyEvents\":\"反杀绑架案彻底击溃对手\",\"foreshadowing\":\"新能源赛道布局暗示续篇可能\"}],\"chapterOutlines\":[{\"plot\":\"沈知微在车祸瞬间重生回2019年,正是她准备签下股权转让书、将沈氏地产交给陆辞深的前一刻。她当着所有人的面撕毁文件,反手以三倍杠杆抄底自家即将暴跌的股票。陆辞深错愕追问,她只笑说\\\"突然想自己玩\\\"。当晚她独自复盘前世记忆,列出三十七个必爆雷的投资标的——这是她的死亡清单,也是发财秘籍。\",\"keyEvents\":\"当众撕毁股权转让书\",\"characters\":\"\",\"foreshadowing\":\"死亡清单上的第一个名字:荣盛建材\"},{\"plot\":\"沈知微盯上荣盛建材,这家表面风光的供应商实为陆辞深白手套。她假意接近苏晚晴,套取对方虚增订单的证据,同时匿名向证监会举报。三个月后荣盛暴雷,股价腰斩,沈知微通过做空狂赚两千万。庆功宴上陆辞深试探她是否幕后推手,她将红酒推过去:\\\"陆总高估我了,我只是……运气比较好。\\\"眼底却无半分温度。\",\"keyEvents\":\"做空荣盛建材获利两千万\",\"characters\":\"\",\"foreshadowing\":\"陆辞深开始怀疑她知晓未来\"},{\"plot\":\"沈老爷子突发脑溢血,需要天价进口药。沈知微为凑资金,冒险与周牧野合作竞标旧城改造项目。谈判桌上周牧野提出五五分成,她冷笑抛出前世记忆:三年后此地会通地铁,溢价至少八倍。周牧野瞳孔骤缩,改口三七分且垫付全款。项目中标当晚,沈知微在ICU外握紧爷爷的手,第一次露出脆弱——这是她唯一的软肋,也是最后的枷锁。\",\"keyEvents\":\"与周牧野达成合作\",\"characters\":\"\",\"foreshadowing\":\"周牧野调查她信息来源\"},{\"plot\":\"陆辞深设局邀请沈知微参加慈善拍卖,实则为套取她投资动向。她明知陷阱却欣然赴约,故意\\\"泄露\\\"看好某支科技股。陆辞深重仓杀入,却不知这是她联合周牧野做的杀猪盘——三周后财报造假曝光,陆辞深亏损过亿。更狠的是,沈知微提前收购了陆氏集团第二大股东的债权,此刻登门\\\"雪中送炭\\\",条件是要他亲手送苏晚晴进监狱。\",\"keyEvents\":\"反向做局让陆辞深巨亏\",\"characters\":\"\",\"foreshadowing\":\"苏晚晴手中握有陆辞深洗钱证据\"},{\"plot\":\"苏晚晴狗急跳墙,绑架沈知微索要五亿赎金。沈知微被绑在废弃仓库却异常平静,细数苏晚晴前世如何在她病床前炫耀出轨细节。警方破门瞬间,苏晚晴才发现定位器早被缝进沈知微袖口——这场绑架本就是请君入瓮。尘埃落定,沈知微站在沈氏集团新总部顶层,俯瞰城市灯火。手机弹出陆辞深的求婚短信,她拉黑删除,转头对助理说:\\\"明天飞深圳,宁德时代要定增了。\\\"窗外朝阳正升,她的时代才刚刚开始。\",\"keyEvents\":\"反杀绑架案彻底击溃对手\",\"characters\":\"\",\"foreshadowing\":\"新能源赛道布局暗示续篇可能\"}],\"stylePreference\":\"heroine\"}', NULL, 'completed', 5, NULL, NULL, NULL, '2026-03-04 19:20:58', 0);
INSERT INTO `studio_project` VALUES (19, 2026229317599551489, 1, 'novel', '女主重生后拒绝恋爱脑，以...', '女主重生后拒绝恋爱脑，以商业天才的手腕一步步建立自己的商业帝国', '{\"synopsis\":\"沈知微重生回到二十岁,前世她为爱情放弃家族企业,最终被丈夫与闺蜜联手逼死。这一世她撕毁婚约、夺回股权,以精准眼光投资互联网风口,从被轻视的千金小姐蜕变为资本猎手。当旧爱跪求复合、对手设局围剿,她早已站在他们无法企及的高度——这一次,她的棋盘上只有利益,没有感情。\",\"characters\":[{\"name\":\"沈知微\",\"desc\":\"冷静果决,前世恋爱脑被害死,重生后目标明确:建立商业帝国,让所有背叛者付出代价\"},{\"name\":\"周牧野\",\"desc\":\"前世丈夫,伪善野心家,擅长情感操控,今生成为沈知微第一个击溃的对手\"},{\"name\":\"林晚棠\",\"desc\":\"表面闺蜜实则毒蛇,嫉妒沈知微出身,前世参与谋夺家产,今生被反将一军\"},{\"name\":\"谢辞深\",\"desc\":\"神秘投资人,欣赏沈知微的手段,亦敌亦友,提供关键资源但索取对等筹码\"},{\"name\":\"沈老爷子\",\"desc\":\"家族掌权人,重男轻女,是沈知微必须征服的第一座大山\"}],\"chapters\":[{\"plot\":\"重生醒来,沈知微正坐在订婚宴现场,周牧野单膝跪地举着戒指。前世记忆如潮水涌来——三年后他会转移资产,五年后她会\'意外\'坠楼。她当众起身,将红酒泼在他脸上宣布退婚,同时用前世知道的内幕消息,当场与原本瞧不上她的港城谢家达成秘密协议,换取第一笔启动资金。\",\"keyEvents\":\"当众退婚,反将周家股价\",\"foreshadowing\":\"谢辞深提出的奇怪条件\"},{\"plot\":\"沈知微回老宅见祖父,对方以\'女子不宜掌事\'为由要收回她名下股份。她早有准备,拿出周牧野暗中收购沈氏散股的证据,点破这是引狼入室。老爷子震怒却不得不倚重她,她趁机要求进入董事会并拿到互联网投资权限。当晚林晚棠假意安慰,沈知微微笑收下掺了慢性药的燕窝——前世她喝了三年。\",\"keyEvents\":\"智斗祖父夺权,识破闺蜜下毒\",\"foreshadowing\":\"燕窝瓶底的特殊标记\"},{\"plot\":\"沈知微押注刚起步的即时通讯软件\'闪信\',董事会一片嘲讽。她亲自飞深圳与创始人谈判,用前世知道的运营痛点和竞争对手布局,以极低估值拿下15%股权。周牧野闻讯搅局,试图用更高价截胡,却发现创始人是她大学室友的亲哥——这层关系她藏了十年。签约当晚,闪信服务器突发故障,她连夜指挥抢修,展现技术判断力。\",\"keyEvents\":\"闪电投资闪信,挫败周牧野截胡\",\"foreshadowing\":\"服务器故障的人为痕迹\"},{\"plot\":\"闪信用户暴涨,沈知微估值翻二十倍。周牧野与林晚棠联手做空沈氏股票,散布她\'投资失误\'的谣言。她将计就计,故意放出闪信要被巨头收购的假消息,诱使对家高价接盘自己早期布局的竞品公司,再反手举报其数据造假。股灾中沈氏股价逆势上扬,她召开记者会,当众播放林晚棠三年前买凶撞人的录音——那是前世她死后才知道的真相。\",\"keyEvents\":\"股市反杀,公开处刑闺蜜\",\"foreshadowing\":\"录音来源的匿名寄件人\"},{\"plot\":\"林晚棠入狱,周牧野破产失踪。谢辞深现身揭示最后一层棋局:他当年提供的资金来自周牧野的对家,而服务器故障是他所为——他在测试她是否配得上合作。沈知微笑纳这份\'考验\',提出新交易:共同收购周家残存的核心资产。签字时她收到陌生号码短信,周牧野的声音透过文字传来:你以为赢了？你母亲的车祸,也是计划的一部分。沈知微捏碎酒杯,血与酒混流——原来复仇才刚刚开始。\",\"keyEvents\":\"与谢辞深结盟,发现母亲死因疑云\",\"foreshadowing\":\"母亲生前与沈老爷子的秘密通话\"}],\"chapterOutlines\":[{\"plot\":\"重生醒来,沈知微正坐在订婚宴现场,周牧野单膝跪地举着戒指。前世记忆如潮水涌来——三年后他会转移资产,五年后她会\'意外\'坠楼。她当众起身,将红酒泼在他脸上宣布退婚,同时用前世知道的内幕消息,当场与原本瞧不上她的港城谢家达成秘密协议,换取第一笔启动资金。\",\"keyEvents\":\"当众退婚,反将周家股价\",\"characters\":\"\",\"foreshadowing\":\"谢辞深提出的奇怪条件\"},{\"plot\":\"沈知微回老宅见祖父,对方以\'女子不宜掌事\'为由要收回她名下股份。她早有准备,拿出周牧野暗中收购沈氏散股的证据,点破这是引狼入室。老爷子震怒却不得不倚重她,她趁机要求进入董事会并拿到互联网投资权限。当晚林晚棠假意安慰,沈知微微笑收下掺了慢性药的燕窝——前世她喝了三年。\",\"keyEvents\":\"智斗祖父夺权,识破闺蜜下毒\",\"characters\":\"\",\"foreshadowing\":\"燕窝瓶底的特殊标记\"},{\"plot\":\"沈知微押注刚起步的即时通讯软件\'闪信\',董事会一片嘲讽。她亲自飞深圳与创始人谈判,用前世知道的运营痛点和竞争对手布局,以极低估值拿下15%股权。周牧野闻讯搅局,试图用更高价截胡,却发现创始人是她大学室友的亲哥——这层关系她藏了十年。签约当晚,闪信服务器突发故障,她连夜指挥抢修,展现技术判断力。\",\"keyEvents\":\"闪电投资闪信,挫败周牧野截胡\",\"characters\":\"\",\"foreshadowing\":\"服务器故障的人为痕迹\"},{\"plot\":\"闪信用户暴涨,沈知微估值翻二十倍。周牧野与林晚棠联手做空沈氏股票,散布她\'投资失误\'的谣言。她将计就计,故意放出闪信要被巨头收购的假消息,诱使对家高价接盘自己早期布局的竞品公司,再反手举报其数据造假。股灾中沈氏股价逆势上扬,她召开记者会,当众播放林晚棠三年前买凶撞人的录音——那是前世她死后才知道的真相。\",\"keyEvents\":\"股市反杀,公开处刑闺蜜\",\"characters\":\"\",\"foreshadowing\":\"录音来源的匿名寄件人\"},{\"plot\":\"林晚棠入狱,周牧野破产失踪。谢辞深现身揭示最后一层棋局:他当年提供的资金来自周牧野的对家,而服务器故障是他所为——他在测试她是否配得上合作。沈知微笑纳这份\'考验\',提出新交易:共同收购周家残存的核心资产。签字时她收到陌生号码短信,周牧野的声音透过文字传来:你以为赢了？你母亲的车祸,也是计划的一部分。沈知微捏碎酒杯,血与酒混流——原来复仇才刚刚开始。\",\"keyEvents\":\"与谢辞深结盟,发现母亲死因疑云\",\"characters\":\"\",\"foreshadowing\":\"母亲生前与沈老爷子的秘密通话\"}],\"stylePreference\":\"heroine\"}', NULL, 'editing', 1, NULL, NULL, NULL, '2026-03-07 22:25:33', 1);
INSERT INTO `studio_project` VALUES (20, 2026229317599551489, 2, 'drama', 'AI觉醒了自我意识，与创...', 'AI觉醒了自我意识，与创造者展开一场关于生存权的对话', NULL, NULL, 'editing', 1, NULL, NULL, NULL, '2026-03-07 14:55:43', 1);
INSERT INTO `studio_project` VALUES (21, 2026229317599551489, 2, 'drama', '后宫妃嫔之间的权力博弈，...', '后宫妃嫔之间的权力博弈，每个人都有不可告人的秘密', '{\"synopsis\":\"德妃为掩盖毒杀宫女之罪,以砒霜证据要挟昔日心腹淑妃顶罪。淑妃反以同谋证据相胁,二人深夜对弈,互相撕扯旧日师徒情分。最终德妃以满门性命逼其就范,淑妃含恨写下自裁遗书,以血咒终结这场深宫博弈。\",\"characters\":[{\"name\":\"德妃\",\"desc\":\"四妃之首,阴鸷深沉,擅借刀杀人,说话慢条斯理却句句藏刀\"},{\"name\":\"淑妃\",\"desc\":\"德妃旧部,表面柔顺实则隐忍,被逼至绝境时锋芒毕露\"},{\"name\":\"翠缕\",\"desc\":\"淑妃贴身宫女,机敏忠心,关键时刻递刀破局\"}],\"chapters\":[{\"plot\":\"德妃夜访淑妃寝宫,以宫女翠儿暴毙案发难,暗示淑妃曾私购砒霜。淑妃初时装傻,德妃遂出示药房账册,直指其毒害宫女。淑妃反唇相讥,提及三年前德妃赐死的刘贵人,二人表面寒暄,实则互相探底。\",\"keyEvents\":\"德妃出示砒霜证据\",\"foreshadowing\":\"刘贵人之死另有隐情\"},{\"plot\":\"淑妃命翠缕取来檀木盒,内藏德妃亲笔所写的毒杀方子。德妃色变,旋即冷笑,以淑妃母家九族性命要挟。淑妃崩溃质问十年师徒情谊,德妃直言后宫从无真心。淑妃被迫提笔,泪落宣纸。\",\"keyEvents\":\"淑妃出示反制证据\",\"foreshadowing\":\"翠缕眼神暗示尚有后手\"},{\"plot\":\"淑妃写完遗书,以血指按印,忽而低笑诅咒德妃众叛亲离。德妃拂袖离去,淑妃独坐至天明,将真正毒方塞入翠缕怀中,嘱其呈交皇后。翠缕跪泣,淑妃自缢,遗言「这局棋,我才刚落子」。\",\"keyEvents\":\"淑妃自裁并留后手\",\"foreshadowing\":\"皇后将成为最终执棋人\"}],\"chapterOutlines\":[{\"plot\":\"德妃夜访淑妃寝宫,以宫女翠儿暴毙案发难,暗示淑妃曾私购砒霜。淑妃初时装傻,德妃遂出示药房账册,直指其毒害宫女。淑妃反唇相讥,提及三年前德妃赐死的刘贵人,二人表面寒暄,实则互相探底。\",\"keyEvents\":\"德妃出示砒霜证据\",\"characters\":\"\",\"foreshadowing\":\"刘贵人之死另有隐情\"},{\"plot\":\"淑妃命翠缕取来檀木盒,内藏德妃亲笔所写的毒杀方子。德妃色变,旋即冷笑,以淑妃母家九族性命要挟。淑妃崩溃质问十年师徒情谊,德妃直言后宫从无真心。淑妃被迫提笔,泪落宣纸。\",\"keyEvents\":\"淑妃出示反制证据\",\"characters\":\"\",\"foreshadowing\":\"翠缕眼神暗示尚有后手\"},{\"plot\":\"淑妃写完遗书,以血指按印,忽而低笑诅咒德妃众叛亲离。德妃拂袖离去,淑妃独坐至天明,将真正毒方塞入翠缕怀中,嘱其呈交皇后。翠缕跪泣,淑妃自缢,遗言「这局棋,我才刚落子」。\",\"keyEvents\":\"淑妃自裁并留后手\",\"characters\":\"\",\"foreshadowing\":\"皇后将成为最终执棋人\"}],\"stylePreference\":\"palace\"}', NULL, 'editing', 3, NULL, NULL, NULL, '2026-03-07 16:18:13', 1);
INSERT INTO `studio_project` VALUES (22, 2026229317599551489, 2, 'drama', '后宫妃嫔之间的权力博弈，...', '后宫妃嫔之间的权力博弈，每个人都有不可告人的秘密', '{\"synopsis\":\"新帝登基,后宫格局未稳。皇后顾氏出身将门,手握兵权却膝下无子；贵妃萧氏诞下皇长子,母凭子贵野心暗藏；德妃沈氏表面不争不抢,实为前朝遗孤,借医术布局复仇；昭仪柳氏年方十六,以天真为刃,实为权臣安插的眼线。四人各怀鬼胎,在赏花宴、皇子中毒、边关急报等事件中互相试探、结盟又背叛,最终揭露出皇帝才是最大的棋手——他以妃嫔为子,制衡朝堂,而真正的猎物,是她们身后盘根错节的世家势力。\",\"characters\":[{\"name\":\"顾皇后\",\"desc\":\"将门嫡女,二十八岁,端庄威仪,不善言辞却句句诛心,以沉默施压,对皇嗣执念极深\"},{\"name\":\"萧贵妃\",\"desc\":\"江南士族,二十六岁,明艳张扬,言语带刺惯用捧杀,将皇长子视为登天梯\"},{\"name\":\"沈德妃\",\"desc\":\"太医院之女,二十四岁,温婉疏离,说话慢条斯理藏机锋,以医术为刀复仇\"},{\"name\":\"柳昭仪\",\"desc\":\"十六岁,娇憨懵懂,善用天真作伪装,每句话都在试探,是 youngest 的猎手\"},{\"name\":\"皇帝\",\"desc\":\"二十五岁,深不可测,对每位妃嫔都温柔,温柔里皆是算计\"}],\"chapters\":[{\"plot\":\"春日赏花宴,皇后以牡丹为题令众妃作诗。萧贵妃故意让皇长子当众背诵《诗经·黍离》,暗讽皇后无子如周室东迁。沈德妃以药理为由,指出贵妃所戴香囊含麝香,恐伤皇子。柳昭仪天真发问:\\\\\",\"keyEvents\":\"香囊事件暴露贵妃隐患,德妃首次主动出击\",\"foreshadowing\":\"柳昭仪的\\\\\"},{\"plot\":\"皇长子突发急症,太医束手无策。萧贵妃哭求德妃施救,德妃以\\\\\",\"keyEvents\":\"皇子中毒牵出边关势力,德妃发现复仇线索\",\"foreshadowing\":\"两种毒药暗示两拨人动手,皇帝对边关将领的猜忌浮出水面\"},{\"plot\":\"顾氏父子入宫,皇帝设家宴试探。皇后与父亲以军情密语交谈,被柳昭仪\\\\\",\"keyEvents\":\"德妃与皇帝摊牌,玉佩证实皇帝知她身份\",\"foreshadowing\":\"将军中毒暗示皇后一族被皇帝暗中削弱,玉佩是威胁也是试探\"},{\"plot\":\"柳昭仪\\\\\",\"keyEvents\":\"柳昭仪身份暴露,第四种势力浮现,德妃登顶\",\"foreshadowing\":\"德妃晋位是皇帝推她至风口浪尖,第二种毒的主人即将现身\"},{\"plot\":\"德妃掌权后,发现宫中所有隐秘皆在皇帝掌握:她的复仇、皇后的无子、贵妃的野心、柳昭仪的棋子身份,全是他一手纵容。皇帝坦言,他要的不是贤后宠妃,而是让她们背后的世家互相撕咬,好收归兵权、相权于己手。德妃以当年毒方要挟,要求皇帝赐死陷害她父亲的真凶——却发现那人正是先帝,而先帝早已驾崩。最终,德妃在皇帝茶中下毒,剂量恰如当年父亲所受。皇帝饮尽,笑说:\\\\\",\"keyEvents\":\"\",\"foreshadowing\":\"\"}],\"chapterOutlines\":[{\"plot\":\"春日赏花宴,皇后以牡丹为题令众妃作诗。萧贵妃故意让皇长子当众背诵《诗经·黍离》,暗讽皇后无子如周室东迁。沈德妃以药理为由,指出贵妃所戴香囊含麝香,恐伤皇子。柳昭仪天真发问:\\\\\",\"keyEvents\":\"香囊事件暴露贵妃隐患,德妃首次主动出击\",\"characters\":\"\",\"foreshadowing\":\"柳昭仪的\\\\\"},{\"plot\":\"皇长子突发急症,太医束手无策。萧贵妃哭求德妃施救,德妃以\\\\\",\"keyEvents\":\"皇子中毒牵出边关势力,德妃发现复仇线索\",\"characters\":\"\",\"foreshadowing\":\"两种毒药暗示两拨人动手,皇帝对边关将领的猜忌浮出水面\"},{\"plot\":\"顾氏父子入宫,皇帝设家宴试探。皇后与父亲以军情密语交谈,被柳昭仪\\\\\",\"keyEvents\":\"德妃与皇帝摊牌,玉佩证实皇帝知她身份\",\"characters\":\"\",\"foreshadowing\":\"将军中毒暗示皇后一族被皇帝暗中削弱,玉佩是威胁也是试探\"},{\"plot\":\"柳昭仪\\\\\",\"keyEvents\":\"柳昭仪身份暴露,第四种势力浮现,德妃登顶\",\"characters\":\"\",\"foreshadowing\":\"德妃晋位是皇帝推她至风口浪尖,第二种毒的主人即将现身\"},{\"plot\":\"德妃掌权后,发现宫中所有隐秘皆在皇帝掌握:她的复仇、皇后的无子、贵妃的野心、柳昭仪的棋子身份,全是他一手纵容。皇帝坦言,他要的不是贤后宠妃,而是让她们背后的世家互相撕咬,好收归兵权、相权于己手。德妃以当年毒方要挟,要求皇帝赐死陷害她父亲的真凶——却发现那人正是先帝,而先帝早已驾崩。最终,德妃在皇帝茶中下毒,剂量恰如当年父亲所受。皇帝饮尽,笑说:\\\\\",\"keyEvents\":\"\",\"characters\":\"\",\"foreshadowing\":\"\"}],\"stylePreference\":\"palace\"}', NULL, 'editing', 2, NULL, NULL, NULL, '2026-03-07 16:18:11', 1);
INSERT INTO `studio_project` VALUES (23, 2026229317599551489, 2, 'drama', '后宫妃嫔之间的权力博弈，...', '后宫妃嫔之间的权力博弈，每个人都有不可告人的秘密', NULL, NULL, 'draft', 0, NULL, NULL, NULL, '2026-03-07 18:36:02', 1);
INSERT INTO `studio_project` VALUES (24, 2026229317599551489, 2, 'drama', '啊啊', '啊啊', '```json\n{\n  \"synopsis\": \"冷宫弃妃沈知微意外发现先帝遗诏，卷入皇权更迭的漩涡。她与隐忍多年的废太子萧珩结盟，在波谲云诡的宫廷中步步为营。当真相浮出水面，她才发现自己不过是先帝棋局中的一枚弃子，而真正的棋手，正藏在最不起眼的阴影里。\",\n  \"characters\": [\n    {\"name\": \"沈知微\", \"desc\": \"冷宫弃妃，表面温婉隐忍，内心机敏果决，说话慢条斯理却暗藏锋芒\", \"voiceType\": \"清冷女声\"},\n    {\"name\": \"萧珩\", \"desc\": \"废太子，左腿残疾，表面颓废酗酒，实则城府极深，语气慵懒中带压迫感\", \"voiceType\": \"沙哑低沉男声\"},\n    {\"name\": \"高无咎\", \"desc\": \"掌印太监，先帝心腹，语调阴柔平缓，喜怒不形于色\", \"voiceType\": \"尖细苍老男声\"},\n    {\"name\": \"萧珏\", \"desc\": \"当朝皇帝，少年登基，声音清亮却暴躁易怒，情绪起伏极大\", \"voiceType\": \"年轻尖锐男声\"},\n    {\"name\": \"柳氏\", \"desc\": \"沈知微贴身宫女，表面憨厚，实则身份成谜，说话带着乡音的质朴感\", \"voiceType\": \"憨厚少女声\"}\n  ],\n  \"chapters\": [\n    {\"plot\": \"沈知微在冷宫枯井中发现先帝密匣，内有遗诏与半块虎符。当夜，废太子萧珩翻墙而入，以她宫外亲族性命要挟合作。两人对峙至天明，沈知微假意屈服，实则将密匣内容暗记于心。萧珩离去时留下一句\'你以为自己是第一个发现的人吗\'，令她彻夜难眠。\", \"keyEvents\": \"冷宫发现先帝遗诏\", \"foreshadowing\": \"萧珩暗示此前有人知情\"},\n    {\"plot\": \"三日后宫宴，沈知微借献舞复宠，席间故意遗落虎符碎片引皇帝注意。萧珏果然震怒，当场杖毙两名侍卫。高无咎冷眼旁观，宴后独留沈知微，以她父母棺椁相胁，逼她交出遗诏。沈知微周旋间察觉高无咎与萧珩暗中往来，意识到这盘棋远比想象中复杂。\", \"keyEvents\": \"虎符碎片引皇帝暴怒\", \"foreshadowing\": \"高无咎与萧珩关系暧昧\"},\n    {\"plot\": \"沈知微夜探萧珩居所，撞见他与高无咎密会。偷听中得知先帝之死另有隐情，而遗诏所立之人竟是——她自己。惊惶后退时踢翻铜盆，萧珩追出却未擒她，反将完整遗诏塞入她手中。原来他早知她偷听，所谓\'废太子\'不过是诱出真凶的饵，而她，才是先帝选中的刀。\", \"keyEvents\": \"沈知微发现自己才是遗诏所立之人\", \"foreshadowing\": \"萧珩坦白自己是诱饵\"},\n    {\"plot\": \"沈知微持遗诏面圣，萧珏癫狂大笑，吐露弑父真相。禁军包围大殿之际，柳氏突然出手制住皇帝，亮出暗卫身份——她才是先帝真正的底牌。萧珩率兵入宫，却非为夺位，而是奉遗诏护沈知微登基。高无咎此时现身，宣读先帝第二道密旨：若沈知微临阵退缩，萧珩取而代之。\", \"keyEvents\": \"柳氏亮明暗卫身份反制皇帝\", \"foreshadowing\": \"高无咎手握第二道密旨\"},\n    {\"plot\": \"沈知微端坐龙椅，看着阶下萧珩从容受封摄政王。夜深人静，她独对先帝牌位，将遗诏投入火盆——那上面\'立沈氏女为帝\'的墨迹，是她三日前亲手仿写。真正的遗诏早被萧珩焚毁，而她不过是将计就计。窗外传来萧珩的轻笑：\'陛下好手段。\'她垂眸：\'彼此彼此，皇叔。\'\", \"keyEvents\": \"沈知微自焚伪造遗诏\", \"foreshadowing\": \"萧珩早已知情并配合\"}\n  ]\n}\n```', NULL, 'draft', 0, NULL, NULL, NULL, '2026-03-07 17:09:18', 1);
INSERT INTO `studio_project` VALUES (25, 2026229317599551489, 2, 'drama', '霍总装穷追妻被女主打脸', '霍总装穷追妻被女主打脸', '```json\n{\n  \"synopsis\": \"霍氏总裁霍沉舟为试探未婚妻真心，伪装破产外卖员接近苏晚棠。苏晚棠发现真相后，将计就计反向套路，在豪门晚宴上当众\\\"打脸\\\"装穷丈夫，最终两人坦诚相待。\",\n  \"characters\": [\n    {\"name\": \"霍沉舟\", \"desc\": \"霍氏集团总裁，表面冷峻矜贵，内心傲娇闷骚，装穷时笨拙可爱\", \"voiceType\": \"低沉磁性的青年男声，装穷时略带局促\"},\n    {\"name\": \"苏晚棠\", \"desc\": \"珠宝设计师，表面温婉实则通透，擅长以柔克刚的腹黑女主\", \"voiceType\": \"清冷温婉的女声，关键时刻带笑意\"},\n    {\"name\": \"林秘书\", \"desc\": \"霍沉舟特助，被迫配合老板演戏，吐槽役\", \"voiceType\": \"干练略带无奈的青年男声\"},\n    {\"name\": \"苏母\", \"desc\": \"势利眼贵妇，推动冲突的喜剧角色\", \"voiceType\": \"尖利夸张的中年女声\"}\n  ],\n  \"chapters\": [\n    {\"plot\": \"霍沉舟以\'霍氏破产\'为由退婚，实则化身外卖员\'小霍\'接近苏晚棠。苏晚棠在暴雨夜收留浑身湿透的他，递毛巾时指尖相触，霍沉舟耳红却嘴硬说\'只是顺路\'。苏晚棠垂眸轻笑，目光掠过他价值六位数的腕表。\", \"keyEvents\": \"暴雨夜收留，初见识破\", \"foreshadowing\": \"苏晚棠注意腕表细节\"},\n    {\"plot\": \"霍沉舟送外卖被苏母撞见，苏母当众羞辱\'穷酸配不上我女儿\'。苏晚棠护在他身前，反讽\'妈，您去年拍卖的翡翠是假的\'。霍沉舟震惊于她的维护，却不知她早已查到他名下十七套房产。深夜，苏晚棠对着电脑屏幕轻点鼠标，霍氏股权结构图清晰展开。\", \"keyEvents\": \"苏母羞辱，苏晚棠反护\", \"foreshadowing\": \"苏晚棠调查霍氏资产\"},\n    {\"plot\": \"霍沉舟\'凑钱\'送苏晚棠廉价项链，她当场戴上称赞\'比拍卖行的亮\'。林秘书紧急来电：\'霍总，慈善晚宴您必须出席——\'霍沉舟手忙脚乱捂手机，苏晚棠假装没听见，转头给闺蜜发消息：\'猎物上钩，收网。\'\", \"keyEvents\": \"廉价项链事件，电话露馅\", \"foreshadowing\": \"苏晚棠策划晚宴反击\"},\n    {\"plot\": \"【高潮反转】霍沉舟以真身出席慈善晚宴，却见苏晚棠挽着\'外卖员小霍\'入场——那是她雇的演员。全场哗然中，苏晚棠走向真正的霍沉舟，轻晃手机：\'霍总，您送我的项链，发票抬头是霍氏集团呢。\'大屏幕突然播放他装穷期间的笨拙录像，霍沉舟耳红到滴血。\", \"keyEvents\": \"真假霍沉舟对峙，当众揭穿\", \"foreshadowing\": \"录像证据公开\"},\n    {\"plot\": \"天台夜话，霍沉舟终于坦白\'怕你只是爱钱\'。苏晚棠将真项链放入他掌心：\'我爱的不是破产的你，是暴雨夜耳朵红透却硬撑的你。\'霍沉舟愣住，她踮脚轻笑：\'但装穷骗我三个月，利息怎么算？\'远处烟花炸开，他低头吻住她，林秘书在楼下疯狂拍照发群：\'老板被反杀了！\'\", \"keyEvents\": \"天台坦白，双向奔赴\", \"foreshadowing\": \"林秘书拍照留证\"}\n  ]\n}\n```', NULL, 'draft', 0, NULL, NULL, NULL, '2026-03-07 18:36:00', 1);
INSERT INTO `studio_project` VALUES (26, 2026229317599551489, 2, 'drama', '重生回到离婚前一天复仇渣...', '重生回到离婚前一天复仇渣男', '{\"synopsis\":\"林知意重生回到离婚前一天,发现丈夫顾景深与闺蜜苏晚晴的阴谋。她伪装顺从,在离婚仪式上当众播放两人偷情录音与转移财产证据,让渣男身败名裂。最终她夺回公司、收养前世未能救下的女孩,开启新人生。\",\"characters\":[{\"name\":\"林知意\",\"desc\":\"前世软弱隐忍,重生后果断狠辣,说话带笑里藏刀的从容\"},{\"name\":\"顾景深\",\"desc\":\"虚伪精英男,擅长温柔陷阱,情绪失控时暴露本性\"},{\"name\":\"苏晚晴\",\"desc\":\"表面天真,实则绿茶,语气娇嗲爱撒娇\"},{\"name\":\"周牧野\",\"desc\":\"林知意前世错过的合作伙伴,沉默可靠,说话简短\"},{\"name\":\"小宝\",\"desc\":\"前世被苏晚晴虐待致死的孩子,声音怯懦\"}],\"chapters\":[{\"plot\":\"林知意从车祸中惊醒,发现回到离婚前一天。她冷静梳理前世记忆:顾景深与苏晚晴的私情、转移的资产、小宝的死亡。她对着镜子练习微笑,给顾景深打电话时语气如常,却在挂断后眼神骤冷。她联系私家侦探,要求24小时内拿到所有证据。\",\"keyEvents\":\"重生确认,启动复仇计划\",\"foreshadowing\":\"镜中眼神变化暗示黑化\"},{\"plot\":\"顾景深回家扮演完美丈夫,林知意配合演出,却在拥抱时闻到苏晚晴的香水味。次日民政局外,苏晚晴\'偶遇\'两人,三人合影时林知意故意让顾景深站中间。她暗中观察两人眼神交流,在离婚协议签字前突然说\'等等\',拿出一份补充条款——要求分割顾景深名下\'隐藏\'的三处海外房产。\",\"keyEvents\":\"当众揭露隐藏财产\",\"foreshadowing\":\"顾景深签字时手抖暴露心虚\"},{\"plot\":\"顾景深脸色铁青否认,林知意微笑打开直播。画面切到酒店监控:顾景深与苏晚晴的亲密画面、转账记录、更有关键录音——\'等那孩子死了,知意就会彻底崩溃,股份自然归我\'。弹幕爆炸,顾景深暴怒抢夺手机,被周牧野拦住。苏晚晴哭喊是被强迫,林知意甩出她虐待小宝的完整视频。\",\"keyEvents\":\"直播实锤,双重反转\",\"foreshadowing\":\"周牧野提前到场暗示布局\"},{\"plot\":\"顾景深跪地求饶,林知意俯身轻语\'你演深情的样子,和前世一模一样\',转身离去。她接管公司,在股东大会播放顾景深贿赂董事的录音。深夜她找到被苏晚晴遗弃的小宝,孩子瑟缩说\'阿姨说我不乖\',林知意哽咽拥抱。周牧野递来热可可,两人沉默对视。\",\"keyEvents\":\"夺回公司,收养小宝\",\"foreshadowing\":\"周牧野手腕疤痕暗示前世渊源\"},{\"plot\":\"三年后,林知意带着小宝在公园野餐,新闻播报顾景深入狱、苏晚晴精神病院自残。小宝跑向冰淇淋车,撞上周牧野。男人蹲下替她擦脸,抬头与林知意相视一笑。画外音响起林知意独白:\'前世我死在恨里,这一世我活在爱里。\'片尾彩蛋:小宝画的一家三口,签名日期是林知意前世死亡日。\",\"keyEvents\":\"新家庭形成,闭环治愈\",\"foreshadowing\":\"彩蛋日期暗示命运改写\"}],\"chapterOutlines\":[{\"plot\":\"林知意从车祸中惊醒,发现回到离婚前一天。她冷静梳理前世记忆:顾景深与苏晚晴的私情、转移的资产、小宝的死亡。她对着镜子练习微笑,给顾景深打电话时语气如常,却在挂断后眼神骤冷。她联系私家侦探,要求24小时内拿到所有证据。\",\"keyEvents\":\"重生确认,启动复仇计划\",\"characters\":\"\",\"foreshadowing\":\"镜中眼神变化暗示黑化\"},{\"plot\":\"顾景深回家扮演完美丈夫,林知意配合演出,却在拥抱时闻到苏晚晴的香水味。次日民政局外,苏晚晴\'偶遇\'两人,三人合影时林知意故意让顾景深站中间。她暗中观察两人眼神交流,在离婚协议签字前突然说\'等等\',拿出一份补充条款——要求分割顾景深名下\'隐藏\'的三处海外房产。\",\"keyEvents\":\"当众揭露隐藏财产\",\"characters\":\"\",\"foreshadowing\":\"顾景深签字时手抖暴露心虚\"},{\"plot\":\"顾景深脸色铁青否认,林知意微笑打开直播。画面切到酒店监控:顾景深与苏晚晴的亲密画面、转账记录、更有关键录音——\'等那孩子死了,知意就会彻底崩溃,股份自然归我\'。弹幕爆炸,顾景深暴怒抢夺手机,被周牧野拦住。苏晚晴哭喊是被强迫,林知意甩出她虐待小宝的完整视频。\",\"keyEvents\":\"直播实锤,双重反转\",\"characters\":\"\",\"foreshadowing\":\"周牧野提前到场暗示布局\"},{\"plot\":\"顾景深跪地求饶,林知意俯身轻语\'你演深情的样子,和前世一模一样\',转身离去。她接管公司,在股东大会播放顾景深贿赂董事的录音。深夜她找到被苏晚晴遗弃的小宝,孩子瑟缩说\'阿姨说我不乖\',林知意哽咽拥抱。周牧野递来热可可,两人沉默对视。\",\"keyEvents\":\"夺回公司,收养小宝\",\"characters\":\"\",\"foreshadowing\":\"周牧野手腕疤痕暗示前世渊源\"},{\"plot\":\"三年后,林知意带着小宝在公园野餐,新闻播报顾景深入狱、苏晚晴精神病院自残。小宝跑向冰淇淋车,撞上周牧野。男人蹲下替她擦脸,抬头与林知意相视一笑。画外音响起林知意独白:\'前世我死在恨里,这一世我活在爱里。\'片尾彩蛋:小宝画的一家三口,签名日期是林知意前世死亡日。\",\"keyEvents\":\"新家庭形成,闭环治愈\",\"characters\":\"\",\"foreshadowing\":\"彩蛋日期暗示命运改写\"}],\"stylePreference\":\"meme\"}', NULL, 'editing', 5, NULL, NULL, NULL, '2026-03-07 20:24:12', 1);
INSERT INTO `studio_project` VALUES (27, 2026229317599551489, 2, 'drama', '霍总装穷追妻被女主打脸', '霍总装穷追妻被女主打脸', '{\"synopsis\":\"霍氏总裁霍沉舟为试探真心,伪装破产程序员追求设计师苏晚。苏晚识破后配合演出,却在霍沉舟身份曝光当日反将一军——她早知他是谁,陪他演这场戏只为让他体会被欺骗的滋味。最终两人坦诚相对,霍沉舟以真名真身份重新追求,苏晚提出:这次换我考察你。\",\"characters\":[{\"name\":\"霍沉舟\",\"desc\":\"霍氏集团总裁,表面高冷矜贵,装穷时笨拙真诚,被拆穿后慌乱又执拗\"},{\"name\":\"苏晚\",\"desc\":\"独立设计师,表面温柔清冷,实则通透果决,擅长以退为进\"},{\"name\":\"林秘书\",\"desc\":\"霍沉舟特助,崩溃边缘的打工人,被迫配合老板演戏\"},{\"name\":\"陈总监\",\"desc\":\"苏晚上司,势利眼,关键打脸工具人\"}],\"chapters\":[{\"plot\":\"咖啡厅面试,霍沉舟以\'破产程序员\'身份应聘苏晚工作室助理,声称\'会修电脑、能加班、不要钱\'。苏晚盯着他腕上三百万的百达翡丽,轻笑:\'明天来报到。\'霍沉舟窃喜,未察觉她目光中的了然。林秘书在门外疯狂使眼色被无视。\",\"keyEvents\":\"苏晚一眼识破名表,假意录用\",\"foreshadowing\":\"苏晚早已调查过霍氏总裁照片\"},{\"plot\":\"霍沉舟\'穷\'得理直气壮,吃苏晚带的便当、住她租的公寓隔壁、蹭她的车上班。苏晚纵容他,却在暴雨夜\'无意间\'露出霍氏周年庆邀请函——烫金名字霍沉舟。她歪头:\'霍先生,这名字好耳熟。\'霍沉舟僵住,便当盒捏变形。\",\"keyEvents\":\"苏晚亮出邀请函,霍沉舟身份首次危机\",\"foreshadowing\":\"苏晚抽屉里藏着霍沉舟三年前的采访杂志\"},{\"plot\":\"霍氏晚宴,陈总监嘲讽苏晚\'靠勾搭穷鬼上位\'。霍沉舟忍无可忍,当场摘下工牌:\'霍氏总裁,够不够资格？\'全场哗然。苏晚却鼓掌起身,投影亮起——正是霍沉舟装穷时发给她的\'求包养\'表情包合集。\'霍总,演技不错。\'\",\"keyEvents\":\"霍沉舟自爆身份,苏晚反甩证据打脸\",\"foreshadowing\":\"苏晚手机云端同步了他所有\'穷鬼\'言论\"},{\"plot\":\"后台对峙,霍沉舟攥住她手腕:\'你什么时候知道的？\'苏晚抽手,从包里抽出三年前杂志——封面正是他,配文\'霍沉舟:从不屑伪装\'。\'你演破产,我演动心,公平。\'她逼近,\'但现在游戏结束,霍总。\'转身时被拽回,霍沉舟声音发哑:\'动心不是演的。\'\",\"keyEvents\":\"苏晚亮出三年旧杂志,揭露双向试探\",\"foreshadowing\":\"杂志内页有她写的批注\'装模作样\'\"},{\"plot\":\"三个月后,霍沉舟以真身份重新出现,捧着设计合约:\'苏设计师,这次我姓霍名沉舟,资产可查,真心可验。\'苏晚签字,却将笔递回:\'试用期三个月,霍助理。\'他愣住,她笑:\'公平。\'——窗外,正是他们初遇的那家咖啡厅。\",\"keyEvents\":\"身份对等的重新追求,权力反转\",\"foreshadowing\":\"合约附加条款写着\'不得隐瞒任何资产\'\"}],\"chapterOutlines\":[{\"plot\":\"咖啡厅面试,霍沉舟以\'破产程序员\'身份应聘苏晚工作室助理,声称\'会修电脑、能加班、不要钱\'。苏晚盯着他腕上三百万的百达翡丽,轻笑:\'明天来报到。\'霍沉舟窃喜,未察觉她目光中的了然。林秘书在门外疯狂使眼色被无视。\",\"keyEvents\":\"苏晚一眼识破名表,假意录用\",\"characters\":\"\",\"foreshadowing\":\"苏晚早已调查过霍氏总裁照片\"},{\"plot\":\"霍沉舟\'穷\'得理直气壮,吃苏晚带的便当、住她租的公寓隔壁、蹭她的车上班。苏晚纵容他,却在暴雨夜\'无意间\'露出霍氏周年庆邀请函——烫金名字霍沉舟。她歪头:\'霍先生,这名字好耳熟。\'霍沉舟僵住,便当盒捏变形。\",\"keyEvents\":\"苏晚亮出邀请函,霍沉舟身份首次危机\",\"characters\":\"\",\"foreshadowing\":\"苏晚抽屉里藏着霍沉舟三年前的采访杂志\"},{\"plot\":\"霍氏晚宴,陈总监嘲讽苏晚\'靠勾搭穷鬼上位\'。霍沉舟忍无可忍,当场摘下工牌:\'霍氏总裁,够不够资格？\'全场哗然。苏晚却鼓掌起身,投影亮起——正是霍沉舟装穷时发给她的\'求包养\'表情包合集。\'霍总,演技不错。\'\",\"keyEvents\":\"霍沉舟自爆身份,苏晚反甩证据打脸\",\"characters\":\"\",\"foreshadowing\":\"苏晚手机云端同步了他所有\'穷鬼\'言论\"},{\"plot\":\"后台对峙,霍沉舟攥住她手腕:\'你什么时候知道的？\'苏晚抽手,从包里抽出三年前杂志——封面正是他,配文\'霍沉舟:从不屑伪装\'。\'你演破产,我演动心,公平。\'她逼近,\'但现在游戏结束,霍总。\'转身时被拽回,霍沉舟声音发哑:\'动心不是演的。\'\",\"keyEvents\":\"苏晚亮出三年旧杂志,揭露双向试探\",\"characters\":\"\",\"foreshadowing\":\"杂志内页有她写的批注\'装模作样\'\"},{\"plot\":\"三个月后,霍沉舟以真身份重新出现,捧着设计合约:\'苏设计师,这次我姓霍名沉舟,资产可查,真心可验。\'苏晚签字,却将笔递回:\'试用期三个月,霍助理。\'他愣住,她笑:\'公平。\'——窗外,正是他们初遇的那家咖啡厅。\",\"keyEvents\":\"身份对等的重新追求,权力反转\",\"characters\":\"\",\"foreshadowing\":\"合约附加条款写着\'不得隐瞒任何资产\'\"}],\"stylePreference\":\"ceo\"}', '[\"男主（冷傲霸道、强势占有，声线：浑厚男声）\", \"女主（外柔内刚、聪慧独立，声线：温柔女声）\"]', 'editing', 1, NULL, NULL, NULL, '2026-03-07 20:24:08', 1);
