INSERT INTO `user_creation` VALUES (2027348852096438273, 2026229317599551489, 'tts', '配音 2026-02-27', '呵，原来是你啊。刚才远远看着，还以为是谁家走丢的宠物，摇着尾巴等着主人施舍呢。几年不见，你怎么还穿着当年那套旧西装？领口都磨破了吧。对，就像你那点可怜的自尊心。你以为我会哭？会歇斯底里？会跪下来求你解释为什么背叛我？不，我只是在想……当年那个傻乎乎把全部信任都交给', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772192604764.mp3', 33, 551520, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027352297130029058, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用四川话、慵懒随意的方言语气] 诶，说啥子哦。四川话嘛，就是巴适。你听我这个调调，是不是安逸得很？莫得啥子压力，就像喝杯盖碗茶。慢悠悠的，才叫生活噻。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772193427713.mp3', 19, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027352965018415106, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用语速快、重点突出、带神秘感的语气] 还有五分钟！别慌，听好了。这次考试的秘密，就在第三单元。特别是上周五老师反复强调的那道例题，我敢打赌，至少占二十分。翻开笔记第七页，看到我用红笔圈出来的公式了吗？对，就是那个。还有，选择题最后五道，大概率会考时间换算。记住，千万别被表面数字迷惑。重点来了——作文题，我昨晚研究过往年真题，发现一个规律。当题干出现“最难忘的”和“第一次”这两个关键词时，核心立意一定是成长与感悟。你的素材，准备好了吗？时间紧迫，但抓住这些，绝对来得及！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772193586650.mp3', 59, 0, NULL, NULL, 1, 2027355973823287298, NULL, 1);
INSERT INTO `user_creation` VALUES (2027354844481843201, 2026229317599551489, 'tts', '配音 2026-02-27', '夜深了，窗外的霓虹还在不知疲倦地闪烁，而我的心却像这杯凉透了的茶。我总以为，只要够执着，就能把回忆捂热，把走散的人等回来。可有些告别，原来真的没有回音。那些夜里反复咀嚼的遗憾，那些假设了无数次的“如果当时”，今晚忽然都变得很轻，轻得像一声叹息，飘散在空气里。我终于明白，不是所有的故事都需要一个圆满的结局，有些人的出现，只是为了教会你如何好好告别。杯子空了，就让它空着吧。天快亮了，我也该为自己，续上一杯新的温暖了。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772194035032.mp3', 52, 841440, NULL, NULL, 1, 2027355953925509122, NULL, 1);
INSERT INTO `user_creation` VALUES (2027358597410807809, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用慷慨激昂、热血沸腾的语气，像战场上的最后宣言] 将士们！看那城下的狼烟！听那敌军的嘶吼！但你们听到了吗？还有我们身后百姓的祈祷！还有我们脚下这片土地的心跳！我们是谁？我们是守护者！我们是最后一道防线！每一寸城墙都浸透着祖辈的血汗！每一块砖石都见证着不屈的脊梁！刀锋会卷刃！铠甲会破损！但我们的意志！永远不会折断！今日！就让我们的怒吼！成为敌人最后的丧钟！用我们的血肉！筑成新的长城！为了家园！为了明天！杀！', 'zh_female_mizai_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772194929850.mp3', 51, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027359777314660354, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用温柔轻缓、充满治愈感的语气，像深夜电台主播在耳边低语] 将士们，听我说！看看你们身后！那是我们的父母、妻儿，是我们世代守护的家园！看看前方！那是磨刀霍霍的豺狼，是妄图践踏我们土地的强盗！今天，我们已无路可退！身后即是家园，退一步，便是万丈深渊！我，将与你们一同，站在这里，寸土不让！他们以为，用刀剑就能让我们屈服？他们以为，用铁蹄就能踏碎我们的脊梁？做梦！让我们的怒吼，成为他们最后的丧钟！让我们的鲜血，染红这片我们深爱的土地！为了身后的灯火，为了明天的太阳！杀！', 'zh_female_mizai_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772195211077.mp3', 58, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027360346779508737, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用哭腔加重、呼吸急促、声音颤抖、断断续续的语气] 为什么……为什么总是这样？我明明已经很努力了……真的……已经拼尽全力了……可为什么……还是逃不掉？每一次……每一次都以为……这次会不一样……可最后……还是回到原点……\n\n呼吸好困难……胸口像被什么压着……喘不过气……凌晨三点……全世界都睡着了……只有我……只有我还醒着……听着自己的心……在一点点碎掉……\n\n对不起……对不起……我真的……撑不下去了……这条路……太黑太长了……我找不到出口……也看不见光……所有的力气……都用完了……所有的希望……都耗尽了……', 'zh_female_mizai_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772195346767.mp3', 64, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027360704226484226, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用哭腔加重、呼吸急促、声音颤抖、断断续续的语气] （叹气）为什么……为什么总是这样？（叹气）我明明已经很努力了……（叹气）真的……已经拼尽全力了……可为什么……还是逃不掉？每一次……每一次都以为……这次会不一样……可最后……还是回到原点……\n\n呼吸好困难……胸口像被什么压着……喘不过气……凌晨三点……全世界都睡着了……只有我……只有我还醒着……听着自己的心……在一点点碎掉……\n\n对不起……对不起……我真的……撑不下去了……这条路……太黑太长了……我找不到出口……也看不见光……所有的力气……都用完了……所有的希望……都耗尽了……', 'zh_female_mizai_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772195426959.mp3', 67, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027360850389590017, 2026229317599551489, 'tts', '配音 2026-02-27', '（温柔而略带沙哑的男声，背景有极淡的雨声）  你看，窗外的雨又下起来了。记得以前你总说，这样的夜晚最适合听雨声，两个人窝在沙发里，什么话都不用说。 现在只剩我一个人了……起初觉得这雨声吵得人心烦，每一滴都像在提醒我，那些空荡荡的角落。  但今晚，我忽然听懂了——雨声从来不是为了谁而下，它只是落下，然后汇成新的水流，去往我从未见过的地方。 原来，放不下一段过去，就像固执地想把雨水留在掌心。摊开手吧……让它走，也让自己走。  雨总会停的，天也总会亮的。而我，也该起身去煮一杯新的咖啡了。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772195467178.mp3', 60, 964800, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027361212777455618, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用哭腔加重、呼吸急促、声音颤抖、断断续续的语气] （抽泣声）我……我撑不住了。真的……我真的不行了。（深呼吸）为什么……为什么总是我？（声音颤抖）这条路，太黑太长了……我看不见光。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772195548597.mp3', 23, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027361887087321089, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[怒目圆睁，冲着你大声怒吼]放肆！我是龙族的女王，是这乱世的主宰，岂容你这蝼蚁来评判我！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772195709535.mp3', 11, 0, NULL, NULL, 0, NULL, NULL, 0);
