INSERT INTO `user_creation` VALUES (2027365580390072322, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用语气强势、咬字清晰、带点慵懒或命令感的语气] （轻笑）把那些小心翼翼，都丢掉。我想要的，从来不是你的讨好。看着我，听清楚。我允许你，站在我的身边。但别妄想，能左右我的方向。明白吗？', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772196594735.mp3', 23, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027367954563252225, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用暧昧低沉、若即若离的语气，像在耳边轻声说情话] （压低声音）别动。你睫毛上，落了一粒光。（轻笑）像偷偷藏起来的星星。（沉默片刻）呼吸，再轻一点。我怕听不清，你心跳漏掉的那一拍。指尖的温度，是故意的吗？（低声）靠近我。又退后。这若即若离的游戏……（叹气）你赢了。我投降。但只限今晚。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772197160214.mp3', 35, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027370266270679042, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用微微叹气、语速变快、带点无奈的笑、重复重点的语气] 唉……我说了多少次了。这道题，这个思路，讲过三遍了。你看看这里——（吸气）还是错在同一个地方。我真的……（短促的笑）不知道该拿你怎么办才好。用点心，多用点心啊！时间不等人，机会更不等人。你明明可以做到的……为什么就是不肯再往前多走一步呢？我替你着急啊。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772197711824.mp3', 38, 0, NULL, NULL, 0, NULL, NULL, 0);
