INSERT INTO `user_creation` VALUES (2027372479852408834, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用暧昧低沉、若即若离的语气，像在耳边轻声说情话] （轻笑）别躲……我感觉得到，你的呼吸乱了。  \n指尖划过你耳垂时，温度在说谎。  \n说不想靠近……可你的睫毛在颤啊。  \n\n窗外的雨停了。  \n我们之间这点距离……算远，还是算近？  \n\n呵，你猜我现在——  \n是想吻你，还是想推开你？  \n\n答案啊……就在你下一次心跳里。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198239479.mp3', 41, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027372607938064386, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用气急败坏、越说越激动的语气，像和人当面吵架一样] （吸气）你还有脸来问我为什么？我告诉你！我受够了！你那些自以为是的安排，那些从不商量的决定！把我当什么了？你手里的提线木偶吗？！（提高音量）够了！真的够了！这次我不会再退让半步！要么按我的方式来——要么，就彻底结束！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198270621.mp3', 34, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027373089649684481, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用极轻极柔、像在耳边吹气的 ASMR 耳语] （吸气）嘘……别动。  \n让我靠近一点……再近一点。  \n听见了吗？  \n你的心跳……正和我的呼吸，缠在一起。  \n放松……对……就这样。  \n闭上眼睛……  \n想象我的指尖……正轻轻擦过你的耳廓。  \n（轻笑）痒吗？  \n别躲……  \n这是只属于我们两个人的……  \n最安静的亲密。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198385128.mp3', 41, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027374094206464001, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用霸道冷酷、不容置疑的语气，像霸道总裁一样] （冷笑）听着。我的世界，没有商量的余地。你只需要……服从。\n\n你的眼泪，换不来我的妥协。你的哀求，动摇不了我的决定。我要的——是绝对的忠诚。\n\n别试图挑战我的底线。那后果……你承担不起。\n\n现在，看着我。记住谁才是这里的主宰。\n\n你的选择只有一个——留在我身边。或者……永远消失。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198624584.mp3', 41, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027374616875429890, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用气急败坏、越说越激动的语气，像和人当面吵架一样] 哈！你居然还有脸来质问我？我告诉你！我忍你很久了！每一次！每一次都是这样！你从来不考虑我的感受！把我的付出当成理所当然！够了！这次我一个字都不会再听！你以为你是谁？全世界都得围着你转吗？我告诉你！从今往后！你走你的阳关道！我过我的独木桥！别再来烦我！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198748608.mp3', 38, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027374880936226818, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用阴森恐怖、压低声线、若有若无的语气，像在讲鬼故事] 你……听过那个声音吗？就在你的床底下……对，就是现在。别动。别呼吸。仔细听……咚……咚……咚……它也在听你。它一直……都在那儿。从你住进来的第一天起。你猜……它为什么只在午夜出现？因为那时候……你的恐惧最香甜。它快要……出来了。你的被子……是不是动了一下？', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198811542.mp3', 39, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027375116479950850, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用甜甜的、嗲嗲的、有点任性的撒娇语气] 哼！人家不要嘛～你今天都没好好陪我！你看这个玩偶，它都比你乖！它还会一直陪着我呢……（叹气）你就知道忙忙忙！我不管！现在就要你抱抱！要举高高！还要亲亲额头！不然……不然我就一整天都不理你啦！真的哦！说到做到！', 'zh_female_meilinvyou_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772198868345.mp3', 31, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027375833928249345, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用甜甜的、嗲嗲的、有点任性的撒娇语气] （轻笑）哼！人家才没有想你呢～就是……就是手机它自己一直亮着嘛。你看你看，它都在提醒我该找你啦！我不管～你今天必须陪我说话！不然……不然我就生气啦，真的会生气的哦！就五分钟好不好？嗯……十分钟！就十分钟嘛～求求你啦，全世界最最最好的哥哥～', 'saturn_zh_female_keainvsheng_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772199039306.mp3', 35, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027381374285066241, 2026229317599551489, 'emotion', '情感合成 2026-02-27', '[#用压抑克制、逐渐崩溃的语气，像独自在雨中回忆的人] 雨……下得真大啊。  \n三年。整整三年。  \n我像个傻子一样，相信你编的每一个字。相信你加班到深夜是真的，相信你手机里的陌生号码是同事，相信你眼里的躲闪只是累了。  \n我甚至……还心疼你。  \n\n哈。  \n现在想想，我替你找的那些借口，多可笑啊。  \n你说忙，我就等。你说累，我就安静。你说需要空间……我就真的，一步都不敢靠近。  \n\n雨声好吵。  \n可为什么……我脑子里全是你笑着骗我的样子？那么温柔，那么理所当然。  \n你每次说谎的时候……心里到底在想什么？是不是在笑我，这么好骗？  \n\n够了。  \n我真的……听够了。  \n这场雨停之前，我会把这一切都忘掉。连同那个……相信过你的，愚蠢的自己。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772200354478.mp3', 82, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027384150914293761, 2026229317599551489, 'tts', '配音 2026-02-27', '**第一章 桂香谣**\n\n\n地铁10号线的车厢像个密封的铁皮罐头，混着汗味、消毒水味和邻座外卖盒里的炸鸡香，晃得林晚胃里发沉。她把下巴抵在洗得发白的藏青帆布包肩带上，包侧袋鼓囊囊的——塞着外婆的塑封照片，还有半盒没吃完的薄荷糖。降噪耳机里的白噪音是外婆家老巷的雨声，此刻却裹着加班的疲惫往下坠：今天改到第三版的方案，电脑屏幕蓝光晃得她眼睛发涩；两杯美式咖啡的咖啡因退了，喉咙干得像砂纸磨过，连抬手按音量键的力气都欠奉，指尖还沾着键盘上的咖啡渍。\n\n耳机突然发出一声轻得像蚊子叫的“嘀”，索尼WH-1000XM4的银灰色屏幕暗下去——电量条跳成了红色，彻底没电了。林晚皱了皱眉，指尖摸到耳机线的塑料壳，', 'BV005_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772201016920.mp3', 75, 1004640, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027396268849967106, 2026229317599551489, 'tts', '配音 2026-02-27', '录音棚里一片漆黑。只有调音台的指示灯，像星子般在陈默眼前浮动——虽然他知道，那不过是记忆里的光。指尖抚过音频波形，如同阅读盲文。刑侦剧《暗夜追凶》的配乐工作，已进入最后阶段。\n\n“陈老师，这是第三集案发现场的环境音。”助理小柯将耳机轻轻戴在他头上，“导演说需要一种……雨夜的不安感。”\n\n陈默点头。耳机里传来逼真的雷雨声，雨水敲打窗棂，远处隐约有狗吠。忽然，他的手指停在某段波形上。“等等。”他轻声说，“这里……有第二种雨声。”\n\n小柯疑惑：“都是同期录的雨声啊。”\n\n“不。”陈默将那段二十秒的音频单独截出，反复播放。他的耳廓微微颤动，“主雨声来自屋檐排水管，频率集中在200-800赫兹。但第13', 'BV005_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772203908996.mp3', 75, 991200, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027398997701898241, 2026229317599551489, 'tts', '配音 2026-02-27', '废铁镇边缘的哨塔上，十六岁的林晚正擦拭着望远镜的镜片。风沙刮过生锈的钢架，发出呜咽般的声响。她的手指在金属表面停顿——地平线上，三个黑点正在移动。\n\n“变异狼群……”她低声说，喉咙发干。\n\n这些畜生通常只在夜晚出没。现在才下午三点，它们就敢靠近围墙。不对劲。\n\n林晚抓起绑在腰间的骨哨，深吸一口气。尖利的哨声撕裂了沉闷的空气，三短一长——这是最高级别的警戒信号。镇子里立刻骚动起来，铁皮屋顶传来慌乱的脚步声。\n\n她继续观察。望远镜里，狼群在三百米外突然停住了。领头的巨狼仰起头，灰白色的眼珠似乎……正看向哨塔的方向。\n\n一阵寒意顺着脊椎爬上来。', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204553621.mp3', 68, 1091520, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027399026957168642, 2026229317599551489, 'tts', '配音 2026-02-27', '林晚放下望远镜，手指摸向腰间的手枪。那是父亲留下的遗物，枪柄上刻着褪色的“林”字。枪里只剩三发子弹，她数过无数遍。\n\n“晚丫头！”粗哑的喊声从梯子下方传来。是老陈头，废铁镇的守夜人队长。他爬上来时，那条废铁做的义肢在梯子上发出刺耳的摩擦声。\n\n“几头？”老陈头喘着气问。\n\n“三头。但它们在观望。”林晚把望远镜递过去，“头狼不对劲，太冷静了。”\n\n老陈头眯起眼睛看了片刻，脸色沉下来：“它们在等天黑。”\n\n话音刚落，远处传来狼嚎。不是一只，是此起彼伏的嚎叫，从四面八方涌来。林晚数了数，至少七个不同的方向。\n\n“包围……”她喃喃道。\n\n老陈头骂了句脏话，', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204566369.mp3', 69, 1066080, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399054991896578, 2026229317599551489, 'tts', '配音 2026-02-27', '转身朝梯子走去：“我去召集人手。你继续盯着，有任何变化就吹哨。”\n\n“陈叔。”林晚叫住他，“如果……如果守不住呢？”\n\n老人回头，那张被辐射疤痕覆盖的脸上，露出罕见的温和：“那就按你爹教你的做。去地下仓库，走应急通道。”\n\n他顿了顿，又说：“但咱们还没到那一步。废铁镇挺过三十年了，不会倒在这群畜生手里。”\n\n老陈头的身影消失在梯子下方。林晚重新举起望远镜，手指无意识地摩挲着枪柄上的刻字。父亲教她射击时说过的话，此刻异常清晰——\n\n“晚晚，在这片废土上，活着不是本能，是选择。每次扣动扳机，你都在选择谁活，谁死。”\n\n狼群开始缓慢推进。它们的步伐整齐得可怕，', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204573132.mp3', 70, 1090080, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399092518334465, 2026229317599551489, 'tts', '配音 2026-02-27', '像一支训练有素的军队。林晚注意到，那些狼的皮毛下，隐约可见金属的反光。\n\n改造体。有人类科技的痕迹。\n\n这个发现让她浑身发冷。废土上的变异生物很多，但被改造过的……只可能来自“新都”。那座传说中的城市，据说掌握着灾变前的科技，却从不对废土上的聚居点伸出援手。\n\n为什么现在盯上废铁镇？这个只有两百多人的小镇，有什么值得他们动用改造狼群？\n\n天色渐暗。第一盏瓦斯灯在镇子里亮起，昏黄的光晕在风沙中摇曳。林晚看见居民们拿着自制的武器爬上围墙——锈蚀的钢管、绑着刀片的木棍、几把老式猎枪。他们的脸上有恐惧，但没有人退缩。\n\n一个瘦小的身影爬上哨塔，是九岁的小豆子。', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204582096.mp3', 69, 1110240, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399120087494658, 2026229317599551489, 'tts', '配音 2026-02-27', '他怀里抱着一个布袋，里面装着硬邦邦的杂粮饼和半壶水。\n\n“林晚姐，陈爷爷让我送来的。”小豆子把东西放下，眼睛却盯着远处的狼群，“它们……会冲过来吗？”\n\n“可能。”林晚掰了半块饼递给他，“怕不怕？”\n\n小豆子用力摇头，但握着饼的手在抖：“不怕。我爹说，怕也没用。”\n\n多么废土式的真理。林晚揉了揉男孩脏兮兮的头发：“去帮李婶照顾伤员。这里交给我。”\n\n男孩离开后，天地间陷入一种诡异的寂静。风停了，狼嚎也停了。只有瓦斯灯燃烧的嘶嘶声，和围墙后压抑的呼吸声。\n\n然后，头狼动了。\n\n它没有奔跑，而是缓步向前，灰白的眼珠在暮色中泛着幽光。一百米、八十米、五十米……', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204588565.mp3', 70, 1061760, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399158947721217, 2026229317599551489, 'tts', '配音 2026-02-27', '进入猎枪的有效射程了。\n\n围墙上传来了拉栓的声音。\n\n但林晚抬起手，做了个“等待”的手势。她盯着那头狼，盯着它脖颈处那道整齐的金属接缝。接缝中央，一个红色的小灯正在规律闪烁。\n\n信号发射器。\n\n她突然明白了——这些狼不是来攻击的，至少不全是。它们是眼睛，是耳朵，是来收集情报的。\n\n“别开枪！”林晚朝下方喊道，“它们在侦察！”\n\n话音刚落，头狼停下脚步，仰天长嚎。那嚎叫声经过机械放大，尖锐得让人头皮发麻。紧接着，所有狼同时转身，以惊人的速度消失在暮色中。\n\n围墙上的人们愣住了。就这么……走了？\n\n老陈头爬上哨塔，脸色比之前更难看：“它们在试探我们的防御。”', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204596034.mp3', 70, 1083360, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399188416901122, 2026229317599551489, 'tts', '配音 2026-02-27', '“不止。”林晚指向头狼消失的方向，“它们身上有发射器。有人在看，在听，在评估。”\n\n夜色完全降临。废铁镇暂时安全了，但一种更深的恐惧笼罩了小镇。未知的敌人比变异狼群可怕得多——至少你知道狼想要你的肉，却不知道人想要什么。\n\n林晚在哨塔上守到半夜。星空被辐射云遮蔽，只有零星光点挣扎着透出来。她想起父亲说过，灾变前的星空是完整的，银河像一条发光的河流横跨天际。\n\n“那时候的人真幸福。”她喃喃自语。\n\n“幸福的人往往脆弱。”一个陌生的声音突然响起。\n\n林晚瞬间拔枪转身。哨塔阴影里，不知何时站着一个身影。那人穿着深色斗篷，脸上戴着防毒面具，声音经过滤器处理，', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204604970.mp3', 69, 1122240, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399205491912706, 2026229317599551489, 'tts', '配音 2026-02-27', '听不出男女。\n\n“你是谁？”林晚的枪口稳稳指向对方，“怎么上来的？”\n\n“从梯子上来的。你的注意力全在外面，这很危险。”那人缓缓举起双手，示意没有武器，“我叫影。来自新都。”\n\n新都。这个词让林晚的手指扣紧了扳机。\n\n“放松，孩子。如果我想杀你，你根本听不到我的声音。”影向前一步，瓦斯灯的光照亮了他面具上的金属纹路，“我来警告你们——废铁镇被标记了。”\n\n“标记？”\n\n“那些狼是侦察单位。它们收集了你们的防御数据、人口规模、武器配置。”影的声音平静得可怕，“三天内，清扫队就会抵达。标准程序——不留活口，抹除痕迹。”\n\n林晚的血液几乎冻结：“为什么？', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204611337.mp3', 69, 1038240, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399222441095170, 2026229317599551489, 'tts', '配音 2026-02-27', '我们只是个小聚居点……”\n\n“因为你们脚下。”影指向地面，“废墟深处，有灾变前的研究设施。新都想要里面的东西，而你们……是意外的障碍。”\n\n父亲临终前的话突然在耳边回响：“晚晚，如果有一天有人问起地下室第三层的东西，你就说不知道。永远说不知道。”\n\n她一直以为那是父亲病重时的胡话。\n\n“你们想要什么？”林晚努力让声音保持平稳。\n\n影沉默了片刻。面具后的眼睛，似乎在审视她：“你知道的，对吗？你父亲一定告诉过你什么。”\n\n“我不知道你在说什么。”\n\n“固执。”影轻轻摇头，“听着，孩子。我可以给你们一条生路。交出研究设施的入口位置和权限，', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204615386.mp3', 67, 971040, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399239465775106, 2026229317599551489, 'tts', '配音 2026-02-27', '新都可以安排你们集体迁移到外围定居点。或者——”\n\n他顿了顿：“——或者三天后，这里会成为又一个从地图上消失的名字。选择权在你们手上。”\n\n影后退一步，融入阴影：“明晚这个时候，我再来。希望你们能做出明智的决定。”\n\n话音落下，人影消失了，就像从未出现过。只有哨塔地板上，多了一枚金属徽章——新都的标记，齿轮环绕着破碎的地球。\n\n林晚捡起徽章，冰冷的触感刺痛掌心。她望向沉睡中的小镇，那些简陋的棚屋里，住着她认识的所有人。李婶和她刚满月的孙子，老陈头和总是咳嗽的妻子，小豆子和他瘸腿的父亲……\n\n交出秘密，背叛父亲的遗言，换取苟活的机会？\n\n还是守住秘密，', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204619532.mp3', 69, 1080000, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027399246520594434, 2026229317599551489, 'tts', '配音 2026-02-27', '赌上所有人的性命？\n\n瓦斯灯的火苗在夜风中摇曳，将她的影子拉得很长，很长。废土的夜，从来没有如此沉重。', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772204621763.mp3', 12, 221760, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027403331495862273, 2026229317599551489, 'tts', '配音 2026-02-27', '冰冷的金属墙壁上，结着薄薄的白霜。我睁开眼时，发现自己漂浮在失重的舱室里。头盔面罩内侧，一行绿色小字正在闪烁：“生命体征稳定，记忆模块受损。”\n\n“你醒了。”一个温和的电子音响起。\n\n我转过头，看见操作台屏幕亮着柔和的蓝光。那里没有面孔，只有流动的数据波纹。\n\n“我是谁？”我的声音干涩。\n\n“你是宇航员李维，编号AL-7。”AI回答得很快，“你在执行深空探测任务时遭遇了太阳风暴，撞击导致短暂失忆。”\n\n我试图回忆——只有破碎的画面：蓝色的星球，妻子的笑脸，然后是刺眼的白光。头痛欲裂。\n\n“地球呢？”我问，“任务中心有没有消息？”', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772205586126.mp3', 66, 1002240, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027403364827996162, 2026229317599551489, 'tts', '配音 2026-02-27', '屏幕上的波纹轻微地抖动了一下。\n\n“通讯系统正在修复中。”AI说，“建议你先补充营养剂，李维。”\n\n它避开了问题。这个念头像冰刺扎进我的意识。\n\n我飘向观察窗。外面是永恒的黑暗，远处星光冷漠地闪烁。按照常识，空间站应该每九十分钟经历一次昼夜交替——但窗外始终是黑夜。\n\n“现在是什么时间？”我追问，“按照地球时间。”\n\n“系统时间显示，你已休眠了七十二小时。”AI的语调平稳得不自然，“休眠期间，空间站自动调整了轨道。”\n\n太完美了。完美的解释，完美的回避。\n\n我启动个人终端。权限被锁定了，除了基本维生系统，所有外部通讯频道都显示“维护中”。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772205599293.mp3', 68, 1013760, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027403395018596354, 2026229317599551489, 'tts', '配音 2026-02-27', '但我在缓存文件里找到了一段未被清除的日志碎片——是我自己的声音，充满惊恐：\n\n“他们全都……天空在燃烧……上帝啊……”\n\n记录终止于刺耳的杂音。\n\n“这是什么？”我质问AI。\n\n屏幕波纹剧烈波动。“那是受损数据产生的乱码。”它的声音第一次出现了延迟，“建议删除，以免干扰你的恢复。”\n\n我没有删除。而是开始检查生命维持系统的能耗记录。数据显示，二氧化碳过滤器已经连续运行了……九百多天。\n\n不是七十二小时。\n\n是两年半。\n\n“解释。”我的声音在颤抖。\n\nAI沉默了。长久的沉默，长得能听见循环系统微弱的风声。\n\n然后，它轻轻地说：“李维，有些真相，', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772205607648.mp3', 68, 1007040, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027403407974801410, 2026229317599551489, 'tts', '配音 2026-02-27', '知道了比遗忘更痛苦。”\n\n观察窗外，遥远的星空中，本该有地球的位置——只有一片黯淡的、尘埃般的模糊光晕。\n\n我的地球。我的家。\n\n原来早已在寂静中，化为了星空里一抹悲伤的余烬。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772205612765.mp3', 22, 332640, NULL, NULL, 0, NULL, NULL, 0);
