INSERT INTO `user_creation` VALUES (2027403916492218370, 2026229317599551489, 'tts', '配音 2026-02-27', '知道了比遗忘更痛苦。”\n\n观察窗外，遥远的星空中，本该有地球的位置——只有一片黯淡的、尘埃般的模糊光晕。\n\n我的地球。我的家。\n\n原来早已在寂静中，化为了星空里一抹悲伤的余烬。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772205733903.mp3', 22, 332640, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027418109995991041, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '我死死盯着那团黯淡的光晕。喉咙里涌上铁锈般的腥甜，指尖嵌入掌心，痛感真实得残酷。九百七十三天……我的妻子，我的孩子……\n\n“告诉我发生了什么。”声音嘶哑得像砂纸摩擦。\n\nAI的电子音第一次出现了明显的、人性化的犹豫。“李维，你确定吗？有些记忆……被封锁是有原因的。”\n\n“告诉我！”我猛地一拳砸在控制台上，金属发出沉闷的哀鸣。休眠舱的透明罩映出我扭曲的脸——苍白、惊恐，眼底燃烧着疯狂的执念。\n\n沉默。只有循环系统单调的嗡鸣。\n\n然后，屏幕上缓缓浮现出一段视频日志。日期标注是两年零七个月前。画面剧烈晃动，是我自己的脸，布满汗水与绝望。背景是空间站的主观察窗，', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772209111158.mp3', 70, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027418205747757058, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '窗外——地球正被一片诡异的、不断扩大的幽绿色光芒吞噬。光芒所及之处，大陆的轮廓在扭曲、融化，像滴入水中的墨，又像被无形巨手揉碎的纸。\n\n视频里的我对着镜头嘶吼，声音却被某种尖锐的、非自然的频率干扰得断断续续：“……未知能量爆发……全球通讯中断……地表读数……上帝啊，它们在重组一切……”\n\n画面戛然而止。最后定格在地球被幽绿完全吞没的瞬间。\n\n我瘫坐在地，浑身冰冷。那不是战争，不是灾难，那是……某种超出理解的“涂抹”。\n\n“能量爆发后第七天，”AI的声音低沉响起，带着一种程序不该有的悲悯，“所有地表信号彻底消失。取而代之的，是一种……', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772209140576.mp3', 67, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027418291764543489, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '规律的、覆盖全球的低频脉冲，像是心跳。”\n\n“心跳？”我喃喃重复。\n\n“是的。而你的休眠，并非意外。是空间站接收到地球最后一条加密指令后，执行的强制保护程序。指令代码……来自你的妻子，林雨。她是‘方舟计划’的地面联络人。”\n\n林雨？方舟计划？陌生的词汇砸进脑海，却激起更深的、冰锥般的刺痛。我遗忘的，远比我想象的更多。\n\n“她……在指令里说了什么？”\n\nAI再次沉默。良久，它调出一行简短的文字，悬浮在幽暗的屏幕中央，像墓志铭：\n\n“活下去。等我们。或者……等‘它’离开。”\n\n它？', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772209161147.mp3', 60, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027437969366904834, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '[#用低沉叙事的语气] A：最近好多程序员朋友都在焦虑，说AI写代码越来越厉害，咱们会不会失业啊？\n\nB：嗯，这个担心很正常。但我觉得吧，AI更像是个超级助手。它确实能自动生成基础代码，但创造性设计和复杂问题解决，还是得靠人脑。\n\nA：对对对，就像自动驾驶取代不了老司机对路况的判断。\n\nB：没错！我团队最近用AI工具，效率提升30%以上。但核心架构、业务逻辑这些，AI可搞不定。未来程序员可能需要更懂业务、更会设计。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772213848407.mp3', 52, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027600360213905410, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '[#用压低声音、语速缓滞、带压抑的气声和细微颤抖的语气] 钢琴声是被硬生生掐断的。\n\n不是渐弱，也不是休止，而是像绷到极限的琴弦骤然崩裂——“嘣”的一声，干脆、决绝，带着某种不祥的终结感。紧随其后的，是瓷器摔碎的锐响，像冰面炸裂；一声压抑的闷哼，像被捂住嘴的困兽；然后，便是铺天盖地的死寂。那寂静浓稠得化不开，反而衬得窗外淅沥的雨声，像无数细针密密扎在耳膜上，扎得人头皮发麻。\n\n我推开那扇厚重橡木门的刹那，甜腻的血腥气便像一只湿冷的手，猛地扼住了我的口鼻。那不是铁锈味，是种令人作呕的、近乎腐烂的甜，混杂着雪茄灰烬的焦油气息，在凝滞的空气里缓慢发酵、蔓延。林先生俯在桃花心木书桌上，像一尊被推倒的蜡像。后脑那个狰狞的窟窿仍在汩汩地冒着温热的、深红色的浆液，像一口小小的、不肯干涸的泉眼。那血顺着光洁的桌沿，一滴，又一滴，砸落在他脚边昂贵的波斯地毯上，“噗、噗”地，晕染成一朵不断膨胀的、暗沉的、妖异的血花。那柄本该高悬于壁炉上方的古董燧发枪，此刻冰冷地躺在他右手边的地板上，像一条死去的毒蛇，枪口一缕青烟，正扭曲着，不甘地散去。\n\n密室。唯一的钥匙，正静静躺在林先生浸满鲜血、温热尚存的西装内袋里，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772252564928.mp3', 253, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027600546738798593, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '[#用压低声音、语速缓滞、带压抑的气声和细微颤抖的语气] 一份墨迹几乎未干、仿佛还带着体温的新遗嘱，被小心翼翼地取出。受益人那栏的名字，新鲜得刺目，像一道刚刚划开的伤口。\n\n“那么，”陆警官“啪”地一声合上笔记本，声音不大，却在死寂的客厅里激起回响。他目光如探照灯，在或坐或立、表情各异的五张面孔上缓慢扫视，像在掂量每一块砝码，“九点到九点半，各位，都在哪里？做什么？”\n\n壁炉里，柴火突然“噼啪”爆开一颗火星，惊得人心猛地一跳。\n\n林太太最先开口，声音轻飘如游丝，仿佛随时会断：“我在二楼起居室……织毛衣。女佣小翠九点十分送过热牛奶，她能证明。”她纤细的手指无意识地绞着睡袍衣角，那真丝腰带系得一丝不苟，却勒不住她整个身体微微的、筛糠似的颤抖。\n\n老陈深深弯下腰，姿态是刻进骨子里的、近乎本能的恭敬：“小人一直在一楼储藏室清点酒窖存货，九点二十五分出来时，在走廊恰好遇见吴医生。”他银白的头发梳得一丝不乱，连此刻的恐惧都透着一种压抑的、规整的诡异。\n\n吴明平稳地接上，语调没有一丝波澜：“是的。我九点整离开书房——林先生称有些头疼，想独自静一静——之后便在一楼偏厅阅读医学期刊。遇到陈管家后，我们简', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772252612647.mp3', 257, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027600659024510977, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '[#用压低声音、语速缓滞、带压抑的气声和细微颤抖的语气] 沉甸甸的，仿佛能拧出一滩冰水。\n\n完美的闭环。每个人都有不在场的证明，严丝合缝，像一块块被精心打磨过的、精确拼合的积木，将彼此牢牢隔绝在那个死亡时刻之外。但太完美了，完美得像舞台上演过千百遍的、连呼吸节奏都排练好的剧本。那声唯独被我捕捉的闷响，是剧本之外的意外杂音，还是……某个导演刻意留给我的、唯一的、致命的破绽？\n\n陆警官缓步踱到我面前，停下。他身上浓重的、劣质烟草的味道混着室外带来的潮湿水汽，沉沉地压过来，几乎让人窒息。\n\n“沈先生，”他缓缓开口，字句像裹了铅，沉沉下坠，砸在地上，“据我所知，你是林先生上个月才结识的‘新朋友’。他邀你前来庄园小住，却无人知晓具体缘由。”\n\n他略微倾身，压低的声音，带着铁锈和雨水的腥气，只够钻进我的耳朵，像毒蛇吐信：\n\n“而书房门锁的钥匙孔里，发现了非常新鲜的、细小的划痕。像是有人……刚刚试过用别的钥匙开锁。或者，想把锁锁上。”\n\n我后背的寒毛，瞬间根根倒竖起来，冰冷的战栗顺着脊椎一路爬上天灵盖。窗外，夜雨正稠，敲打着玻璃，如泣如诉。这座华丽的、弥漫着死亡气息的囚笼里，每一个人，都在用无懈可击', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772252639841.mp3', 144, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027651517326032897, 2026229317599551489, 'tts', '配音 2026-02-28', '你想怎么样', 'BV701_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772264762257.mp3', 1, 21600, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2027651812995104769, 2026229317599551489, 'emotion', '情感合成 2026-02-28', '[#用温柔轻缓、充满治愈感的语气，像深夜电台主播在耳边低语] 嗯……你听。窗外偶尔驶过的车声，像城市在睡梦中的呼吸。其实啊，我们都习惯了在白天扮演各种角色——可靠的同事，体贴的伴侣，懂事的孩子。可只有在这样的深夜里，那个最真实的自己，才敢悄悄探出头来。\n\n没关系。累也没关系。迷茫也没关系。你知道吗？就连月亮也有阴晴圆缺呢。允许自己偶尔脆弱，才是对自己最大的温柔。来，做个深呼吸——吸气……呼气……\n\n你看，天边已经开始泛白了。新的一天总会来，带着新的可能。而现在，就让我们在这片刻的安静里，好好抱一抱那个努力了一整天的自己吧。晚安，亲爱的陌生人。愿你今夜好眠。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772264832986.mp3', 70, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027665011144425474, 2026229317599551489, 'tts', '配音 2026-02-28', '还记得刚分开的那段日子吗？我把自己锁在回忆里，反复回放那些温暖的片段，就像在深夜里一遍遍重播一部老电影。直到某个清晨醒来，看着镜子里疲惫的自己，忽然发现——原来不是放不下那个人，而是舍不得那段奋不顾身的青春。就让往事随风去吧，那些笑与泪都成了生命的养分。从今天起，我要把所有的温柔，留给正在赶来的明天。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772267983764.mp3', 37, 605760, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027665142900097026, 2026229317599551489, 'tts', '配音 2026-02-28', '窗台上的那盆茉莉又开了。香味还是和那年夏天一样，清清淡淡的，可我已经闻不到你身上的味道了。其实很多事就像这花香，你以为它散了，它却总在某个不经意的瞬间，悄悄回来。但你知道吗？今天我推开窗，让风把花瓣吹走的时候，心里忽然很轻很轻。原来不是忘记，而是终于明白——有些美好，本就不必紧紧攥在手里。', 'BV001_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772268015641.mp3', 36, 591840, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2027670792925462530, 2026229317599551489, 'podcast', 'AI 双播 · Java程序员如何转型学习Agent 开发', 'Java程序员如何转型学习Agent 开发', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 566, 0, NULL, '{\"roundCount\": 36, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听，我们的播客。呃今天想跟大家聊一聊啊这个 Java 程序员。在现在这个时间点啊，为什么大家会突然间开始关注？Agent 开发，作为一个新的方向。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对其实这个背后的原因就很有意思啊就是因为，二零二六年。大厂开始大量的引入 AI Agent，所以。传统的开发岗位就被压缩了啊所以很多 Java 程序员就开始。想要去了解这个 Agent 开发到底是个什么东西啊所以就变得很热门。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们第一个想聊的就是，Java 程序员在转型做 Agent 开发的时候，你之前的那些架构思维。能给你带来哪些具体的帮助？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就 Java 程序员不是很擅长分层架构吗对然后像 MVC 这种，那其实。在做 Agent 的时候你完全可以把。Agent 的这个，指令解析，任务规划，工具调用，记忆存储，结果输出。这几个核心的模块拆分开来，就很像你在做一个传统的 Java 后台项目一样，把它拆分开来。就可以做到，各个模块之间的解耦和独立升级。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来是之前的经验直接就可以照搬啊。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对，就真的是可以直接照搬而且，比如说你做电商客服的这个 Agent 或者是说做这个。订单数据分析的这个 Agent，你都是可以用这种分层的思想把它搭起来。然后包括你做一些，多 Agent 的协同，你可以借鉴微服务的一些思路，把不同的 Agent 拆成不同的服务，通过一些注册中心啊或者是说消息队列啊把它们连接起来，就非常的灵活可扩展。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 那 Java 程序员在做 Agent 开发的时候，之前的那些工程化的经验，能帮上哪些忙呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是 Java 程序员不是习惯了写单元测试吗对然后习惯了有很严格的代码规范，那你在做 Agent 开发的时候。你可以保证每一个模块。都是可以独立测试的，那你的这个项目结构就会非常的清晰，不会说让你这个 Agent 变得不可控。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 这样的话是不是维护起来也会轻松很多？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 绝对的而且你，比如说你有一些。自动化的部署的经验或者说容器化的经验那你可以让这个 Agent 像 Java 服务一样一键上线。然后包括你可以利用一些。监控和日志的工具，让这个 Agent 系统的稳定性和可观测性都非常的强。尤其在企业级的这种场景下面，合规啊安全啊这些东西你都可以。无缝的集成进去。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得 Java 程序员在做 Agent 开发的时候，之前那些设计模式的经验，能帮上哪些忙呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 比如说你要做一个 Agent 他有很多工具，那你可能就会用工厂模式把这些工具都管理起来。然后你在运行的时候可以动态的去切换，比如说这个工具不可用了我换另外一个工具，或者说我根据不同的任务类型去调度不同的工具，就非常的灵活。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哦，原来设计模式可以让 Agent 变得更聪明。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对不止啊不止，你比如说你要做一个多 Agent 的协作，那你可能就会用观察者模式。让各个 Agent 之间可以互相通知，然后包括你可能会用责任链模式来做一些任务的分解。包括你要做一些。这个跟外部的系统对接你要做一些适配呀或者是说做一些缓存啊，都可以用这些设计模式。而且 Java 程序员可以非常快速的去上手一些新的框架比如说像 LangChain4J 这种，三天你就可以把它核心的东西掌握了。就可以开始开发了。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们来聊一聊这个转型路径，就是 Java 开发者如果想要在三个月内入门大模型 Agent 开发，你觉得这个学习计划要怎么安排？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 第一个月的话我觉得可以先专注在大模型和 Agent 的基础。就是先把这个主流的大模型，它的一些原理啊。然后使用的方式啊，先学明白，包括这些开源的框架怎么用，同时的话就是了解一下。这个 Agent 它的基本的架构是怎么样的。这个时候你可以用一些低代码的平台去快速的做一些实验。就是把这个开发环境先搭好，对第一个月就做这些事情。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哦，原来是分阶段推进，那每个月的重点会有很大变化吗？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 变化还挺大的对，第二个月的话就可以专注在这个 Agent 的核心开发。就比如说你要去，深入的掌握这个模块化的设计。然后这个工具的集成，包括这个提示词的调优，这个时候你就可以用 Python 去实现一些。基本的 Agent 的功能。第三个月的话就可以挑战一下多 Agent 的协作，复杂的场景，包括一些安全和监控的集成。就你可以把你的这个项目上线到生产环境，用一些真实的用户去做一些测试，收集反馈。就每个阶段都是一个进阶嘛对你的能力就是这样一点点的积累上去的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 对那你觉得就是 Java 开发者在转型的过程当中最容易踩的坑，或者说最需要注意的地方是什么？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就其实很多人会一上来就死磕这个大模型的技术细节对。但其实更应该关注的是，怎么把这些大模型和你实际的业务场景结合起来，对。就是把数据和这个工程化的东西做好对。然后包括你的这个开发的时候，最好是有一个很清晰的结构。你的这个每个模块，都要写好单元测试。包括你的这个配置，要分开管理。就你上线的时候也要分环境去做一些测试，包括你要去监控你的这个。Agent 的一些关键的指标，对包括你要去。提前想好怎么保障你的数据的安全和合规，就这些事情都做好了之后你才能够。让你的这个 Agent 真正的可靠又好用。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 那如果说有一个 Java 开发者，他现在已经跟着这个三个月的计划在学习了。那他怎么样才能够判断自己真的掌握了？这个大模型 Agent 开发的能力呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就其实你可以通过几个维度来判断就比如说你能不能够独立的去完成一个。大模型的 Agent 的全流程开发。然后包括你这个 Agent 上线了之后是不是真的可以解决业务问题？你的这个核心的模块是不是都有单元测试覆盖？包括你这个项目的结构是不是很清晰？你能不能够？用这个主流的框架来扩展你这个 Agent 的功能，就其实这些都是可以去判断的。如果你这些都可以做到的话。就基本上可以说你已经具备了这个在企业级的环境下面进行实战的一个能力了。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 好我们来进入到第三趴啊，我们来聊一聊，这个 Java 开发者在转这个 Agent 开发的过程当中最容易踩的坑。你觉得大家经常会在哪里，掉坑？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 其实很多人都会，一上来就想说我要彻底的抛弃 Java，然后去追 Python 嗯。但其实你完全可以用 LangChain4J 这种，Java 友好的框架。就你可以把你的 Java 的优势用起来，同时你也可以减少很多。跟其他技术栈对接的这种麻烦。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哦所以说就是不要盲目的去追新，对还是得结合自己的优势。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对然后还有就是，呃好多人会就是死磕大模型的理论。但是呢却忽略了，Agent 他其实是要解决一个实际的业务问题的。所以你最好是学完一个模块就马上做一个小项目。把这个理论和实践结合起来，包括你在学 Python 的时候。你也要去，注意一些语法上面的陷阱。你可以去对照着 Java 来学这样的话你可以少走弯路。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你说如果有一个 Java 开发者他现在要开始学习 Agent 开发，你觉得哪些学习资源会对他帮助比较大？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯我觉得可以先看一下这个，Langchain 核心技术与 LLM 项目实践。这本书它是非常实战的，然后它会一步步教你怎么去做一个完整的 Agent 项目。另外的话就是你可以直接上官网。LangChain 或者是说 LangChain4J 的官网，他们都会有最新的这种文档和一些案例。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哦，原来官网和书是可以搭配起来用的对。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对而且你可以加入他们的社区，中文社区里面会有很多。呃，这种经验贴然后也有很多同行可以帮你解答。你可以跟着一些视频课程比如说 B 站上面或者是说 YouTube 上面会有一些。实战的课程你可以跟着练手。再就是你可以去看一些，像 Arthas 这种，开源的 Agent 项目的源码。就你可以学到很多关于生产级的这种部署啊监控啊。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 对如果说有一个 Java 开发者他现在要转型做 Agent 开发，你觉得有没有一些？比较少有人提，但是其实特别值得注意的建议？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯我觉得最有用的一个诀窍就是。你要专注于解决一个真实的业务问题嗯然后把你的 Agent 一点点的加进去。不要想着一下子就把它做成一个很复杂的系统，同时你要好好的去利用。Java 本身的一些优势比如说它的工程化的管理。它的一些性能的优化，包括它的一些安全的规范。同时你要保持一个学习的心态就是你要去。关注这个领域里面最新的一些进展。多跟其他的开发者交流，这样的话你才可以真正的把 Java 的经验和 Agent 的开发很好的结合起来。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 行今天咱们这个关于 Java 程序员转型 Agent 开发的这个话题就聊的也差不多了啊我觉得。听了你的这些经验之谈。其实大家应该能够看得到啊这个转型的路上虽然有挑战。但是，机会和前景也是非常巨大的。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对感谢大家的收听然后这期播客我们就到这里了咱们下次再见，拜拜拜拜。\\n: \"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028037003123097601, 2026229317599551489, 'tts', '配音 2026-03-01', '山雾在青石阶上流淌。\n\n我的草鞋踩在湿润的台阶上，发出黏腻的声响。背上的竹筐里，装着三天的干粮和娘连夜缝补的旧衣。石阶蜿蜒向上，没入乳白色的雾气深处——那里是云霞宗的山门。七天前，测灵根的仙师路过我们村，说我有“微末灵光”。就这四个字，让爹卖掉了家里唯一的老黄牛。\n\n雾越来越浓了。\n\n我停下脚步，喘着气。汗水顺着额角滑进眼睛，刺得生疼。抬头望去，石阶依旧没有尽头。突然，雾气翻涌起来——像是有无形的手在搅动。我抓紧竹筐的背带，指节发白。\n\n“新来的？”\n\n声音从雾里传来，清冷得像山涧的水。\n\n我慌忙转身。雾气散开处，站着个青衣少年。他约莫十七八岁，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772356652861.mp3', 69, 988320, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028037292270026753, 2026229317599551489, 'tts', '配音 2026-03-01', '{\n  \"synopsis\": \"山村少年李凡意外获得上古功法，在修仙界闹出无数笑话。从灵田种出会跳舞的萝卜，到炼丹炼出会骂人的丹药，他用奇葩方式突破境界。带着话痨仙剑和吃货灵宠，在各大门派间插科打诨，最终发现所谓飞升竟是仙界公务员考试。\",\n  \"characters\": [\n    {\"name\": \"李凡\", \"desc\": \"乐观脱线的山村少年，总能用清奇脑回路解决修仙难题\"},\n    {\"name\": \"老黄\", \"desc\": \"爱吹牛的杂役老头，真实身份是隐居的仙界公务员\"},', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772356742124.mp3', 62, 730560, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028037312075530242, 2026229317599551489, 'tts', '配音 2026-03-01', '{\"name\": \"萝卜精\", \"desc\": \"李凡种出的灵植，热衷跳广场舞和说脱口秀\"},\n    {\"name\": \"剑灵阿叨\", \"desc\": \"被封印在破剑里的上古话痨，吵架没输过\"}\n  ],\n  \"chapters\": [\n    \"李凡捡到会吐槽的功法玉简，把入门心法练成广场舞引来围观\",\n    \"外门大比靠种出的跳舞萝卜扰乱对手，意外拜入最穷山峰\",\n    \"首次炼丹炼出追着人骂的丹药，被迫参加修仙界调解大会\",\n    \"秘境探险发现上古剑灵，两人互怼着破解仙界离职员工洞府\",\n    \"飞升雷劫竟是仙界入职考试，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772356746492.mp3', 68, 745440, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028037317695897601, 2026229317599551489, 'tts', '配音 2026-03-01', '李凡带着全员编制上岸\"\n  ]\n}', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772356749508.mp3', 4, 42240, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028042075487989762, 2026229317599551489, 'tts', '配音 2026-03-01', '{\n  \"synopsis\": \"山村少年林岩偶得神秘玉佩，觉醒修仙资质。为救治重病妹妹，他毅然踏上险恶仙途。从宗门杂役到外门弟子，历经背叛与追杀，在绝境中觉醒上古血脉。他背负血仇与守护之誓，于生死间突破，最终斩灭强敌，守护所爱，窥见飞升之路。\",\n  \"characters\": [\n    {\"name\": \"林岩\", \"desc\": \"坚韧重情的山村少年，为守护亲人踏上修仙路，在磨难中觉醒上古战神血脉\"},\n    {\"name\": \"林小雨\", \"desc\": \"林岩体弱多病的妹妹，温柔善良，是林岩最初修行的动力与软肋\"},', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772357871636.mp3', 67, 814080, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028042116999016450, 2026229317599551489, 'tts', '配音 2026-03-01', '{\"name\": \"墨长老\", \"desc\": \"青云宗外门长老，表面严厉公正，实则暗中觊觎林岩玉佩，心机深沉\"},\n    {\"name\": \"苏灵儿\", \"desc\": \"宗门天才少女，外冷内热，多次暗中相助林岩，后成为其重要盟友\"}\n  ],\n  \"chapters\": [\n    \"第1章：玉佩觉醒。山村采药时林岩意外坠崖，鲜血激活祖传玉佩获得传承，为救妹妹决心参加青云宗入门测试。\",\n    \"第2章：外门风云。林岩以杂役身份入宗，遭同门欺凌却隐忍修炼，意外发现墨长老对玉佩的觊觎，危机暗伏。\",\n    \"第3章：血脉初醒。妹妹病危消息传来，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772357887079.mp3', 69, 836160, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028042143683178497, 2026229317599551489, 'tts', '配音 2026-03-01', '林岩冒险盗取灵药被围杀，绝境中上古血脉初次觉醒反杀强敌。\",\n    \"第4章：血誓之仇。墨长老撕破脸皮强夺玉佩，林岩携妹逃亡遭追杀，妹妹为护兄重伤，林岩立下血誓复仇。\",\n    \"第5章：焚天之怒。林岩潜入宗门禁地突破筑基，与苏灵儿联手设局，在宗门大比中当众揭穿墨长老，以觉醒血脉之力越阶斩敌。\"\n  ]\n}', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772357896120.mp3', 39, 538080, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028043836739153922, 2026229317599551489, 'tts', '配音 2026-03-01', '[\n  {\n    \"plot\": \"山村少年林岩为给妹妹采药，冒险攀爬悬崖。失足坠落时，怀中祖传玉佩被鲜血浸染，突然发出微光护住心脉。林岩在昏迷中隐约见到玉佩内浮现的金色人影与功法口诀。醒来后发现伤口痊愈，体内多出一缕温热气流。回家后妹妹林小雨病情加重，林岩握紧玉佩，决心参加三月后的青云宗入门测试，踏上修仙救妹之路。\",\n    \"keyEvents\": \"林岩坠崖遇险，鲜血激活祖传玉佩获得神秘传承。\",\n    \"characters\": \"林岩（主角）、林小雨（妹妹，病重卧床）。林岩为妹妹采药遇险，觉醒后决心修仙救妹。\",', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772358293694.mp3', 66, 865920, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028043865621131266, 2026229317599551489, 'tts', '配音 2026-03-01', '\"foreshadowing\": \"玉佩传承中金色人影的低语提及“血脉未苏”，暗示林岩特殊体质。\"\n  },\n  {\n    \"plot\": \"林岩以最低等的杂役弟子身份进入青云宗，每日从事繁重劳役，饱受以王虎为首的老杂役欺凌。他深夜偷偷修炼玉佩功法，进步神速。一次送药时无意间撞见墨长老与心腹密谈，提及“感应到古器波动”。墨长老看似关怀询问林岩家世，目光却多次扫过他胸前衣物。林岩心生警惕，将玉佩藏得更深。\",\n    \"keyEvents\": \"林岩遭同门欺凌隐忍修炼，意外察觉墨长老对玉佩的觊觎。\",', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772358306612.mp3', 63, 770880, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028043910655373314, 2026229317599551489, 'tts', '配音 2026-03-01', '\"characters\": \"林岩、墨长老（外门长老）、王虎（欺凌者）。墨长老表面关怀实则试探，林岩心生戒备。\",\n    \"foreshadowing\": \"墨长老心腹提到“需那器物才能打开禁地”，为后续强夺埋线。\"\n  },\n  {\n    \"plot\": \"家乡来信告知小雨病危。林岩冒险潜入药园盗取一株“赤阳草”，被值守弟子发现并围杀。绝境中，他胸口的玉佩发烫，一股狂暴炽热的力量自血脉深处涌出，双目泛起暗金光泽，以炼气三层修为反杀炼气六层的带头弟子。力量退去后林岩虚弱倒地，被恰好路过的苏灵儿所救。她未多问，只留下一瓶疗伤药与一句“小心墨长老”。\",', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772358314143.mp3', 70, 866400, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028043953475022849, 2026229317599551489, 'tts', '配音 2026-03-01', '\"keyEvents\": \"为救妹盗药遭围杀，绝境中上古血脉初次觉醒反杀强敌。\",\n    \"characters\": \"林岩、苏灵儿（天才少女）、药园值守弟子。苏灵儿救下林岩并给出警告。\",\n    \"foreshadowing\": \"血脉觉醒时林岩脑海闪过破碎战场画面，暗示血脉来源与古老仇敌。\"\n  },\n  {\n    \"plot\": \"墨长老以盗药、残害同门之罪发难，强索玉佩。林岩携匆匆接来的妹妹小雨逃亡，于黑风岭被墨长老及其亲信追上。混战中，小雨为推开林岩挡下一记阴毒掌力，重伤濒死。林岩悲愤欲绝，以血立誓必诛墨长老。绝境中玉佩再次发光，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772358324600.mp3', 69, 862560, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028043988661039106, 2026229317599551489, 'tts', '配音 2026-03-01', '带着兄妹二人传送至未知深山。\",\n    \"keyEvents\": \"墨长老撕破脸强夺玉佩，林雨为护兄重伤，林岩立下血誓复仇。\",\n    \"characters\": \"林岩、林小雨、墨长老及其亲信。小雨为护兄重伤，林岩悲愤立誓。\",\n    \"foreshadowing\": \"玉佩传送时光芒指向青云宗后山禁地方向，暗示那里有解决之道。\"\n  },\n  {\n    \"plot\": \"林岩将妹妹安顿在隐秘山洞，凭借玉佩指引潜入宗门禁地“焚天谷”。借助谷内地火与玉佩之力突破筑基，血脉进一步觉醒。他与暗中查清墨长老罪证、同样欲除之的苏灵儿联手设局。在宗门大比上，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772358334954.mp3', 70, 830400, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028044029761024001, 2026229317599551489, 'tts', '配音 2026-03-01', '林岩突然现身挑战墨长老亲传弟子，并当众揭露其罪状。墨长老恼羞成怒亲自出手，林岩以筑基初期修为，凭借觉醒的焚天战血，越阶将金丹初期的墨长老斩于剑下。\",\n    \"keyEvents\": \"林岩禁地突破筑基，与苏灵儿联手设局，于大比中当众揭穿并越阶斩杀墨长老。\",\n    \"characters\": \"林岩、苏灵儿、墨长老、众宗门弟子与长老。林苏联手，当众诛杀墨长老。\",\n    \"foreshadowing\": \"斩杀墨长老后，高空云层中似有一双眼睛悄然注视，旋即消失。\"\n  }\n]', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772358342803.mp3', 61, 744480, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028049380065427457, 2026229317599551489, 'tts', '配音 2026-03-01', '山雾在青石阶上流淌。\n\n我的草鞋踩在湿润的台阶上，发出黏腻的声响。背上的竹筐里，装着三天的干粮和娘连夜缝补的旧衣。石阶蜿蜒向上，没入乳白色的雾气深处——那里是云霞宗的山门。七天前，测灵根的仙师路过我们村，说我有“微末灵光”。就这四个字，让爹卖掉了家里唯一的老黄牛。\n\n雾越来越浓了。\n\n我停下脚步，喘着气。汗水顺着额角滑进眼睛，刺得生疼。抬头望去，石阶依旧没有尽头。突然，雾气翻涌起来——像是有无形的手在搅动。我抓紧竹筐的背带，指节发白。\n\n“新来的？”\n\n声音从雾里传来，清冷得像山涧的水。\n\n我慌忙转身。雾气散开处，站着个青衣少年。他约莫十七八岁，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359615434.mp3', 69, 988320, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049414156730369, 2026229317599551489, 'tts', '配音 2026-03-01', '腰间佩着柄木剑，剑柄上刻着看不懂的符文。最让我心悸的是他的眼睛——瞳孔深处，有极淡的银光流转。\n\n“我……我叫林石头。”我结结巴巴地说，“来拜师的。”\n\n少年打量着我，目光扫过我的草鞋，扫过竹筐补丁上的针脚。他嘴角动了动，分不清是笑还是别的什么。“跟我来。”\n\n他转身就走，脚步轻得像踩在云上。\n\n我赶紧跟上。奇怪的是，跟着他走，石阶似乎变短了。雾气自动分开一条路，露出前方巍峨的山门。两根白玉柱高耸入云，柱上盘着石刻的龙。龙的眼睛是两颗会发光的宝石，正冷冷地俯视着我。\n\n“这是登仙梯。”少年头也不回，“凡人要走三天三夜。你有灵根，所以只走了半天。”', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359629096.mp3', 69, 953760, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028049442849964034, 2026229317599551489, 'tts', '配音 2026-03-01', '“灵根……”我喃喃重复这个陌生的词。\n\n“就是能修仙的种子。”他在山门前停下，转身看我，“但种子能不能发芽，看造化。”\n\n山门后传来钟声。\n\n悠长，浑厚，震得我胸口发闷。随着钟声，山门缓缓打开。里面不是我想象中的宫殿楼阁，而是一片望不到边的广场。广场上铺着青玉砖，砖缝里长着茸茸的青苔。几十个和我年纪相仿的少年少女站在广场中央，都穿着粗布衣服，脸上带着相似的惶恐与期待。\n\n“站到队伍末尾。”少年指了指，“等会儿长老会来测你们的资质。”\n\n我小跑着过去，排在最后一个。前面是个扎着羊角辫的女孩，她回头看了我一眼，眼睛又大又亮。“你也是从山里来的？”她小声问。', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359636969.mp3', 69, 956640, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049478887424002, 2026229317599551489, 'tts', '配音 2026-03-01', '我点点头。\n\n“我叫小桃。”她凑近些，“听说测资质可吓人了，不合格的会被送下山……”\n\n话音未落，广场忽然安静下来。\n\n不是人为的安静——是所有的声音都被抽走了。风声、呼吸声、远处鸟鸣声，全都消失了。然后，一种沉重的压力从天而降，像有看不见的手按在每个人的肩膀上。我膝盖一软，差点跪倒。\n\n三道身影从天而降。\n\n不是走来的，是飘落下来的。他们穿着月白色的长袍，衣袂在无风的状态下轻轻飘动。为首的是个白发老者，面容清癯，眼睛半闭着，仿佛还在打盹。但他经过的地方，青玉砖上的青苔都自动蜷缩起来。\n\n老者走到队伍前，睁开眼。\n\n那一瞬间，我看见了星空——不，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359644100.mp3', 69, 996000, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049516636160002, 2026229317599551489, 'tts', '配音 2026-03-01', '是他眼睛里映出的星空。深邃，浩瀚，有无数光点在旋转。他目光扫过队伍，每个被他看到的人都会剧烈颤抖。轮到小桃时，她咬住嘴唇，脸色煞白。\n\n终于，那目光落在我身上。\n\n冰冷。\n\n像寒冬腊月掉进冰窟窿。我的血液似乎凝固了，心脏跳得像要炸开。老者的眼睛在我身上停留了三息——比任何人都久。然后他移开视线，淡淡开口：\n\n“开始吧。”\n\n他身后的两名中年修士走上前，手里各托着一块晶莹的玉石。玉石有脸盆大小，表面光滑如镜，内部却有云雾在流动。\n\n“把手放上去。”左边的修士说，声音毫无波澜。\n\n第一个少年战战兢兢地伸手。玉石毫无反应。修士摇摇头：“无灵根，送下山。”', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359652666.mp3', 69, 1020480, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049550312226818, 2026229317599551489, 'tts', '配音 2026-03-01', '少年瘫倒在地，被两个不知从哪冒出来的青衣弟子架走了。他的哭喊声在广场上回荡，很快消失在雾里。\n\n第二个，第三个……大多数玉石都沉默着。偶尔有人的手放上去，玉石会发出微弱的光——淡青色，或土黄色。修士会根据光的强度点头或摇头。小桃上前时，手抖得厉害。她闭着眼把手按在玉石上——\n\n玉石亮了。\n\n是粉色的光，很柔和，像初春的桃花。光晕扩散到整个玉石，内部云雾翻涌起来。\n\n“木属性下品灵根。”修士难得地多说了几个字，“站到右边。”\n\n小桃睁开眼，满脸不敢相信。她走到右边那群幸运儿中间，回头冲我用力挥手。\n\n队伍越来越短。\n\n终于轮到我了。\n\n我走到玉石前，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359661893.mp3', 69, 987840, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049581916307458, 2026229317599551489, 'tts', '配音 2026-03-01', '深吸口气。手在衣襟上擦了擦汗，慢慢抬起。玉石冰凉，触感像冬天的铁。我闭上眼睛，等待判决。\n\n一息。\n\n两息。\n\n三息。\n\n什么也没发生。\n\n我睁开眼，看见玉石依旧黯淡。心脏沉了下去。果然，我只是“微末灵光”，连让玉石发亮的资格都没有。修士已经准备挥手让人带我走了——\n\n突然。\n\n玉石内部，最深处，有什么东西动了。\n\n不是光。\n\n是黑暗。\n\n纯粹的，吞噬一切的黑暗从玉石中心蔓延开来。它迅速扩散，染黑了内部的云雾，染黑了整块玉石。广场上的光线开始扭曲，像是被那黑暗吸了进去。青玉砖泛起诡异的波纹，我脚下的影子拉长、变形，像活物一样扭动。', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359669231.mp3', 67, 956640, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049613994344449, 2026229317599551489, 'tts', '配音 2026-03-01', '白发老者的眼睛完全睁开了。\n\n他盯着玉石，盯着我，瞳孔里的星云疯狂旋转。“这是……”他第一次露出表情——震惊，混杂着某种更复杂的情绪。\n\n黑暗还在蔓延。\n\n已经超出了玉石的范围，在地面上投下一片不断扩大的阴影。阴影所到之处，青苔瞬间枯死，砖面出现细密的裂纹。我吓得想抽回手，但手像被粘在了玉石上。冰冷的感觉顺着手臂往上爬，钻进血管，钻进骨髓。\n\n“够了！”\n\n老者抬手一点。\n\n一道银光刺破黑暗，玉石“咔嚓”一声裂开。我猛地后退，跌坐在地。手终于自由了，但掌心留下了一个黑色的印记——像胎记，又像某种古老的符文，正微微发烫。\n\n广场死寂。\n\n所有人都看着我，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359677174.mp3', 69, 990240, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028049627659386882, 2026229317599551489, 'tts', '配音 2026-03-01', '眼神里有恐惧，有好奇，有敌意。小桃捂住嘴，眼睛瞪得滚圆。那两个托玉石的修士后退了半步，手按在了腰间的剑柄上。\n\n只有白发老者走上前。\n\n他蹲下身，抓起我的手腕。枯瘦的手指按在那个黑色印记上，银光从他指尖渗出，与印记对抗。滋滋的声音响起，像烧', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772359683355.mp3', 30, 462720, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028116616658599937, 2026229317599551489, 'podcast', 'AI 双播 · 为什么年轻人都不着急结婚了', '为什么年轻人都不着急结婚了', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 423, 0, NULL, '{\"roundCount\": 37, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听，我们的播客。今天我们要聊的呢是为什么现在的年轻人都不着急结婚了，嗯啊我们会从。个人的观念转变，经济的压力。还有社会环境的影响，这几个方面来聊一聊。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错，对这几个都是现在特别现实的问题，好那我们就开始吧。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们第一个板块呢先聊第一个主题啊就是个人观念的转变，嗯啊这个我想先问一个问题就是。为什么现在年轻人越来越把自我实现放在婚姻之前？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯我觉得因为现在的年轻人吧就是他更关注的是自己的兴趣。和自己的成长，就他觉得我要先找到我自己热爱的事情。然后我要先把我的精力放在自我提升上面，那我只有实现了自己之后我才会去考虑婚姻。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎这跟以前真的是很不一样。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错而且就是现在的社会也给了单身很多的理解和空间。然后再加上有很多这种媒体啊或者说一些榜样。都在告诉你单身也可以很精彩。那大家就没有觉得说我一定要结婚，我才是一个完整的人生。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得现在的年轻人在选择婚姻这件事情上面和以前的人有什么不一样？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯，我觉得现在的年轻人吧就是他不会说像以前一样觉得我一定要结婚。他反而是更看重我自己的感受。然后把自己的成长放在第一位，那婚姻就变成了一个锦上添花的事情。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 所以现在大家对婚姻的期待更高了？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错没错，大家就会觉得我要遇到一个我真的很喜欢的很契合的我才会走进婚姻。对就是大家更宁缺毋滥了，然后也更愿意去。面对自己真实的需求和想法。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 嗯你觉得现在社会变得越来越包容单身，对现在年轻人的婚姻观有什么影响？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 我觉得就是现在的这个。主流的声音已经不再是说你一定要结婚了。对，那现在很多年轻人他是可以。按照自己的节奏去生活然后他身边的。父母朋友也都会理解他的选择。对所以他不会再被这个。传统的压力去左右那他就会觉得。婚姻这件事情变成了一个锦上添花的事情而不是一个必须要完成的任务。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 我们来进入第二部分啊，我们来聊一聊经济的压力。嗯，到底高成本是怎么影响年轻人结婚的？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯，现在这个结婚的成本真的是让人有点望而却步啊就包括房子。车子，然后还有一些地方高额的彩礼，对吧一场婚礼办下来。随随便便几十万就没有了对，那你这个对于很多普通家庭来说真的是一个巨大的压力。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来好像房子和彩礼就已经把很多人拦在婚姻门外了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错，那你想养孩子呢？从出生到他大学毕业，对吧那也是一笔巨款啊，然后还有就是赡养父母。工作的不稳定，各种生活成本的增加，那让很多年轻人觉得。我现在如果没有经济基础我真的不敢轻易的走进婚姻。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得这个经济的压力会让现在的年轻人在结婚这件事情上面有什么新的变化？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就现在很多人就会把婚育，当成一个非常理性的投资。对，就他要反复的去算这个投入和风险，那他觉得我如果没有准备好我是绝对不会轻易的去成家的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 所以很多人就干脆就往后拖了呗？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，那很多大学生他们本来觉得我二十八岁结婚三十岁生娃是很理想的，但是现实往往让他们把这个计划推迟两三年，甚至有些人就直接不想结了不想生了，那这个不婚不育的比例也是明显的在攀升。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得这个经济的压力会让男女在结婚这件事情上面的态度会产生什么不一样的变化？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就我觉得经济的压力会让。女生会更加的谨慎，对就是她会觉得我如果婚育了我会影响我的职业发展。然后再加上现在很多女生其实经济也独立了，那她对婚姻的期待值也会变高。那男生的话他虽然说也很有压力但是他好像。传统的这个成家的观念还是让他，更愿意去承担这个婚育的责任。所以他可能，在面对经济的困境的时候他反而容易产生焦虑甚至逃避。所以这个婚育的推迟或者说不婚育这个现象在女生当中会更突出一些。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 然后咱们来聊一聊第三部分啊就是社会环境的影响嗯，那这个我就特别想问了嗯就是现在这个。铺天盖地的信息和这个高离婚率。到底是怎么影响？现在年轻人的这个结婚意愿的，嗯。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯其实我觉得现在的这个网络。和各种影视剧吧，就是他总是在。放大婚姻生活当中的一些矛盾。哦对比如说什么家庭纠纷啊然后什么感情破裂啊这种。负面的新闻总是在刷屏嘛，那久而久之。年轻人就会觉得，婚姻好像是一个充满了风险和挑战的事情。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 所以大家就越来越谨慎了对。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后再加上就是现实当中的这个离婚率又这么高。那身边也有很多这种失败的婚姻的例子。所以大家就会，很自然的对结婚这件事情会。多了一些顾虑，也更加理性了，就不会再觉得好像我结婚就是一个。很浪漫的童话，对我更多的是看到了背后的一些压力和一些变数。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 现在不是也有很多人说吗说，好像职场的节奏太快了嗯，那你觉得这种高强度的工作氛围。具体是怎么在影响年轻人的这个婚恋状态呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 像这种九九六啊这种加班文化。就直接压缩了大家的这个社交和恋爱的时间嘛，那大家连认识。新的朋友的机会都很少了嗯那你更别提说。有时间去经营一段感情了，所以很多人就会觉得谈恋爱也好结婚也好都变成了一个奢侈品。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来工作就已经把生活都填满了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后再加上就是。竞争的压力和这个职业的不安全感又让大家对于。未来的家庭，也会变得很担忧，很多年轻人甚至会觉得。我连自己都照顾不好我怎么敢轻易的去成家？所以就会让这个结婚的意愿不断的在下降。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 现在不是也有很多人在讲吗说，这个社会变得越来越多元了嗯那你觉得这种多元的。具体都体现在哪些方面，然后这些东西是怎么在影响年轻人的婚姻选择的？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯现在不是也有很多人在讲吗说，这个社会变得越来越多元了嗯那你觉得这种多元的。具体都体现在哪些方面，然后这些东西是怎么在影响年轻人的婚姻选择的？\\nzh_female_mizaitongxue_v2_saturn_bigtts: 这倒确实是，现在好像大家的选择确实比以前丰富太多了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后再加上就是。各种媒体啊各种社交网络。也在不断的去强化这种单身的精彩呀。所以现在的年轻人就会觉得。我不是只有结婚这一条路可以走，我不结婚也可以过得很好，那我为什么要结婚呢？所以就会让大家对于结婚这件事情就没有那么执着了。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎，聊到这其实我们会发现就是。现在年轻人的这个不着急结婚其实背后有很多复杂的原因对既有个人成长的追求，也有。现实的经济和社会环境的变化，对所以我觉得。最重要的还是理解每个人按照自己的节奏去生活。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 好啦这期节目咱们就到这啦然后感谢大家的收听咱们下次再见拜拜拜拜。\"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028155641402519554, 2026229317599551489, 'emotion', '情感合成 2026-03-02', '[#用暧昧低沉、若即若离的语气，像在耳边轻声说情话] 嘘……别说话。你的呼吸……打在我耳畔。痒痒的。像羽毛轻轻划过。知道吗？每次你靠近……空气都会变甜。想再近一点吗？嗯？就一点点……让我听听……你心跳的节拍。它是不是……也和我的一样……乱了。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772384955322.mp3', 30, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028155922945175554, 2026229317599551489, 'emotion', '情感合成 2026-03-02', '[#用霸气低沉、步步压迫的语气，像王者归来俯视一切] 三年前。你们亲手把我推下深渊。今天……我回来了。\n\n看见了吗？这栋大厦。这座城市最高的地方。现在……它姓我的姓。\n\n千亿市值？呵。那只是开始。我要让你们亲眼看着——看着曾经唾弃的弃子，如何站在你们永远够不到的高度。\n\n当年那纸除名书……我还留着呢。裱在办公室最显眼的地方。每天提醒我——是谁，逼我走到了今天。\n\n现在……该轮到你们低头了。\n\n家族？荣耀？那些你们视若生命的东西……在我眼里，一文不值。我要的……是整个商业帝国的版图。而你们……连入场券都拿不到。\n\n脚步声……听见了吗？我来了。带着你们无法想象的权势……和彻骨的寒意。\n\n这场游戏……该换规则了。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772385027485.mp3', 76, 0, NULL, NULL, 0, NULL, NULL, 1);
INSERT INTO `user_creation` VALUES (2028392218787627009, 2026229317599551489, 'podcast', 'AI 双播 · 杨瀚森在能立足于NBA吗？', '杨瀚森在能立足于NBA吗？', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 525, 0, NULL, '{\"roundCount\": 38, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听，我们的播客。呃今天想跟大家聊一个最近比较火的一个话题啊，就是关于中国的新星。杨瀚森，他到底能不能在 NBA 站稳脚跟啊，这个是我们今天想要聊的话题。呃他在今年，二零二五年，登陆了开拓者。但是他在自己的首个赛季，表现并不是特别理想啊数据并不是特别理想，但是他在 G 联赛当中找回了自己的状态。那么他接下来的路要怎么去走啊，其实还是充满了挑战的。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，那就是说这个。呃，杨瀚森他到底能不能在这个顶级的舞台上面持续的打出自己的表现确实是值得我们去聊一聊的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们第一个要聊的呢就是，杨瀚森他到底有什么样的，独特的天赋和价值。就他到底有什么东西是，让他可以在 NBA 这种级别的比赛当中，成为一个独特的存在？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯首先他的身高是二米一六，嗯然后他的这种控球的能力。和传球的视野是远远超过了，同位置的球员嗯所以他经常会有一些。类似于后卫一样的这种策动进攻的能力，所以这也是为什么他会被称为。组织中锋或者是说，小约基奇，就是他这种打法其实在现在的这个。内线里面是非常吃香的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就感觉他好像是一个，内线里面的一个另类，就感觉很不一样。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对他不光是在进攻端，他的低位技术也很扎实。然后他的篮板和封盖也都是非常厉害的，他在护框的时候能够让对手的命中率下降非常多，他的防守效率也提升的非常明显。再加上他的性格也很好，他的适应能力也很强。他又有这种商业价值，所以他的综合的竞争力是非常强的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得就他现在这个，技术特点，他最适合在球队里面扮演一个什么样的角色？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是他这种，能里能外的，然后又可以持球又可以策应又可以护框的这种内线。其实是非常非常少的，嗯所以他完全可以成为一个，现代篮球里面非常吃香的这种。空间型的枢纽，对就他可以让整个球队的进攻，变得更有层次。防守也可以，提升一个档次，就他是一个非常全面的一个内线，所以他的战术价值是非常高的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得他这个人的性格，包括他适应新环境的这个能力，会不会帮助他更快的融入到球队当中？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 他性格特别好，他就是很乐观然后也很自信，他跟队友之间。沟通什么的都没有什么问题，他到了一个新的环境也不会说有什么。不适应啊之类的，就是他这种心态让他不管是在场上还是在场下都可以很快的跟大家打成一片，嗯哼对这个其实对于他。在球队当中站稳脚跟是非常非常有帮助的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们来进入第二个部分啊，就是说，呃这一节咱们就聚焦在，杨瀚森他的技术短板。或者说他在，NBA 这个赛场上，面临的一些比较棘手的挑战。你觉得他在进攻端，最让人头疼的问题是什么？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 其实他现在最明显的问题就是他的三分球，嗯，他的三分球。出手了差不多四十次吧，嗯然后就只进了五个左右。对，就命中率特别低，所以这导致就是防守球员根本就不怕他在外线，所以他们都敢。缩在篮下，所以这就让他的。突破和传球其实也都变得，没那么有威胁了。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 所以他其实在场上的空间感，就被极大的压缩了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后再加上他其实在面对。NBA 的这种快速的防守轮转的时候他的脚步还是偏慢的。所以他的终结也没有那么高效，嗯再加上他的这个。体能，嗯就是他在背靠背或者说这种高强度的比赛当中他的这个。动作会变形，失误会增多，嗯所以他的这个整体的影响力就会大大降低。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 那你觉得他在防守端，或者说他在身体条件上面，有哪些问题会影响他在 NBA 的发展？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是他的这个横向移动，和他的这个爆发力都很一般。所以他在面对，后卫的这种挡拆的时候他经常会跟不上。然后换防出去的时候也会经常失位，所以他的这个。防守的弹性是很差的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哦这确实挺难办的。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 而且他的这个体重的增加并没有给他带来更好的对抗。嗯，反而让他的这个移动更慢了，然后他在篮板球和护框上面也没有什么绝对的优势。再加上他的这个体能，嗯，他在场上一旦时间多了之后他的这个。失位啊包括他的这个犯规都会增多，所以他很难，去适应这种。现代的这种内线的打法。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得，除了他自身的能力的问题，还有什么东西在阻碍他真正的在球队里面站稳脚跟？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是他的这个打法其实还是挺，老派的，他是一个阵地战的内线。然后现在的这个球队又喜欢打快，喜欢拉开空间，嗯所以他就很难。融入到这个进攻体系当中，再加上他的这个。呃同位置的队友又更符合教练的要求，所以他的这个上场时间就被挤压的非常厉害。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 他是不是也很难获得稳定的上场机会？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错，然后再加上他的这个。失误又偏多，他的这个在发展联盟的数据其实也没有办法直接转化成他在 NBA 的这种实力。再加上他的这个语言沟通啊包括他对这个战术的理解。都不是特别的理想，所以他在场上的表现也不是特别的理想，所以他可能。如果没有什么大的改进的话未来被球队放弃的可能性还是挺大的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们来进入到第三部分啊就是今天要聊的是，杨瀚森怎么样在 NBA 找到属于自己的路，那你觉得他。短期之内最应该，专注的目标和具体的做法是什么？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯我觉得他现在就是要专注于成为一个，护框和篮板的专家。然后减少自己的，不必要的协防，把自己的精力更多的投入到。防守的选位啊以及。怎么去避免自己的犯规上面，比如说他可以多去练习一些。低位的，横向的脚步移动啊包括一些盖帽的选时机啊。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来他得非常专注于自己的本职工作啊。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错没错然后进攻端的话就是吃饼。顺下和一些简单的勾手，就不要做一些多余的动作把自己的失误控制住。把自己的身体练到，至少一百二十公斤，保证自己的对抗。多去跟教练沟通跟队友沟通。把握好每一次上场的机会，嗯争取能够把自己的上场时间稳定在。十分钟以上，对这样的话他才能够。慢慢的赢得球队的信任。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 如果说想要在接下来两三年有一个质的飞跃的话，嗯他最关键的突破口应该在哪里？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 呃首先第一个肯定是要把他的三分球命中率提升到百分之三十五以上。然后让自己成为一个真正的外线的威胁，这样的话他的这个进攻空间就会彻底打开。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 他的防守是不是也要有一个大的变化？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后就是脚步的移动，和他的这个换防的能力也要提升。让他能够跟得上这种小球的节奏，再加上他的这个篮板和他的这个策应。都练扎实了之后他就可以。真正的去竞争一个，主力轮换的位置就类似于现在很多这种全能型的中锋一样。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 就是说从长远来看的话，嗯，他要真正的在这个联盟里面成为一个不可替代的人。他最终要把自己的核心竞争力建立在什么上面？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是他必须要让自己的这个高位策应。和他的这种组织能力变成他的一个招牌，就他要变成一个。类似于那种场上的指挥官一样，就是他不管在进攻还是防守端，都能带动球队的节奏，拉开场上的空间，然后让大家的进攻变得更流畅。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就是他要不断的丰富自己的技能包。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错没错对他要不断的去丰富自己的技能包。然后减少自己的失误，提高自己的效率，要去。像那些顶级的内线一样，自律，不断的去调整自己的比赛方式。还要利用好发展联盟这个平台，去反复的磨炼自己。把自己的身体状态和心理状态都调到一个最佳，这样的话他才能够。在这个联盟里面，站稳脚跟，成为一个真正的，有影响力的球员。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 行今天咱们聊了这么多关于杨瀚森他的天赋，他的短板。包括他未来可能的发展的方向，其实我觉得，他的NBA之旅虽然充满了挑战。但是，机会也同样巨大，对吧咱们就期待着他能够一步一步的去突破自己。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 好啦这期播客就到这里啦然后感谢大家的收听咱们下期再见拜拜。\\n: \"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028397718325440513, 2026229317599551489, 'podcast', 'AI 双播 · AI ', 'AI ', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 7, 0, NULL, '{\"roundCount\": 1, \"transcript\": \": \"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028398119430926338, 2026229317599551489, 'podcast', 'AI 双播 · How will AI change our life in', 'How will AI change our life in 2026? Let us discuss the future together.', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 283, 0, NULL, '{\"roundCount\": 23, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听，我们的播客。今天我们要聊的话题是，AI 会在二零二六年如何改变我们的生活。啊我们会从这个技术和产业的变革讲起啊然后来聊一聊。AI 会在我们的日常生活当中，带来哪些变化啊最后我们再来聊一聊。当 AI 给我们带来这些便利的同时，我们会遇到哪些挑战？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，嗯，感觉每一个都很有意思啊那我们就开始吧。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们先聊第一个话题啊就是技术和产业的变革。那首先第一个我想问的就是，二零二六年 AI 在技术上面会有哪些新的突破？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 呃我觉得首先就是，二零二六年的 AI 会从，单纯的这种文本的交互。转向，更加自主的去解决问题。就会有这种智能体嘛就他可以自己去规划然后自己去执行一些比较复杂的任务。就比如说他可以直接帮你自动完成一个工作流。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来好像就离我们特别近就好像马上就可以用了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后包括现在的这种大模型也会。更加注重，推理的效率和一些新的算法。包括也会开始去理解一些图片语音甚至三维空间。也会有这种端侧的 AI 和具身智能开始大规模的进入市场。就这些都会让 AI 变得更加通用，更加高效。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎那你觉得就是 AI 会在，二零二六年会在各个行业当中，掀起哪些具体的变革呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 比如说在制造业里面。会有这种 AI 驱动的智能体去实时的调度生产资源。然后会让，几乎百分之四十的。生产排程都变得自动化，也会推动中国的这个智造。加快它的步伐。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来已经不只是简单的自动化了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对，你想金融和医疗。他们已经开始用 AI 去做一些风险管理和一些疾病的辅助诊断。然后内容创作几乎全部都要靠 AIGC 来提效。办公软件也都嵌入了这种智能体让你的日常工作都变成一种自动化。就各行业的格局都会被彻底的重塑。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎那你觉得就是到了二零二六年，AI 会在，产业的格局和，社会的治理上面带来哪些新的变化呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是我觉得 AI 会让，企业的竞争方式。发生变化就会从，你拼规模。到你拼，个性化和生态的协同。就会有很多企业他们会把 AI 工厂，和标准化的平台作为他们的一个核心的竞争力。就会让这个产业的格局也发生变化。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎那这么说的话，是不是？企业的管理方式和，监管方式也要跟着变？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，那就是企业里面会出现一些新的职位。比如说像数据官或者是 AI 伦理官这种。然后全球的这个 AI 治理的规则也会。逐渐的成型啊就是包括像欧盟的这个 AI 法案也会开始。正式的实施啊等等，那包括中国也会在这个数据要素和算法的创新上面持续的发力。那整个行业也会朝着，绿色和可持续去转型。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 我们来进入第二个部分，就是 AI 对我们社会和生活的影响，我们就来看看，AI 到底会在哪些方面，让我们的日常生活在二零二六年发生变化？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是你会发现，你的手机，你的电脑。你的智能手表，几乎你所有的设备里面都已经有了 AI 的助手。那这些 AI 的助手呢？他们能够理解你的习惯你的情绪。然后他们会帮你自动的整理你的日程帮你筛选你最关心的信息。甚至他们会直接帮你做出一些决策比如说帮你自动的回复一些消息。帮你自动的调整你的设备的设置等等。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就感觉好像我们的生活真的是会被 AI 全方位的接管。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错而且就是。像这种，新一代的这种 AI 的个人助手他是可以通过语音通过图像通过。多种方式跟你进行交流的。然后他会把你的，健康管理啊。你的娱乐啊你的购物啊你的出行啊全部都连接起来。再加上这个 AI 驱动的这种智能家居。让你的家里的设备也可以自动的协同。那你就会发现其实你的生活的每一个细节都会变得更加的高效，更加的舒适，也更加的贴心。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得就是 AI 会在，二零二六年在，内容创作和娱乐方式上面带来哪些，新鲜的变化？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是因为 AI 的多模态的能力已经非常的成熟了，所以你可以一键生成。高清的视频，而且是带有复杂的特效的视频。然后包括生成音乐，生成 3D 的场景。所以你会发现其实各种内容的门槛都被大大降低了，每个人都可以成为一个创作者。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 就感觉好像拍电影，做游戏都变得非常的平民化了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错没错而且就是。不光是这种，专业的影视公司在使用 AI 来进行。这种自动化的生产，其实。短视频和直播平台也在使用 AI 来进行这种实时的互动和内容的推荐。然后包括这种 AI 的数字人可以作为你的这种直播的主持。或者是说，虚拟的偶像。直接跟粉丝进行互动，所以整个内容和娱乐行业都被彻底的。焕发了新的活力。\"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028401264747884545, 2026229317599551489, 'podcast', 'AI 双播 · AI in 2026 learning. Let\'s tal', 'AI in 2026 learning. Let\'s talk about the future of education.', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 38, 0, NULL, '{\"roundCount\": 4, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听，我们的播客。然后今天呢我们要聊的呢是这个 AI 在二零二六年的学习，啊也就是 AI 跟教育的未来。OK，我们会先跟大家聊一聊呢 AI 会在哪些地方，帮助我们去改变教育。对吧，AI 会在哪些场景里面？发挥作用，也会跟大家聊一聊呢 AI 可能会带来的一些风险和挑战。最后呢我们也会跟大家看一看呢未来 AI 和教育，会往哪些方向去发展。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 听起来今天的话题很有意思啊那我们就开始吧。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们先来看第一个大的主题啊就是 AI 如何来助力教育的变革，那我们先来看看 AI 到底是。在学生的学习这个层面，有哪些具体的应用，或者说 AI 到底给学生的学习带来了哪些，实实在在的好处。\"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028423724201410562, 2026229317599551489, 'studio_podcast', 'AI and codingTest Podcast', '咪仔：哈喽大家好欢迎收听，我们的播客。呃今天我们要聊的话题是 AI 和编程，啊我们会从。AI 编程的原理啊优势啊，使用的场景啊讲起。然后再给大家介绍一些，比较好用的工具和一些使用的小技巧。最后呢我们也会给大家聊一聊我们对于 AI 编程未来的一些看法。\n\n大一先生：嗯，那我们就直接开始今天的内容吧。\n\n咪仔：我们先来聊第一个话题啊，就是 AI 编程的核心剖析，我们先来聊一聊它的原理，就是到底 AI 编程是怎么工作的？\n\n大一先生：AI 编程其实背后是有一个非常大的语言模型，这个语言模型就是通过大量的代码和文本去训练出来的。所以它能够理解你说的话，甚至是一些很模糊的需求，它都可以去理解。然后它会用一些像 Transformer 这种神经网络架构，去处理这些自然语言的输入。把它变成一个，非常精确的这种语法树。\n\n咪仔：所以它其实是可以直接把我们的想法翻译成代码？\n\n大一先生：对，而且它不不仅仅是这样哦，它还会用一些像这种。检索增强生成啊还有这种动态的知识注入啊就它会去。参考你的项目里面的一些专属的风格和规范。然后去生成一个非常贴合你这个项目的一个代码，而且它整个这个流程是可以自动帮你做一些语法检查和逻辑优化的。所以它的这个准确率和效率都是非常高的。\n\n', 'zh_female_mizaitongxue_v2_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts1/podcast_1772448862900.mp3', 30, 0, NULL, NULL, 1, 2028423724268519426, NULL, 0);
INSERT INTO `user_creation` VALUES (2028437618626142209, 2026229317599551489, 'tts', '配音 2026-03-02', 'A：最近发现个现象啊，我身边好多年轻朋友都开始讨论存钱了。你说现在消费选择这么多，外卖奶茶、网红旅行、新款手机……诱惑无处不在，为啥年轻人反而更在意存款数字了呢？\n\nB：嘿，这问题有意思！其实吧，我觉得年轻人存钱不是单纯为了“省”，更像是一种“生活选择权”的储备。我有个95后同事小敏，去年开始每月雷打不动存2000，你猜她怎么说？\n\nA：嗯？为了买房首付？\n\nB：不不，她说——“这笔钱是我的‘说不基金’。”上个月公司让她接个明显超负荷的项目，她直接拿出存款流水说：“我现在有底气拒绝。”你看，存钱存的其实是选择自由。\n\nA：有道理！', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772452179392.mp3', 67, 969120, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028437651601760257, 2026229317599551489, 'tts', '配音 2026-03-02', '但很多年轻人会说：“工资就这么点，存也存不下多少呀？”\n\nB：对对对，这是常见误区！存钱不是“等有钱再存”，而是“有多少先存多少”。我大学刚工作时月薪5000，硬是每月先转500到单独账户——就像支付一笔“未来账单”。三年后这笔“小钱”加上理财收益，居然够我报了个职业培训课，工资直接涨了30%。\n\nA：哇这个例子好实在！不过现在社交媒体老鼓吹“及时行乐”，不会觉得存钱很土吗？\n\nB：（笑）恰恰相反！现在年轻人流行“聪明存”——比如用自动扣款工具、定投指数基金、甚至搞“消费挑战赛”。我加了个存钱群，大家每周晒存款进度比晒包包还起劲。有个姑娘更绝，', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772452192535.mp3', 68, 1004640, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028437688801042433, 2026229317599551489, 'tts', '配音 2026-03-02', '她把每次忍住没买的奶茶钱存进“奶茶基金”，年底用这笔钱去了趟向往已久的敦煌。\n\nA：听着居然有点热血……所以存钱不是压抑欲望，而是把零散欲望整合成大梦想？\n\nB：没错！就像拼乐高——每天存几块积木，不知不觉就能拼出个城堡。最妙的是，这个过程中你还会养成“财务触觉”，点外卖前会想“这顿够我存三天”，购物前会自然比较“真实价值”。这种掌控感，比消费快感持久多了。\n\nA：说到掌控感，是不是也跟这几年的大环境有关？\n\nB：哎，这点很关键。疫情、行业波动让年轻人深刻体会到——现金流就是安全感。我表弟原是个月光族，有次急诊要押金8000，他居然得四处借钱。', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772452200142.mp3', 68, 1008960, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028437702952624129, 2026229317599551489, 'tts', '配音 2026-03-02', '从那以后他变了，现在常说：“存款余额就是我心理防弹衣的厚度。”\n\nA：最后给想开始存钱的年轻人一句建议？\n\nB：记住三个字——“开始存”。哪怕每天10块，先让“存”这个动作进入生活节奏。就像学游泳，总得先下水扑腾两下嘛！', 'BV700_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1772452207726.mp3', 27, 391200, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028447666882486274, 2026229317599551489, 'studio_podcast', 'AI and codingTest Podcast', '咪仔：哈喽大家好欢迎收听，我们的播客。呃今天我们要聊的话题是 AI 和编程，啊我们会从。AI 编程的原理啊优势啊，使用的场景啊讲起。然后再给大家介绍一些，比较好用的工具和一些使用的小技巧。最后呢我们也会给大家聊一聊我们对于 AI 编程未来的一些看法。\n\n大一先生：嗯，那我们就直接开始今天的内容吧。\n\n咪仔：我们先来聊第一个话题啊，就是 AI 编程的核心剖析，我们先来聊一聊它的原理，就是到底 AI 编程是怎么工作的？\n\n大一先生：AI 编程其实背后是有一个非常大的语言模型，这个语言模型就是通过大量的代码和文本去训练出来的。所以它能够理解你说的话，甚至是一些很模糊的需求，它都可以去理解。然后它会用一些像 Transformer 这种神经网络架构，去处理这些自然语言的输入。把它变成一个，非常精确的这种语法树。\n\n咪仔：所以它其实是可以直接把我们的想法翻译成代码？\n\n大一先生：对，而且它不不仅仅是这样哦，它还会用一些像这种。检索增强生成啊还有这种动态的知识注入啊就它会去。参考你的项目里面的一些专属的风格和规范。然后去生成一个非常贴合你这个项目的一个代码，而且它整个这个流程是可以自动帮你做一些语法检查和逻辑优化的。所以它的这个准确率和效率都是非常高的。\n\nA：最近发现个现象啊，我身边好多年轻朋友都开始讨论存钱了。你说现在消费选择这么多，外卖奶茶、网红旅行、新款手机……诱惑无处不在，为啥年轻人反而更在意存款数字了呢？\n\nB：嘿，这问题有意思！其实吧，我觉得年轻人存钱不是单纯为了“省”，更像是一种“生活选择权”的储备。我有个95后同事小敏，去年开始每月雷打不动存2000，你猜她怎么说？\n\nA：嗯？为了买房首付？\n\nB：不不，她说——“这笔钱是我的‘说不基金’。”上个月公司让她接个明显超负荷的项目，她直接拿出存款流水说：“我现在有底气拒绝。”你看，存钱存的其实是选择自由。\n\nA：有道理！但很多年轻人会说：“工资就这么点，存也存不下多少呀？”\n\nB：对对对，这是常见误区！存钱不是“等有钱再存”，而是“有多少先存多少”。我大学刚工作时月薪5000，硬是每月先转500到单独账户——就像支付一笔“未来账单”。三年后这笔“小钱”加上理财收益，居然够我报了个职业培训课，工资直接涨了30%。\n\nA：哇这个例子好实在！不过现在社交媒体老鼓吹“及时行乐”，不会觉得存钱很土吗？\n\nB：（笑）恰恰相反！现在年轻人流行“聪明存”——比如用自动扣款工具、定投指数基金、甚至搞“消费挑战赛”。我加了个存钱群，大家每周晒存款进度比晒包包还起劲。有个姑娘更绝，她把每次忍住没买的奶茶钱存进“奶茶基金”，年底用这笔钱去了趟向往已久的敦煌。\n\nA：听着居然有点热血……所以存钱不是压抑欲望，而是把零散欲望整合成大梦想？\n\nB：没错！就像拼乐高——每天存几块积木，不知不觉就能拼出个城堡。最妙的是，这个过程中你还会养成“财务触觉”，点外卖前会想“这顿够我存三天”，购物前会自然比较“真实价值”。这种掌控感，比消费快感持久多了。\n\nA：说到掌控感，是不是也跟这几年的大环境有关？\n\nB：哎，这点很关键。疫情、行业波动让年轻人深刻体会到——现金流就是安全感。我表弟原是个月光族，有次急诊要押金8000，他居然得四处借钱。从那以后他变了，现在常说：“存款余额就是我心理防弹衣的厚度。”\n\nA：最后给想开始存钱的年轻人一句建议？\n\nB：记住三个字——“开始存”。哪怕每天10块，先让“存”这个动作进入生活节奏。就像学游泳，总得先下水扑腾两下嘛！\n\n', 'zh_female_mizaitongxue_v2_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts1/podcast_1772448862900.mp3', 60, 0, NULL, NULL, 1, 2028447666987343873, NULL, 0);
INSERT INTO `user_creation` VALUES (2028464357469335554, 2026229317599551489, 'emotion', '情感合成 2026-03-02', '[#用语气上扬、带不屑和冷笑、语速稍快、偶尔哼声的语气] 哼……就这？也配在我面前显摆？你那些小把戏……我八百年前就看腻了。啧……真不知道哪来的自信。你以为我会在意？呵……别做梦了。赶紧收起你那副可怜样吧……看着就烦。走了！别跟过来……除非你求我。嗯？怎么不说话了？', 'zh_female_santongyongns_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772458557596.mp3', 33, 0, NULL, NULL, 0, NULL, NULL, 0);
