INSERT INTO `user_creation` VALUES (2028836402338226178, 2026263446605094913, 'emotion', '情感合成 2026-03-03', '[#专业电视台新闻女主播，声音端庄大气，字正腔圆，语速平稳，播报重要新闻] 各位观众，注意。今日头条很意外。日常琐事，竟成焦点？嗯……深思。热茶，驻足。看似微不足道。——却折射出真人性。请观看。这不仅是播报。——更是生活注脚。你懂了吗？', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772547260182.mp3', 29, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028836649676333058, 2026263446605094913, 'emotion', '情感合成 2026-03-03', '嘘……别动。让我靠近一点……再近一点。听见了吗？你的心跳。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772547325363.mp3', 7, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028866949856911362, 2026263446605094913, 'podcast', 'AI 双播 · AI  Learning', 'AI  Learning', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 506, 0, NULL, '{\"roundCount\": 39, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听，我们的播客，然后今天我们要聊的呢是关于 AI 学习的。啊这个我们会先给大家说一说啊最近国家平台上面新上线的一些 AI 的学习资源。呢再给大家聊一聊啊 AI 是如何正在改变我们的学习的理念，学习的内容。包括学习的场景，最后呢我们也会跟大家聊一聊啊在教育当中应用 AI 会遇到哪些挑战？以及我们如何去规范的使用它。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 好，那我们就开始吧。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们先来说第一个部分就是 AI 学习资源的新的拓展。首先第一个问题啊就是说国家智慧教育平台在 AI 课程这方面到底有哪些新的上线的内容？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就今年啊平台新出了这个 AI 学习的这个专栏，里面已经有八十五门课了，是来自于六十四所高校的。然后这些课程呢又分成了。这个基础，进阶和应用，三个不同的等级啊哈就从这个入门到实战都有。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来内容确实很丰富。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对不光是课程啊，他还有这个虚拟仿真的实验，还有企业的案例。然后包括还有这个人工智能与社会这样的一个，专门的课程啊，就是帮助大家去。理解这个技术背后的一些影响啊等等。就他是一个全方面的去帮助你构建一个 AI 的知识体系。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 这些各种各样的 AI 课程，他们是分别为哪些人准备的？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 比如说这个，腾讯的这个实战课他就是专门为高校的师生设计的。然后他就是让你去学习这个大模型的应用开发。还有一些课程是为了，高职的学生。就他是提升你的这个人工智能的技能，去帮助你就业的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 那中小学生和成人也有适合的内容吗？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对，小学生和中学生他们有那种故事化的，AI 的通识课。然后还有那种 AI 加 X 的这种创新课程。成人的话平台也有很多进阶的课程，包括一些面向教师和开发者的这种专业提升的资源。就是大家都可以找到自己的，学习的路径。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 你觉得国家智慧教育平台的这些 AI 课程，到底带来了哪些新的变化？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就我觉得最厉害的是他把。各种不同的课程类型都集合在了一起啊哈就大家无论是想系统的学习。还是说我就想碎片时间学一点啊哈都可以。然后包括他是强调这种理论和动手一起结合的。他也有这种智能的工具和这种个性化的服务。去帮助你提升你的效率。他也有这种非常权威的，内容非常前沿的一些课程。让你可以去跟随着这个行业的脚步一起进步。他甚至还有这种多语种的。和这种国际的交流的专区。所以他也推动了这个中国的 AI 教育走向世界。就他其实是，为我们每个人打开了一个通往未来的一个新的大门吧。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 我们要聊的第二个部分呢就是 AI 如何去重塑学习的体验。那第一个问题呢就是说，AI 到底是怎么去推动学习的理念发生转变的？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯我觉得就是，AI 其实是让。学习从一个被动的接受。变成了一个主动的探索，对就比如说它会根据每个人的兴趣和基础。然后来自动的调整你的学习内容。它也会用这种对话呀，和这种情境的模拟让你去。像科学家一样的去思考去解决问题。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就比传统的课堂要有趣多了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对而且它会。实时的记录你的学习的过程。然后分析你的优势和短板。帮你去定制属于你自己的学习路线。甚至连你的老师都会变成你的。同伴，就是大家一起去探索这个未知的领域。就是他其实是把。这个重心从知识的记忆转到了能力和素养的培养上面。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎那就是说，AI 到底是怎么？让学习的内容和形式变得更加丰富和灵活了呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是它会。通过智能的算法，然后去分析每个人的学习的进度。和他的兴趣点。自动的去推送。最适合你的知识点和练习。甚至连题目和案例都是。动态生成的就每个人看到的都是不一样的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就比传统的课件要生动很多。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对，而且它会把。文本图片音频视频都融合在一起。然后你可以通过这种虚拟的实验去操作去探索。它也可以自动的帮你整理你的知识结构。推荐你最适合的跨学科的内容。就他会让学习变得更加高效而且有针对性。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 就是人工智能到底是怎么？改变了我们学习的场景和方式。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就是现在有了 AI 的话你可以在智能教室里面。或者说在虚拟实验室里面。甚至在家里就通过这种远程的。和协作的平台，跟你的同伴一起去探索。就学习不再局限于一种教室。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 感觉互动性也强了不少。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错没错，然后还有就是 AI 可以做你的个性化的导师。做你的自动的测评。做这种情感陪伴。就是他会大大减轻老师的负担。让老师可以更专注于去引导学生去创新去解决问题。就他会让整个教育更高效更公平更能够去培养学生的核心素养。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们来聊第三个部分啊就是 AI 教育应用的新的挑战，那这个里面其实最让人关心的就是。AI 技术在课堂上面在校园里面，到底会遇到哪些风险？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯其实我觉得第一个就是。因为 AI 的系统他会收集很多关于学生的学习的细节。那这个数据如果被泄露了的话，是会直接威胁到学生的隐私的。然后包括他的这个算法的不透明性也会导致。一些偏见和不公平的现象，那这个可能会让教育资源的分配，更加的不均衡。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哦，原来不只是技术问题还有伦理的挑战。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后还有就是。呃有些学生他可能会太依赖这个 AI 来帮他解决问题。那他就会逐渐的丧失一些批判思维和创新能力。那包括还有就是大家的信息环境也会变得很单一。大家会形成信息茧房，包括就是。呃人与人之间的那种直接的交流也会被削弱，包括这个。法律和监管的一些跟不上，也会让这个责任变得很模糊。会让这个教育的价值的导向也会变得很模糊。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 对那就是说，我们要怎么做才能够？有效的去防范这些，AI 教育应用里面的风险呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 首先第一就是要完善，相关的法律和伦理的审查。然后明确这个数据的主权和个人信息保护的这样的一个规则。包括对于 AI 教育产品要建立一个动态的监管的机制。这样的话才能够从制度上把这个安全的底线守住。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来是需要多层面的去协同配合。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对，然后技术上就是要做到这个数据的全生命周期的防护。推广可解释的 AI 和这个内容的审核机制。同时把这个 AI 的伦理的素养。融入到这个教师的培训和学生的课程里面。去提倡这个，人和技术要形成一个良好的协作的氛围。对这个就是多方一起来，共同的去推动这个规范的落地。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 就是说，呃，具体到实际的落地当中，AI 在教育领域的规范使用会有哪些？切实可行的做法呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 呃比如我们国家其实已经出台了，人工智能教育的这个促进法。然后也有一些相关的政策，那这些政策其实就明确了哪些场景是可以用 AI 的，哪些场景是 AI 不可以替代老师的，那这些都是一些底线的原则。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来是有很具体的管理办法。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错，然后现在很多高校和平台都有。AI 的伦理委员会，专门来审查。这个 AI 教育的产品，包括对它的这个生成的内容。进行一些检测，包括。呃推动一些优质的 AI 教育资源，也会去帮扶一些。偏远地区的学校，让他们也能够有。安全的靠谱的 AI 工具可以使用，同时也会培训老师和学生。让他们能够去分辨，AI 的风险和规范。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎，今天聊了这么多其实我们看到的是。AI 正在给学习，带来一场全方位的变革。对他让学习变得更加多元，更加个性，也更加开放。对，那当然它带来的这些挑战也让我们去重新思考教育的价值和边界。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 好了那么这期节目咱们就到这里啦然后感谢大家的收听咱们下次再聊拜拜拜拜。\"}', 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2028868140045197313, 2026263446605094913, 'studio_podcast', 'AI  Learning', '咪仔：哈喽大家好欢迎收听，我们的播客，然后今天我们要聊的呢是关于 AI 学习的。啊这个我们会先给大家说一说啊最近国家平台上面新上线的一些 AI 的学习资源。呢再给大家聊一聊啊 AI 是如何正在改变我们的学习的理念，学习的内容。包括学习的场景，最后呢我们也会跟大家聊一聊啊在教育当中应用 AI 会遇到哪些挑战？以及我们如何去规范的使用它。\n\n大一先生：好，那我们就开始吧。\n\n咪仔：咱们先来说第一个部分就是 AI 学习资源的新的拓展。首先第一个问题啊就是说国家智慧教育平台在 AI 课程这方面到底有哪些新的上线的内容？\n\n大一先生：就今年啊平台新出了这个 AI 学习的这个专栏，里面已经有八十五门课了，是来自于六十四所高校的。然后这些课程呢又分成了。这个基础，进阶和应用，三个不同的等级啊哈就从这个入门到实战都有。\n\n咪仔：听起来内容确实很丰富。\n\n大一先生：对不光是课程啊，他还有这个虚拟仿真的实验，还有企业的案例。然后包括还有这个人工智能与社会这样的一个，专门的课程啊，就是帮助大家去。理解这个技术背后的一些影响啊等等。就他是一个全方面的去帮助你构建一个 AI 的知识体系。\n\n咪仔：这些各种各样的 AI 课程，他们是分别为哪些人准备的？\n\n大一先生：比如说这个，腾讯的这个实战课他就是专门为高校的师生设计的。然后他就是让你去学习这个大模型的应用开发。还有一些课程是为了，高职的学生。就他是提升你的这个人工智能的技能，去帮助你就业的。\n\n咪仔：那中小学生和成人也有适合的内容吗？\n\n大一先生：对，小学生和中学生他们有那种故事化的，AI 的通识课。然后还有那种 AI 加 X 的这种创新课程。成人的话平台也有很多进阶的课程，包括一些面向教师和开发者的这种专业提升的资源。就是大家都可以找到自己的，学习的路径。\n\n咪仔：你觉得国家智慧教育平台的这些 AI 课程，到底带来了哪些新的变化？\n\n大一先生：就我觉得最厉害的是他把。各种不同的课程类型都集合在了一起啊哈就大家无论是想系统的学习。还是说我就想碎片时间学一点啊哈都可以。然后包括他是强调这种理论和动手一起结合的。他也有这种智能的工具和这种个性化的服务。去帮助你提升你的效率。他也有这种非常权威的，内容非常前沿的一些课程。让你可以去跟随着这个行业的脚步一起进步。他甚至还有这种多语种的。和这种国际的交流的专区。所以他也推动了这个中国的 AI 教育走向世界。就他其实是，为我们每个人打开了一个通往未来的一个新的大门吧。\n\n咪仔：我们要聊的第二个部分呢就是 AI 如何去重塑学习的体验。那第一个问题呢就是说，AI 到底是怎么去推动学习的理念发生转变的？\n\n大一先生：嗯我觉得就是，AI 其实是让。学习从一个被动的接受。变成了一个主动的探索，对就比如说它会根据每个人的兴趣和基础。然后来自动的调整你的学习内容。它也会用这种对话呀，和这种情境的模拟让你去。像科学家一样的去思考去解决问题。\n\n咪仔：听起来就比传统的课堂要有趣多了。\n\n大一先生：对而且它会。实时的记录你的学习的过程。然后分析你的优势和短板。帮你去定制属于你自己的学习路线。甚至连你的老师都会变成你的。同伴，就是大家一起去探索这个未知的领域。就是他其实是把。这个重心从知识的记忆转到了能力和素养的培养上面。\n\n咪仔：哎那就是说，AI 到底是怎么？让学习的内容和形式变得更加丰富和灵活了呢？\n\n大一先生：就是它会。通过智能的算法，然后去分析每个人的学习的进度。和他的兴趣点。自动的去推送。最适合你的知识点和练习。甚至连题目和案例都是。动态生成的就每个人看到的都是不一样的。\n\n咪仔：听起来就比传统的课件要生动很多。\n\n大一先生：对，而且它会把。文本图片音频视频都融合在一起。然后你可以通过这种虚拟的实验去操作去探索。它也可以自动的帮你整理你的知识结构。推荐你最适合的跨学科的内容。就他会让学习变得更加高效而且有针对性。\n\n咪仔：就是人工智能到底是怎么？改变了我们学习的场景和方式。\n\n大一先生：就是现在有了 AI 的话你可以在智能教室里面。或者说在虚拟实验室里面。甚至在家里就通过这种远程的。和协作的平台，跟你的同伴一起去探索。就学习不再局限于一种教室。\n\n咪仔：感觉互动性也强了不少。\n\n大一先生：对没错没错，然后还有就是 AI 可以做你的个性化的导师。做你的自动的测评。做这种情感陪伴。就是他会大大减轻老师的负担。让老师可以更专注于去引导学生去创新去解决问题。就他会让整个教育更高效更公平更能够去培养学生的核心素养。\n\n咪仔：咱们来聊第三个部分啊就是 AI 教育应用的新的挑战，那这个里面其实最让人关心的就是。AI 技术在课堂上面在校园里面，到底会遇到哪些风险？\n\n大一先生：嗯其实我觉得第一个就是。因为 AI 的系统他会收集很多关于学生的学习的细节。那这个数据如果被泄露了的话，是会直接威胁', 'zh_female_mizaitongxue_v2_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts1/podcast_1772554812745.mp3', 30, 0, NULL, NULL, 1, 2028868140082946050, NULL, 0);
INSERT INTO `user_creation` VALUES (2028872378351640578, 2026229317599551489, 'studio_podcast', 'AI and codingTest Podcast', '咪仔：哈喽大家好欢迎收听，我们的播客。呃今天我们要聊的话题是 AI 和编程，啊我们会从。AI 编程的原理啊优势啊，使用的场景啊讲起。然后再给大家介绍一些，比较好用的工具和一些使用的小技巧。最后呢我们也会给大家聊一聊我们对于 AI 编程未来的一些看法。\n\n大一先生：嗯，那我们就直接开始今天的内容吧。\n\n咪仔：我们先来聊第一个话题啊，就是 AI 编程的核心剖析，我们先来聊一聊它的原理，就是到底 AI 编程是怎么工作的？\n\n大一先生：AI 编程其实背后是有一个非常大的语言模型，这个语言模型就是通过大量的代码和文本去训练出来的。所以它能够理解你说的话，甚至是一些很模糊的需求，它都可以去理解。然后它会用一些像 Transformer 这种神经网络架构，去处理这些自然语言的输入。把它变成一个，非常精确的这种语法树。\n\n咪仔：所以它其实是可以直接把我们的想法翻译成代码？\n\n大一先生：对，而且它不不仅仅是这样哦，它还会用一些像这种。检索增强生成啊还有这种动态的知识注入啊就它会去。参考你的项目里面的一些专属的风格和规范。然后去生成一个非常贴合你这个项目的一个代码，而且它整个这个流程是可以自动帮你做一些语法检查和逻辑优化的。所以它的这个准确率和效率都是非常高的。\n\nA：最近发现个现象啊，我身边好多年轻朋友都开始讨论存钱了。你说现在消费选择这么多，外卖奶茶、网红旅行、新款手机……诱惑无处不在，为啥年轻人反而更在意存款数字了呢？\n\nB：嘿，这问题有意思！其实吧，我觉得年轻人存钱不是单纯为了“省”，更像是一种“生活选择权”的储备。我有个95后同事小敏，去年开始每月雷打不动存2000，你猜她怎么说？\n\nA：嗯？为了买房首付？\n\nB：不不，她说——“这笔钱是我的‘说不基金’。”上个月公司让她接个明显超负荷的项目，她直接拿出存款流水说：“我现在有底气拒绝。”你看，存钱存的其实是选择自由。\n\nA：有道理！但很多年轻人会说：“工资就这么点，存也存不下多少呀？”\n\nB：对对对，这是常见误区！存钱不是“等有钱再存”，而是“有多少先存多少”。我大学刚工作时月薪5000，硬是每月先转500到单独账户——就像支付一笔“未来账单”。三年后这笔“小钱”加上理财收益，居然够我报了个职业培训课，工资直接涨了30%。\n\nA：哇这个例子好实在！不过现在社交媒体老鼓吹“及时行乐”，不会觉得存钱很土吗？\n\nB：（笑）恰恰相反！现在年轻人流行“聪明存”——比如用自动扣款工具、定投指数基金、甚至搞“消费挑战赛”。我加了个存钱群，大家每周晒存款进度比晒包包还起劲。有个姑娘更绝，她把每次忍住没买的奶茶钱存进“奶茶基金”，年底用这笔钱去了趟向往已久的敦煌。\n\nA：听着居然有点热血……所以存钱不是压抑欲望，而是把零散欲望整合成大梦想？\n\nB：没错！就像拼乐高——每天存几块积木，不知不觉就能拼出个城堡。最妙的是，这个过程中你还会养成“财务触觉”，点外卖前会想“这顿够我存三天”，购物前会自然比较“真实价值”。这种掌控感，比消费快感持久多了。\n\nA：说到掌控感，是不是也跟这几年的大环境有关？\n\nB：哎，这点很关键。疫情、行业波动让年轻人深刻体会到——现金流就是安全感。我表弟原是个月光族，有次急诊要押金8000，他居然得四处借钱。从那以后他变了，现在常说：“存款余额就是我心理防弹衣的厚度。”\n\nA：最后给想开始存钱的年轻人一句建议？\n\nB：记住三个字——“开始存”。哪怕每天10块，先让“存”这个动作进入生活节奏。就像学游泳，总得先下水扑腾两下嘛！\n\n', 'zh_female_mizaitongxue_v2_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts1/podcast_1772448862900.mp3', 60, 0, NULL, NULL, 1, 2028872378406166530, NULL, 0);
INSERT INTO `user_creation` VALUES (2029489613164294146, 2026229317599551489, 'emotion', '情感合成 2026-03-05', '[#用阴森恐怖、压低声线、若有若无的语气，像在讲鬼故事] 你听……那扇门，又响了。不是风，是手指，在刮。我数过，三下，停一下，再三下。昨晚，它停了在我床边。呼吸，喷在我后颈。我不敢回头。你知道为什么吗？因为镜子里的我……正在笑。', 'zh_female_mizai_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772702998533.mp3', 25, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029838085935640578, 2026229317599551489, 'emotion', '情感合成 2026-03-06', '嘘……别动。让我靠近一点……再近一点。听见了吗？你的心跳。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772786081316.mp3', 6, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029985982438297602, 2026229317599551489, 'workshop', 'AI声音工坊作品', '亲爱的，生日快乐。遇见你之前，我以为日子只是重复的晨昏；遇见你之后，连空气都变成草莓味的。你笑起来眼睛弯成月牙的样子，是我每天最想收藏的风景。新的一岁，愿你继续做那个追蝴蝶也追梦想的女孩，而我，会永远在你转身就能看见的地方。谢谢你，让我的平凡人生，变成了童话。我爱你，不止今天。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772821342325.mp3', 31, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029987659874586625, 2026229317599551489, 'workshop', 'AI声音工坊作品', '风穿过无人的站台，带走半张车票。有人在此告别，有人恰好抵达——而钟声从不追问，下一站是归途还是远行。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772821742357.mp3', 11, 0, NULL, NULL, 0, NULL, NULL, 0);
