INSERT INTO `user_creation` VALUES (2029988449821413377, 2026229317599551489, 'workshop', 'AI声音工坊作品', '晨光溜进窗台，咖啡香漫过书页。猫咪伸个懒腰，日子就这样轻轻摇晃着，温柔又明亮。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772821935926.mp3', 9, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029991271388434434, 2026229317599551489, 'workshop', 'AI声音工坊作品', '姐妹们！这瓶精华简直是熬夜肌的救命稻草！一抹化水的质地，上脸瞬间吸收，隔天醒来脸蛋像剥壳鸡蛋般透亮软糯。三重玻尿酸层层渗透，干纹细纹统统隐形。用了半瓶，素颜都能自信出门！现在入手还送旅行套装，闭眼冲就对了！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772822603514.mp3', 23, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029991603606671362, 2026229317599551489, 'workshop', 'AI声音工坊作品', '当指尖触碰屏幕的瞬间，0.3毫米的曲面玻璃下，一亿像素正在苏醒。这不是冰冷的参数堆砌，而是光与算法的共舞——夜视如昼，瞬息永恒。科技，终于学会了温柔。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772822687893.mp3', 17, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029993270158843905, 2026229317599551489, 'workshop', 'AI声音工坊作品', '雨夜。老宅。一封没有署名的信。\n\n\"你终于来了。\"\n\n烛火摇曳，墙上的人影多了一道。是谁？门锁早已锈死，窗户封死三十年。\n\n我转身——\n\n身后空无一人。\n\n可那封信，墨迹未干。\n\n\"下一个，轮到你了。\"\n\n滴答。滴答。\n\n是雨，还是血？\n\n（停顿）\n\n你听……阁楼上有脚步声。\n\n三步。停。三步。停。\n\n它正数着台阶，\n\n下来找你。', 'zh_female_mizai_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772823079866.mp3', 37, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2029995292065132545, 2026229317599551489, 'workshop', 'AI声音工坊作品', '【开场白】\n朋友们，今天评测一款运动耳机——它号称\"狂甩不掉\"，我试了下，耳机确实没掉，我的假发片飞了。\n\n【佩戴体验】\n入耳式的设计，像给耳道办了张VIP会员卡，专属定制，拒绝共享。跑步半小时，耳朵没喊疼，这点比我前任强。\n\n【音质实测】\n低音沉，中音稳，高音……我唱上去了它没破音，职业素养极高。\n\n【防水测试】\n官方说IPX7，我直接浇了杯美式。耳机没事，我清醒了——凌晨三点不该喝咖啡。\n\n【', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772823561968.mp3', 59, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030119734162354178, 2026229317599551489, 'workshop', 'AI声音工坊作品', '各位观众晚上好，今天是公元2023年X月X日，农历X月X日。下面播送一则快讯——据‘全球颜值观测站’数据显示，寿星【XXX】同志今日帅气/美丽值较昨日环比上涨1%，创历史新高。专家分析，此现象与‘生日光环’效应及‘收礼手软’定律密切相关……另据本台记者暗中观察，该寿星许愿时疑似默念‘不想上班’，本台将持续追踪报道。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772853231546.mp3', 35, 0, NULL, NULL, 0, NULL, NULL, 0);
