INSERT INTO `user_creation` VALUES (2030288111279280130, 2026229317599551489, 'emotion', '情感合成 2026-03-07', '妈？什么……霍氏集团太子爷？在找未婚妻？照片怎么……怎么是他？！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772893380988.mp3', 7, 0, NULL, NULL, 0, NULL, NULL, 0);
