INSERT INTO `user_creation` VALUES (2030288389323886594, 2026229317599551489, 'studio_drama', '霍总装穷追妻被女主打脸', '林知夏：放门口就行，不用敲门。\n\n霍沉舟：林小姐，这箱是生鲜，需要当面签收。\n\n林知夏：你们快递员现在话这么多？上次那个直接扔门口就走了。\n\n霍沉舟：……公司有规定。\n\n林知夏：什么公司？这制服怎么没见过。\n\n霍沉舟：新成立的，叫……速达。\n\n林知夏：速达？没听过。你们老板谁啊，这么不会起名。\n\n霍沉舟：……可能确实不太会。\n\n林知夏：算了，笔给我。等等，你这手表——\n\n霍沉舟：假的，仿品。\n\n林知夏：仿百达翡丽？仿得挺真，送快递戴这个？\n\n霍沉舟：个人爱好。\n\n林知夏：行吧，爱好挺贵。对了，你们公司还招人吗？我表弟失业。\n\n霍沉舟：目前……不招。\n\n林知夏：也是，看这单量，估计快倒闭了。\n\n霍沉舟：林小姐，您每周网购金额……挺高。\n\n林知夏：关你什么事？\n\n霍沉舟：建议少买杂牌护肤品，脸会过敏。\n\n林知夏：你——你一个送快递的管我用什么？\n\n霍沉舟：只是建议。\n\n林知夏：建议你别干快递了，去当皮肤科医生。\n\n霍沉舟：考虑过。\n\n林知夏：神经。签完了，快走。\n\n霍沉舟：明天还有您的件，是珠宝。\n\n林知夏：又是你送？\n\n霍沉舟：这片区域我负责。\n\n林知夏：你们公司就你一个员工吧？\n\n霍沉舟：……目前是的。\n\n林知夏：难怪。那珠宝保价吗？丢了赔得起吗？\n\n霍沉舟：丢了，我把公司赔给您。\n\n林知夏：吹牛。你那破公司值几个钱。\n\n霍沉舟：值……大概，三千七百个亿。\n\n林知夏：什么？\n\n霍沉舟：没什么。明天见，林小姐。\n\n林知夏：等等！你刚才说——\n\n[关门声]\n\n林知夏：喂！霍——\n\n[手机铃声]\n\n林知夏：妈？什么……霍氏集团太子爷？在找未婚妻？照片怎么……怎么是他？！\n\n[物品掉落声]\n\n林知夏：那个死送快递的——！\n\n', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772893394294.mp3', 159, 0, NULL, NULL, 1, 2030288389353246722, NULL, 0);
INSERT INTO `user_creation` VALUES (2030297412920152065, 2026229317599551489, 'emotion', '情感合成 2026-03-07', '深夜好……我是你的DJ。\n\n此刻的你，或许正蜷缩在黑暗里。手机屏幕的光，是房间里唯一醒着的东西。\n\n我想告诉你——\n\n种子破土之前，要先在泥土里碎裂。蝴蝶展翅之前，要在茧中溶解成液态的自己。那些看似毁灭的时刻……其实是变形正在发生。\n\n\"哪有什么胜利可言，挺住就是一切。\"\n\n但我想改一改——挺住不是硬撑，是允许自己脆弱。是承认疼，承认怕，承认今晚的眼泪是真的……然后，把脸埋进枕头里，睡过去。\n\n低谷从不是惩罚。它是大地在托住你，让你重新确认——根，还在。\n\n明天不会突然变好。但你会。\n\n因为跌倒教会你的，从来不是如何不再坠落……而是落地时，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772895593166.mp3', 60, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030297426132209665, 2026229317599551489, 'emotion', '情感合成 2026-03-07', '怎样用手撑住自己，怎样在尘埃里，找到下一颗种子。\n\n睡吧。谷底的风，正练习托举你的翅膀。\n\n晚安。我在。✨', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772895601830.mp3', 11, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030300445993410561, 2026229317599551489, 'emotion', '情感合成 2026-03-07', '夜深了。\n\n你还没睡。\n\n窗帘漏进一点银白，像谁悄悄铺了层薄霜。风很轻，轻得像是怕惊扰什么。\n\n我知道你今天很累。\n\n不是那种大喊大叫的累，是藏在骨头缝里，说不出口的累。像手机电量只剩百分之三，还在硬撑。\n\n其实你已经很努力了。\n\n那些没做完的事，明天再说。那些没回的消息，让它们等一等。世界不会因为你今晚早睡就塌掉，真的。\n\n现在，把被子往上拉一拉。\n\n想象自己是只蜷起来的猫，毛茸茸的，暖烘烘的，什么都不用想。呼吸慢一点，再慢一点……\n\n没关系的。\n\n今晚不做大人了。\n\n做个被月光盖着的小孩，就好。', 'zh_female_santongyongns_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772896315689.mp3', 56, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030307930737287169, 2026229317599551489, 'emotion', '情感合成 2026-03-07', '夜深了。\n\n你还没睡。\n\n窗帘漏进一点银白，像谁悄悄铺了层薄霜。风很轻，轻得只敢碰一碰窗纱。\n\n我知道你今天很累。\n\n那些没说出口的话，没做完的事，还在脑子里转。像洗衣机最后一分钟的脱水，轰隆隆响。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772898101051.mp3', 22, 0, NULL, NULL, 0, NULL, NULL, 0);
