INSERT INTO `user_creation` VALUES (2030307958130286594, 2026229317599551489, 'emotion', '情感合成 2026-03-07', '月光会替你守夜。\n\n睡吧。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772898112810.mp3', 2, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030308058084745218, 2026229317599551489, 'studio_radio', '给深夜失眠的你，一段温暖...', '夜深了。\n\n你还没睡。\n\n窗帘漏进一点银白，像谁悄悄铺了层薄霜。风很轻，轻得只敢碰一碰窗纱。\n\n我知道你今天很累。\n\n那些没说出口的话，没做完的事，还在脑子里转。像洗衣机最后一分钟的脱水，轰隆隆响。\n\n停了吧。\n\n你已经很努力了。真的。\n\n此刻什么都不用想。被子裹紧一点，想象自己是只蜷着的猫。毛茸茸的，暖烘烘的，谁也不用讨好。\n\n明天的事，交给明天的太阳。\n\n现在，只负责呼吸。\n\n吸气……呼气……\n\n月光会替你守夜。\n\n睡吧。\n\n', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772898119127.mp3', 47, 0, NULL, NULL, 1, 2030308058122493953, NULL, 0);
INSERT INTO `user_creation` VALUES (2030313047184154625, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '如果我们想象太阳在某一瞬间凭空消失，地球并不会立刻陷入黑暗。光需要时间传播，所以我们还能看见太阳八分二十秒——那只是一场延迟播放的幽灵影像。\n\n真正的变化从引力开始。爱因斯坦告诉我们，引力不是瞬间作用的力，而是以光速传播的时空涟漪。所以地球会继续沿轨道飞行八分二十秒，像一头蒙眼奔跑的野兽，浑然不知牵引它的绳索已经断裂。然后——轨道切线方向飞离，成为星际流浪者。\n\n但问题其实很难。太阳消失的瞬间，核心停止核聚变，但光球层储存的能量仍在向外涌流。这意味着温度不会骤降，而是像逐渐冷却的炭火，缓慢黯淡。大气层是更好的缓冲垫，地表降温需要数周甚至数月，而非几小时。', 'zh_female_xiaohe_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772899320661.mp3', 62, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030313084861587458, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '更微妙的是角动量守恒。地球自转轴的稳定性依赖太阳引力矩的微调，失去太阳后，地轴摆动将变得混沌。四季概念消失，极地可能突然转向赤道——想象一下，冰川在热带崩塌，雨林在极寒中冻结。\n\n目前主流观点认为，地球生命将在数月内因光合作用中断而崩溃。但也有科学家指出，深海热泉生态系统或许能撑过数千年，成为新世界的诺亚方舟。\n\n这个领域接下来最激动人心的问题是：如果我们真能制造人工恒星，需要多小的质量才能维持地球宜居？答案或许藏在黑洞吸积盘的辐射效率里——用毁灭性的引力，换取一线生机。', 'zh_female_xiaohe_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772899335100.mp3', 52, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030314198239584258, 2026229317599551489, 'studio_lecture', '如果太阳突然消失，地球会...', '如果我们想象太阳在某一瞬间凭空消失，地球并不会立刻陷入黑暗。光需要时间传播，所以我们还能看见太阳八分二十秒——那只是一场延迟播放的幽灵影像。\n\n真正的变化从引力开始。爱因斯坦告诉我们，引力不是瞬间作用的力，而是以光速传播的时空涟漪。所以地球会继续沿轨道飞行八分二十秒，像一头蒙眼奔跑的野兽，浑然不知牵引它的绳索已经断裂。然后——轨道切线方向飞离，成为星际流浪者。\n\n但问题其实很难。太阳消失的瞬间，核心停止核聚变，但光球层储存的能量仍在向外涌流。这意味着温度不会骤降，而是像逐渐冷却的炭火，缓慢黯淡。大气层是更好的缓冲垫，地表降温需要数周甚至数月，而非几小时。\n\n更微妙的是角动量守恒。地球自转轴的稳定性依赖太阳引力矩的微调，失去太阳后，地轴摆动将变得混沌。四季概念消失，极地可能突然转向赤道——想象一下，冰川在热带崩塌，雨林在极寒中冻结。\n\n目前主流观点认为，地球生命将在数月内因光合作用中断而崩溃。但也有科学家指出，深海热泉生态系统或许能撑过数千年，成为新世界的诺亚方舟。\n\n这个领域接下来最激动人心的问题是：如果我们真能制造人工恒星，需要多小的质量才能维持地球宜居？答案或许藏在黑洞吸积盘的辐射效率里——用毁灭性的引力，换取一线生机。\n\n', 'zh_female_xiaohe_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772899342049.mp3', 115, 0, NULL, NULL, 1, 2030314198327664642, NULL, 0);
INSERT INTO `user_creation` VALUES (2030318104738811906, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '我前两天发现个好东西。洗完脸不绷不干，毛孔像在呼吸。\n\n以前用的洗面奶，洗完脸涩得像搓盘子，赶紧拍水乳救急。这支完全不会，泡沫绵得像奶油，上脸软乎乎的，冲完水摸一把，嫩滑但不假滑。\n\n氨基酸的，pH跟皮肤差不多。我敏感肌的朋友 borrowed 去用，第二天追着我要链接。她说终于找到洗完不泛红的了。\n\n早上赶时间，三十秒搞定，不耽误化妆。晚上卸妆后二次清洁，油脂灰尘全带走，脸干净到会发光。\n\n一百出头这么大一支，我用了两个月才瘪下去一半。真该把家里那瓶皂基的扔了，脸又不是碗，不用洗那么涩。\n\n信我，今晚就试试。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772900526450.mp3', 57, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030318605693898754, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '去年公司年会，我穿了件厚棉袄去。结果会议室暖气开到二十八度，我像个粽子一样坐在那，汗顺着后背往下淌。旁边同事倒好，外套一脱，里面是件薄毛衣，轻盈得像刚下班。\n\n中场休息我追出去问，她指了指椅背。一件叠成豆腐块的轻薄羽绒服，还没我的化妆包大。她说早上零下五度穿着骑车来的，进公司塞包里，下班再拿出来。\n\n我当时不信。直到今年深秋，我在地铁口被冷风刮透，冲进优衣库买了件同款。早上通勤穿着挡风，到办公室脱了放抽屉，午休下楼买咖啡再套上。周末带娃去公园，塞妈咪包里备用，孩子玩水弄湿外套，这件立刻顶上。\n\n最绝的是上个月出差。北京飞深圳，机舱里热得要命，', 'zh_female_xiaohe_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772900646163.mp3', 60, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030318627156152321, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '别人的厚羽绒服堆在腿上占地方，我的叠好塞前座口袋。落地深圳二十度，直接塞双肩包侧袋，轻到忘记它的存在。\n\n现在我的衣柜里，这件使用率超过了所有大衣。不是它多好看，是它让我不再为穿什么发愁。\n\n你要问哪买的，就搜轻薄羽绒，选能叠成小块的。剩下的，穿了就知道。', 'zh_female_xiaohe_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772900656492.mp3', 28, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030318699935715329, 2026229317599551489, 'studio_ad', '一件轻薄羽绒服从办公室到...', '去年公司年会，我穿了件厚棉袄去。结果会议室暖气开到二十八度，我像个粽子一样坐在那，汗顺着后背往下淌。旁边同事倒好，外套一脱，里面是件薄毛衣，轻盈得像刚下班。\n\n中场休息我追出去问，她指了指椅背。一件叠成豆腐块的轻薄羽绒服，还没我的化妆包大。她说早上零下五度穿着骑车来的，进公司塞包里，下班再拿出来。\n\n我当时不信。直到今年深秋，我在地铁口被冷风刮透，冲进优衣库买了件同款。早上通勤穿着挡风，到办公室脱了放抽屉，午休下楼买咖啡再套上。周末带娃去公园，塞妈咪包里备用，孩子玩水弄湿外套，这件立刻顶上。\n\n最绝的是上个月出差。北京飞深圳，机舱里热得要命，别人的厚羽绒服堆在腿上占地方，我的叠好塞前座口袋。落地深圳二十度，直接塞双肩包侧袋，轻到忘记它的存在。\n\n现在我的衣柜里，这件使用率超过了所有大衣。不是它多好看，是它让我不再为穿什么发愁。\n\n你要问哪买的，就搜轻薄羽绒，选能叠成小块的。剩下的，穿了就知道。\n\n', 'zh_female_xiaohe_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772900662616.mp3', 89, 0, NULL, NULL, 1, 2030318700002824194, NULL, 0);
INSERT INTO `user_creation` VALUES (2030321783508324353, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '从前有一只小兔子，名字叫蹦蹦。\n\n蹦蹦住在蒲公英山坡，屋前有个小园子。\n\n园子里种满胡萝卜，红的橙的，胖嘟嘟。\n\n每天早上，蹦蹦蹦蹦跳，去看她的宝贝。\n\n\"这是我的胡萝卜，\"蹦蹦说，\"谁也别想碰。\"\n\n小松鼠咕噜噜跑过来，尾巴蓬蓬像把小伞。\n\n\"蹦蹦，你的胡萝卜真香，能尝一口吗？\"\n\n蹦蹦捂住耳朵，摇摇头，\"不行不行，这是我的。\"\n\n小松鼠垂下尾巴，沙沙沙，走远了。\n\n小鼹鼠扑通扑通钻出来，小眼睛亮晶晶。\n\n\"蹦蹦，我挖到了土豆，换你的胡萝卜好吗？\"\n\n蹦蹦转过身，背对着他，\"不换不换，你走吧。\"\n\n小鼹鼠叹口气，咕叽咕叽，钻回地底。\n\n天黑了，', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901403634.mp3', 61, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030321987104034817, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '蹦蹦抱着胡萝卜，却觉得好孤单。\n\n月光照进窗子，胡萝卜堆成小山，冷冷的。\n\n第二天，蹦蹦又去园子，发现叶子黄了。\n\n一只胡萝卜烂了，软趴趴，发出怪味道。\n\n蹦蹦哭了，鼻子一抽一抽，\"怎么办呀。\"\n\n小松鼠回来了，抱着松果，\"我们一起想办法。\"\n\n小鼹鼠也钻出来，\"我知道怎么救活它们。\"\n\n三个小伙伴浇水，施肥，太阳底下忙乎乎。\n\n蹦蹦看看小松鼠，看看小鼹鼠，心里扑通扑通。\n\n她拔出一根最红的胡萝卜，\"你们尝尝吧。\"\n\n小松鼠咬一口，咔嚓咔嚓，\"好甜呀！\"\n\n小鼹鼠嚼一嚼，\"这是我吃过最好的胡萝卜。\"\n\n蹦蹦也咬一口，咦，怎么比以前更甜呢？', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901457296.mp3', 60, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030322058658861058, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '小松鼠把松果分给她，小鼹鼠拿出土豆。\n\n三个朋友坐在园子里，你一口，我一口。\n\n风轻轻吹，蒲公英飞起来，像小伞飘呀飘。\n\n蹦蹦明白了，原来分享不是失去，是得到更多。\n\n现在她的园子更热闹了，每天都有朋友来。\n\n胡萝卜还是蹦蹦的，但快乐是大家的。\n\n你想不想也有一个这样的园子呢？', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901474496.mp3', 30, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323046627168257, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '小熊布布今天很生气，气得耳朵都在发抖。\n\n早上，他搭了整整一上午的积木城堡，轰隆——被跑过的梅花鹿撞倒了。布布的脸涨得通红，像熟透的苹果，他握紧拳头，好想好想大喊大叫。\n\n\"坏梅花鹿！我讨厌你！', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901704896.mp3', 21, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323087672627201, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '\"布布的声音把树上的小鸟都吓飞了。\n\n熊妈妈走过来，没有说\"别生气\"，而是蹲下来，轻轻抱住布布发抖的肩膀。\n\n\"布布，你的肚子里是不是有一团火在烧？咕噜咕噜，越烧越旺？\"\n\n布布愣了一下，点点头。', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901719882.mp3', 21, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323129863131138, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '真的呢，胸口又热又闷，像塞了个小太阳。\n\n\"那是\'生气\'来找你玩了，\"妈妈说，\"它想让你保护重要的东西。可是呀，生气是个小迷糊，它不知道大喊大叫会让朋友难过。\"\n\n布布低下头。他想起梅花鹿吓得发白的脸，', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901730049.mp3', 22, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323174591188993, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '还有自己撞翻的水杯，水正滴答滴答流进地毯里。\n\n\"那……那怎么办？\"布布的声音闷闷的。\n\n妈妈拉着他的手走到窗边：\"我们先让生气飞走一点点。来——深深吸，肚子鼓起来，慢慢吐，像吹蜡烛——呼——\"', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901740771.mp3', 21, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323212801298433, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '布布跟着做了三次。奇怪，胸口的小太阳好像变暗了一点。\n\n\"现在，\"妈妈递给他一颗小石子，\"把让你生气的事告诉它，然后用力扔进小河里。\"\n\n布布走到河边，对着石子说：\"我生气是因为城堡倒了，', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901749799.mp3', 20, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323249732145154, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '我搭了很久很久！\"扑通！石子跳进水里，溅起亮晶晶的水花。\n\n\"还生气吗？\"妈妈问。\n\n\"还有一点……但是不像火山要爆发了。\"\n\n\"那我们去告诉梅花鹿，\"妈妈说，\"不是去吵架，', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901758595.mp3', 19, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323292715372545, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '是去说——\'你撞倒了我的城堡，我很生气，请你帮我一起搭，好吗？\'\"\n\n布布的心跳得扑通扑通。他找到正在摘果子的梅花鹿，耳朵烫烫的，但还是把话说完了。\n\n梅花鹿的眼睛睁得圆圆的：\"对不起！我跑太快了，', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901768910.mp3', 22, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323334054432770, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '没看到你。我帮你搭，我还会搭塔楼呢！\"\n\n两个小伙伴蹲在草地上，你一块我一块，新城堡比旧的还高，还有梅花鹿教的尖尖塔顶。\n\n傍晚，布布趴在妈妈膝头：\"妈妈，生气还会再来吗？\"\n\n\"会呀，', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901778754.mp3', 20, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323346096279554, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '\"妈妈梳着他软绵绵的毛，\"但是布布', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772901781674.mp3', 3, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030323943352586242, 2026229317599551489, 'studio_picture_book', '小熊今天很生气，妈妈教他...', '小熊布布今天很生气，气得耳朵都在发抖。\n\n早上，他搭了整整一上午的积木城堡，轰隆——被跑过的梅花鹿撞倒了。布布的脸涨得通红，像熟透的苹果，他握紧拳头，好想好想大喊大叫。\n\n\"坏梅花鹿！我讨厌你！\"布布的声音把树上的小鸟都吓飞了。\n\n熊妈妈走过来，没有说\"别生气\"，而是蹲下来，轻轻抱住布布发抖的肩膀。\n\n\"布布，你的肚子里是不是有一团火在烧？咕噜咕噜，越烧越旺？\"\n\n布布愣了一下，点点头。真的呢，胸口又热又闷，像塞了个小太阳。\n\n\"那是\'生气\'来找你玩了，\"妈妈说，\"它想让你保护重要的东西。可是呀，生气是个小迷糊，它不知道大喊大叫会让朋友难过。\"\n\n布布低下头。他想起梅花鹿吓得发白的脸，还有自己撞翻的水杯，水正滴答滴答流进地毯里。\n\n\"那……那怎么办？\"布布的声音闷闷的。\n\n妈妈拉着他的手走到窗边：\"我们先让生气飞走一点点。来——深深吸，肚子鼓起来，慢慢吐，像吹蜡烛——呼——\"\n\n布布跟着做了三次。奇怪，胸口的小太阳好像变暗了一点。\n\n\"现在，\"妈妈递给他一颗小石子，\"把让你生气的事告诉它，然后用力扔进小河里。\"\n\n布布走到河边，对着石子说：\"我生气是因为城堡倒了，我搭了很久很久！\"扑通！石子跳进水里，溅起亮晶晶的水花。\n\n\"还生气吗？\"妈妈问。\n\n布布想了想：\"还有一点……但是不像火山要爆发了。\"\n\n\"那我们去告诉梅花鹿，\"妈妈说，\"不是去吵架，是去说——\'你撞倒了我的城堡，我很生气，请你帮我一起搭，好吗？\'\"\n\n布布的心跳得扑通扑通。他找到正在摘果子的梅花鹿，耳朵烫烫的，但还是把话说完了。\n\n梅花鹿的眼睛睁得圆圆的：\"对不起！我跑太快了，没看到你。我帮你搭，我还会搭塔楼呢！\"\n\n两个小伙伴蹲在草地上，你一块我一块，新城堡比旧的还高，还有梅花鹿教的尖尖塔顶。\n\n傍晚，布布趴在妈妈膝头：\"妈妈，生气还会再来吗？\"\n\n\"会呀，\"妈妈梳着他软绵绵的毛，\"但是布布\n\n', 'zh_female_xueayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772901789193.mp3', 175, 0, NULL, NULL, 1, 2030323943411306497, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332245876785154, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '国产新一代AI芯片今日正式发布。单芯片算力达到每秒千万亿次运算，较前代产品提升整整十倍。这一突破标志着我国在人工智能核心硬件领域迈出关键一步。\n\n据悉，该芯片采用全新架构设计，能耗比同步优化百分之四十。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903897993.mp3', 22, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332261903220738, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '这意味着同等算力下，电费成本降至原有水平的六成。对于数据中心运营商而言，这直接转化为每年数亿元的运营开支削减。\n\n算力提升十倍，相当于把一座大型图书馆的信息检索时间，从数小时压缩到几分钟。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903907118.mp3', 20, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332277174681601, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '在医疗影像分析场景，肺结节筛查速度可从分钟级进入秒级。自动驾驶系统处理复杂路况的响应延迟，将缩短至人类反应时间的十分之一。\n\n行业数据显示，我国智能算力需求年均增速超过百分之五十。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903910984.mp3', 20, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332292907515905, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '此前高端AI芯片进口依赖度居高不下，供应链风险持续存在。此次量产落地，将有效缓解这一瓶颈。相关产业链人士透露，首批订单已覆盖互联网、金融、制造三大领域。\n\n技术突破的背后，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903914629.mp3', 19, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332310531981314, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '是制程工艺与封装技术的双重跨越。芯片晶体管密度提升至五纳米级别，三维堆叠层数增加两倍。这些参数意味着，指甲盖大小的硅片上，集成了超过千亿个晶体管。\n\n值得关注的是，新芯片同步开放了开发者工具链。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903918945.mp3', 21, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332326399033346, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '中小型企业调用AI算力的门槛，从千万级投入降至百万级。这或将加速AI技术在实体经济的渗透速度。\n\n分析人士指出，算力成本每下降一个数量级，就会催生新的应用场景。十年前云计算如此，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903922620.mp3', 19, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332335936880642, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '今日AI芯片亦遵循这一规律。当算力不再稀缺，真正的创新才刚刚开始。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772903925007.mp3', 7, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030332730566361089, 2026229317599551489, 'studio_news', '最新AI芯片突破：算力提...', '国产新一代AI芯片今日正式发布。单芯片算力达到每秒千万亿次运算，较前代产品提升整整十倍。这一突破标志着我国在人工智能核心硬件领域迈出关键一步。\n\n据悉，该芯片采用全新架构设计，能耗比同步优化百分之四十。这意味着同等算力下，电费成本降至原有水平的六成。对于数据中心运营商而言，这直接转化为每年数亿元的运营开支削减。\n\n算力提升十倍，相当于把一座大型图书馆的信息检索时间，从数小时压缩到几分钟。在医疗影像分析场景，肺结节筛查速度可从分钟级进入秒级。自动驾驶系统处理复杂路况的响应延迟，将缩短至人类反应时间的十分之一。\n\n行业数据显示，我国智能算力需求年均增速超过百分之五十。此前高端AI芯片进口依赖度居高不下，供应链风险持续存在。此次量产落地，将有效缓解这一瓶颈。相关产业链人士透露，首批订单已覆盖互联网、金融、制造三大领域。\n\n技术突破的背后，是制程工艺与封装技术的双重跨越。芯片晶体管密度提升至五纳米级别，三维堆叠层数增加两倍。这些参数意味着，指甲盖大小的硅片上，集成了超过千亿个晶体管。\n\n值得关注的是，新芯片同步开放了开发者工具链。中小型企业调用AI算力的门槛，从千万级投入降至百万级。这或将加速AI技术在实体经济的渗透速度。\n\n分析人士指出，算力成本每下降一个数量级，就会催生新的应用场景。十年前云计算如此，今日AI芯片亦遵循这一规律。当算力不再稀缺，真正的创新才刚刚开始。\n\n', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772903932925.mp3', 131, 0, NULL, NULL, 1, 2030332730637664258, NULL, 0);
INSERT INTO `user_creation` VALUES (2030336273000022017, 2026229317599551489, 'workshop', 'AI声音工坊作品', '城市的灯火一盏盏暗下去，只剩下你还醒着吗？我是今晚陪你的人。\n\n此刻窗外或许有风，或许有雨，或许什么都没有——就像心里那个空着的角落，不必急着填满。你知道吗？深夜的孤独不是惩罚，是生活悄悄给你的留白，让你终于能听见自己的声音。\n\n今天过得好吗？不好也没关系。那些没说出口的委屈、没来得及消化的情绪，都放在这儿吧。这间小小的直播间，是深夜里一艘不灭的船，载着你，慢慢靠岸。\n\n睡吧，或者再坐一会儿。我会', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772904858294.mp3', 54, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030501763055894530, 2026229317599551489, 'workshop', 'AI声音工坊作品', '城市的灯火一盏盏暗下去，只剩下你的耳机还亮着微光。我是今晚守夜的人。\n\n此刻的你，或许刚结束加班，或许正望着天花板发呆，或许只是需要一些声音，证明这个世界还没睡。没关系，这里永远有一盏灯为你留着。\n\n你知道吗？深夜最温柔的地方，是它允许我们卸下所有标签。你不是谁的员工、谁的父母、谁的孩子——你只是你自己，一个需要被倾听的灵魂。\n\n窗外的风轻轻晃着树影，像老朋友在点头。那些白天说不出口的话，就让它留', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772944312605.mp3', 52, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528019919028226, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '苏小姐，这是城西新开的梨园，头牌小生会唱十八摸。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950578413.mp3', 5, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528030434148354, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '……沈姑娘，你可知我是太子未婚妻？', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950581854.mp3', 3, 0, NULL, NULL, 0, NULL, NULL, 0);
