INSERT INTO `user_creation` VALUES (2030528116069253122, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '我看过命簿。你聪慧隐忍，他嫌你心机深沉。你贤良淑德，他骂你乏味无趣。横竖都是死，不如先快活。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950601637.mp3', 10, 0, NULL, NULL, 0, NULL, NULL, 0);
