INSERT INTO `user_creation` VALUES (2030528176064577537, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '我在作死啊。按剧情我该嫉妒你、陷害你、然后被乱棍打死。可我偏要对你好，好到全京城都骂我疯了。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950616543.mp3', 10, 0, NULL, NULL, 0, NULL, NULL, 0);
