INSERT INTO `user_creation` VALUES (2030528225829994498, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '你在赌？', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950628428.mp3', 1, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528239956410369, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '我在掀桌。这破剧情不是爱虐女主吗，我偏要把水搅浑。你活着，我才能死得其所。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950631362.mp3', 8, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528249733332993, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '……那梨园头牌，当真会十八摸？', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950634143.mp3', 3, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528258696560642, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '假的，只会唱牡丹亭。但太子不知道。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950636270.mp3', 3, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528275649937409, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '沈知意，你很有意思。', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950638560.mp3', 2, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528284642525186, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '别爱上我，我是炮灰，命短。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950642281.mp3', 2, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528304187981825, 2026229317599551489, 'emotion', '情感合成 2026-03-08', '巧了，我也是。不如比比谁命更硬？', 'saturn_zh_male_shuanglangshaonian_tob', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772950646663.mp3', 3, 0, NULL, NULL, 0, NULL, NULL, 0);
INSERT INTO `user_creation` VALUES (2030528580076716034, 2026229317599551489, 'studio_drama', '霍总装穷追妻被女主打脸', '[纸张翻动声]\n\n沈知意：苏小姐，这是城西新开的梨园，头牌小生会唱十八摸。\n\n苏晚晴：……沈姑娘，你可知我是太子未婚妻？\n\n沈知意：知道啊，所以送你这个。太子不如戏子，至少戏子卖艺不卖身。\n\n苏晚晴：你疯了？我若告诉太子——\n\n沈知意：去告啊，就说沈家嫡女给你塞了男倌馆的名帖。你看太子信谁。\n\n[茶盏轻磕声]\n\n苏晚晴：你到底想要什么？\n\n沈知意：想要你活着。原书里你嫁太子，三年后被做成人彘。\n\n苏晚晴：原书？\n\n沈知意：我看过命簿。你聪慧隐忍，他嫌你心机深沉。你贤良淑德，他骂你乏味无趣。横竖都是死，不如先快活。\n\n苏晚晴：荒谬……\n\n沈知意：更荒谬的在后头。下个月秋猎，太子会\"偶遇\"你庶妹，你猜谁设计的？\n\n苏晚晴：……我庶妹？\n\n沈知意：错，是太子自己。他需要一个废你的理由，你庶妹只是道具。\n\n[风声穿堂]\n\n苏晚晴：你为何要帮我？\n\n沈知意：我在作死啊。按剧情我该嫉妒你、陷害你、然后被乱棍打死。可我偏要对你好，好到全京城都骂我疯了。\n\n苏晚晴：这算什么作死？\n\n沈知意：等太子发现他的准太子妃天天收我送的男妆图册——\n\n苏晚晴：他会杀你。\n\n沈知意：他会疑心你。一个被\"教坏\"的太子妃，和一个\"疯癫\"的沈家女，谁更该死？\n\n苏晚晴：你在赌？\n\n沈知意：我在掀桌。这破剧情不是爱虐女主吗，我偏要把水搅浑。你活着，我才能死得其所。\n\n苏晚晴：……那梨园头牌，当真会十八摸？\n\n沈知意：假的，只会唱牡丹亭。但太子不知道。\n\n[低笑声]\n\n苏晚晴：沈知意，你很有意思。\n\n沈知意：别爱上我，我是炮灰，命短。\n\n苏晚晴：巧了，我也是。不如比比谁命更硬？\n\n[更鼓声]\n\n', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772950666960.mp3', 152, 0, NULL, NULL, 1, 2030528580076716035, NULL, 0);
INSERT INTO `user_creation` VALUES (2030693653818662913, 2026229317599551489, 'workshop', '工坊 AI 合成', '愿你的生日被温柔以待——烛光摇曳处，心愿轻轻落进蛋糕的甜香里。新的一岁，愿你眼里有光，心中有爱，所行皆坦途，所遇皆温暖。生日快乐，这世间独一无二的你。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1772990064175.mp3', 17, 0, NULL, NULL, 0, NULL, '2026-03-09 01:14:30', 0);
INSERT INTO `user_creation` VALUES (2030696559754203138, 2026229317599551489, 'studio_novel', '高智商死亡游戏博弈', 'ICU的玻璃窗结着一层薄霜。\n\n陆沉把额头抵上去，凉得刺骨。里面那个瘦成一把骨头的女孩是他妹妹，十七岁，先天性心脏病，等一颗永远等不到的供体。\n\n账单在口袋里折成四折，数字烫得他掌心发疼。\n\n\"陆先生？\"\n\n护士递来一个黑色信封。烫金火漆印是希腊字母Ω，拆开只有一行字：\n\n【十亿。七夜。一人。】\n\n【奥林匹斯恭候。】\n\n底下附着一串数字：2024071903。\n\n陆沉瞳孔骤缩。这是妹妹的病历编号，连科室代码都一模一样。\n\n---\n\n环形密室没有门。\n\n十个人站在十等分的金属平台上，头顶是蜂巢状的监控阵列。陆沉数完心跳，第三十七秒，机械女声切开空气：\n\n\"囚徒迷宫，限时一小时。\"\n\n\"两两组队，解开中央密码锁。每队仅一人晋级。\"\n\n\"组队失败，双双淘汰。\"\n\n平台开始移动。陆沉对面是个戴金丝眼镜的中年男人，袖口绣着某投行的LOGO。两人之间的地面裂开，升起一道透明幕墙——只挡视线，不隔音。\n\n\"合作吧。\"男人先开口，声音透过幕墙有些失真，\"我金融数学出身，你——\"\n\n\"陆沉。以前做数论的。\"\n\n男人眼睛亮了一下，像闻到血腥的鲨鱼。陆沉知道这种眼神。三年前他的论文被指控造假，审查委员会里全是这种眼神。\n\n\"数论好，素数分解、椭圆曲线，密码学基础。\"男人凑近幕墙，\"这样，你负责计算，我负责验证，晋级名额——\"\n\n\"怎么分？\"\n\n\"……什么？\"\n\n陆沉笑了。这是三天来他第一次牵动面部肌肉，僵硬得像在撕扯伤疤。\n\n\"规则说每队仅一人晋级。\"他一字一顿，\"你刚才，在回避这个问题。\"\n\n男人脸色变了。\n\n幕墙降下。两人之间只剩三米距离，中央悬浮着一块全息键盘，输入界面是黎曼ζ函数的非平凡零点分布图。\n\n\"限时五十五分钟。\"机械声提醒。\n\n男人扑向键盘。陆沉没动。\n\n他在看监控阵列的反光。十个平台，五组\"队友\"，每一组都在微笑、握手、拍肩——表演着一种荒诞的亲密。左边那对甚至在讨论出去后怎么分奖金。\n\n太完美了。完美得像设计好的剧本。\n\n\"你在干什么！\"男人回头吼他，\"零点计算需要并行——\"\n\n\"零点计算不需要两个人。\"陆沉终于走向键盘，\"黎曼猜想至今未证，但这道题用的是已知前一百亿个零点的近似值。单人足够。\"\n\n\"那你为什么——\"\n\n\"我在等。\"\n\n\"等什么？\"\n\n陆沉按下第一个键。全息界面泛起涟漪，他输入的不是数字，而是一段指令代码。\n\n\"等你露出破绽。\"\n\n屏幕炸裂成无数碎片，重组为全新的界面——【管理员模式】。男人的表情凝固了，他冲向键盘，却被陆沉侧身撞开。\n\n\"规则有漏洞。\"陆沉的声音很轻，像在讲解一道习题，\"它说\'解开密码锁\'，没说必须输入正确答案。\"\n\n他敲下回车键。\n\n【系统覆盖。强制晋级。】\n\n男人僵在原地。机械声再次响起，这次带着某种愉悦的变调：\n\n\"检测到规则利用。陆沉，晋级。\"\n\n\"搭档王振，淘汰。\"\n\n地板裂开。不是升降台，是垂直的深渊。四条机械臂从黑暗中伸出，扣住男人的四肢，拖入暗门。他的尖叫被金属闸门切成碎片。\n\n陆沉站在原地，听着那声音越来越远，最后变成管道里的空洞回响。\n\n不是离开。是处理。\n\n---\n\n出口是一条纯白走廊。\n\n陆沉走了十七步，左侧墙壁变成整面屏幕。十个分屏显示着其他密室的实时画面：有人在搏斗，有人在哭泣，有人在最后一刻被队友推下平台。\n\n主屏幕突然切换。\n\n一张脸占据整个画面。六十岁左右，银白鬓角梳得一丝不苟，胸前的徽章是某国际数学联盟的终身荣誉标志。\n\n周牧野。\n\n三年前那场听证会的首席审查委员。就是他，在镜头前说\"陆沉的论文存在系统性造假，建议撤销学位并终身禁入学术界\"。\n\n屏幕里的老人正在微笑，对着某个不在画面中的人说话：\n\n\"……对，他进来了。比预计的更快识破第一层。\"\n\n\"不，我不担心。囚徒困境只是热身。\"\n\n\"真正的游戏，从第二局开始。\"\n\n画面切断。走廊尽头出现一扇门，门上用血红的漆写着：\n\n【海盗分金】\n\n【九人入局。制定方案，投票处决。】\n\n【得票最低者，淘汰。】\n\n陆沉推开门。\n\n里面八张脸同时转向他。有人认出他，低声惊呼：\"那个学术骗子……\"\n\n他径直走向空位坐下，从口袋里摸出那张邀请函，对着灯光再次审视那串数字。\n\n2024071903。\n\n病历号。精准对应。精准到像是……\n\n有人在三年前就开始写这张邀请函了。\n\n\"各位。\"机械声打断他的思绪，\"海盗分金，经典博弈论模型变体。\"\n\n\"九名海盗分一百枚金币，由最资深者提出方案，全体投票。若半数及以上反对，提议者被扔下船，由下一位提议。\"\n\n\"变体规则：方案需包含\'淘汰对象\'。得票最低者，出局。\"\n\n\"限时，三十分钟。\"\n\n陆沉抬起头。八双眼睛里有贪婪，有恐惧，有算计——\n\n还有一双，来自他正对面的年轻女人，正用一种近乎怜悯的目光看着他。\n\n她嘴唇动了动。没有声音，但陆沉读懂了口型：\n\n\"他们针对你。\"\n\n\"方案从你先开始', NULL, '', 0, 0, NULL, NULL, 1, NULL, '2026-03-09 01:26:03', 0);
INSERT INTO `user_creation` VALUES (2030696795209850881, 2026229317599551489, 'studio_novel', '高智商死亡游戏博弈', 'ICU的玻璃窗结着一层薄霜。\n\n陆沉把额头抵上去，凉得刺骨。里面那个瘦成一把骨头的女孩是他妹妹，十七岁，先天性心脏病，等一颗永远等不到的供体。\n\n账单在口袋里折成四折，数字烫得他掌心发疼。\n\n\"陆先生？\"\n\n护士递来一个黑色信封。烫金火漆印是希腊字母Ω，拆开只有一行字：\n\n【十亿。七夜。一人。】\n\n【奥林匹斯恭候。】\n\n底下附着一串数字：2024071903。\n\n陆沉瞳孔骤缩。这是妹妹的病历编号，连科室代码都一模一样。\n\n---\n\n环形密室没有门。\n\n十个人站在十等分的金属平台上，头顶是蜂巢状的监控阵列。陆沉数完心跳，第三十七秒，机械女声切开空气：\n\n\"囚徒迷宫，限时一小时。\"\n\n\"两两组队，解开中央密码锁。每队仅一人晋级。\"\n\n\"组队失败，双双淘汰。\"\n\n平台开始移动。陆沉对面是个戴金丝眼镜的中年男人，袖口绣着某投行的LOGO。两人之间的地面裂开，升起一道透明幕墙——只挡视线，不隔音。\n\n\"合作吧。\"男人先开口，声音透过幕墙有些失真，\"我金融数学出身，你——\"\n\n\"陆沉。以前做数论的。\"\n\n男人眼睛亮了一下，像闻到血腥的鲨鱼。陆沉知道这种眼神。三年前他的论文被指控造假，审查委员会里全是这种眼神。\n\n\"数论好，素数分解、椭圆曲线，密码学基础。\"男人凑近幕墙，\"这样，你负责计算，我负责验证，晋级名额——\"\n\n\"怎么分？\"\n\n\"……什么？\"\n\n陆沉笑了。这是三天来他第一次牵动面部肌肉，僵硬得像在撕扯伤疤。\n\n\"规则说每队仅一人晋级。\"他一字一顿，\"你刚才，在回避这个问题。\"\n\n男人脸色变了。\n\n幕墙降下。两人之间只剩三米距离，中央悬浮着一块全息键盘，输入界面是黎曼ζ函数的非平凡零点分布图。\n\n\"限时五十五分钟。\"机械声提醒。\n\n男人扑向键盘。陆沉没动。\n\n他在看监控阵列的反光。十个平台，五组\"队友\"，每一组都在微笑、握手、拍肩——表演着一种荒诞的亲密。左边那对甚至在讨论出去后怎么分奖金。\n\n太完美了。完美得像设计好的剧本。\n\n\"你在干什么！\"男人回头吼他，\"零点计算需要并行——\"\n\n\"零点计算不需要两个人。\"陆沉终于走向键盘，\"黎曼猜想至今未证，但这道题用的是已知前一百亿个零点的近似值。单人足够。\"\n\n\"那你为什么——\"\n\n\"我在等。\"\n\n\"等什么？\"\n\n陆沉按下第一个键。全息界面泛起涟漪，他输入的不是数字，而是一段指令代码。\n\n\"等你露出破绽。\"\n\n屏幕炸裂成无数碎片，重组为全新的界面——【管理员模式】。男人的表情凝固了，他冲向键盘，却被陆沉侧身撞开。\n\n\"规则有漏洞。\"陆沉的声音很轻，像在讲解一道习题，\"它说\'解开密码锁\'，没说必须输入正确答案。\"\n\n他敲下回车键。\n\n【系统覆盖。强制晋级。】\n\n男人僵在原地。机械声再次响起，这次带着某种愉悦的变调：\n\n\"检测到规则利用。陆沉，晋级。\"\n\n\"搭档王振，淘汰。\"\n\n地板裂开。不是升降台，是垂直的深渊。四条机械臂从黑暗中伸出，扣住男人的四肢，拖入暗门。他的尖叫被金属闸门切成碎片。\n\n陆沉站在原地，听着那声音越来越远，最后变成管道里的空洞回响。\n\n不是离开。是处理。\n\n---\n\n出口是一条纯白走廊。\n\n陆沉走了十七步，左侧墙壁变成整面屏幕。十个分屏显示着其他密室的实时画面：有人在搏斗，有人在哭泣，有人在最后一刻被队友推下平台。\n\n主屏幕突然切换。\n\n一张脸占据整个画面。六十岁左右，银白鬓角梳得一丝不苟，胸前的徽章是某国际数学联盟的终身荣誉标志。\n\n周牧野。\n\n三年前那场听证会的首席审查委员。就是他，在镜头前说\"陆沉的论文存在系统性造假，建议撤销学位并终身禁入学术界\"。\n\n屏幕里的老人正在微笑，对着某个不在画面中的人说话：\n\n\"……对，他进来了。比预计的更快识破第一层。\"\n\n\"不，我不担心。囚徒困境只是热身。\"\n\n\"真正的游戏，从第二局开始。\"\n\n画面切断。走廊尽头出现一扇门，门上用血红的漆写着：\n\n【海盗分金】\n\n【九人入局。制定方案，投票处决。】\n\n【得票最低者，淘汰。】\n\n陆沉推开门。\n\n里面八张脸同时转向他。有人认出他，低声惊呼：\"那个学术骗子……\"\n\n他径直走向空位坐下，从口袋里摸出那张邀请函，对着灯光再次审视那串数字。\n\n2024071903。\n\n病历号。精准对应。精准到像是……\n\n有人在三年前就开始写这张邀请函了。\n\n\"各位。\"机械声打断他的思绪，\"海盗分金，经典博弈论模型变体。\"\n\n\"九名海盗分一百枚金币，由最资深者提出方案，全体投票。若半数及以上反对，提议者被扔下船，由下一位提议。\"\n\n\"变体规则：方案需包含\'淘汰对象\'。得票最低者，出局。\"\n\n\"限时，三十分钟。\"\n\n陆沉抬起头。八双眼睛里有贪婪，有恐惧，有算计——\n\n还有一双，来自他正对面的年轻女人，正用一种近乎怜悯的目光看着他。\n\n她嘴唇动了动。没有声音，但陆沉读懂了口型：\n\n\"他们针对你。\"\n\n\"方案从你先开始', NULL, '', 0, 0, NULL, NULL, 1, NULL, '2026-03-09 01:26:59', 0);
INSERT INTO `user_creation` VALUES (2030696894887485441, 2026229317599551489, 'studio_novel', '高智商死亡游戏博弈', 'ICU的玻璃窗结着一层薄霜。\n\n陆沉把额头抵上去，凉得刺骨。里面那个瘦成一把骨头的女孩是他妹妹，十七岁，先天性心脏病，等一颗永远等不到的供体。\n\n账单在口袋里折成四折，数字烫得他掌心发疼。\n\n\"陆先生？\"\n\n护士递来一个黑色信封。烫金火漆印是希腊字母Ω，拆开只有一行字：\n\n【十亿。七夜。一人。】\n\n【奥林匹斯恭候。】\n\n底下附着一串数字：2024071903。\n\n陆沉瞳孔骤缩。这是妹妹的病历编号，连科室代码都一模一样。\n\n---\n\n环形密室没有门。\n\n十个人站在十等分的金属平台上，头顶是蜂巢状的监控阵列。陆沉数完心跳，第三十七秒，机械女声切开空气：\n\n\"囚徒迷宫，限时一小时。\"\n\n\"两两组队，解开中央密码锁。每队仅一人晋级。\"\n\n\"组队失败，双双淘汰。\"\n\n平台开始移动。陆沉对面是个戴金丝眼镜的中年男人，袖口绣着某投行的LOGO。两人之间的地面裂开，升起一道透明幕墙——只挡视线，不隔音。\n\n\"合作吧。\"男人先开口，声音透过幕墙有些失真，\"我金融数学出身，你——\"\n\n\"陆沉。以前做数论的。\"\n\n男人眼睛亮了一下，像闻到血腥的鲨鱼。陆沉知道这种眼神。三年前他的论文被指控造假，审查委员会里全是这种眼神。\n\n\"数论好，素数分解、椭圆曲线，密码学基础。\"男人凑近幕墙，\"这样，你负责计算，我负责验证，晋级名额——\"\n\n\"怎么分？\"\n\n\"……什么？\"\n\n陆沉笑了。这是三天来他第一次牵动面部肌肉，僵硬得像在撕扯伤疤。\n\n\"规则说每队仅一人晋级。\"他一字一顿，\"你刚才，在回避这个问题。\"\n\n男人脸色变了。\n\n幕墙降下。两人之间只剩三米距离，中央悬浮着一块全息键盘，输入界面是黎曼ζ函数的非平凡零点分布图。\n\n\"限时五十五分钟。\"机械声提醒。\n\n男人扑向键盘。陆沉没动。\n\n他在看监控阵列的反光。十个平台，五组\"队友\"，每一组都在微笑、握手、拍肩——表演着一种荒诞的亲密。左边那对甚至在讨论出去后怎么分奖金。\n\n太完美了。完美得像设计好的剧本。\n\n\"你在干什么！\"男人回头吼他，\"零点计算需要并行——\"\n\n\"零点计算不需要两个人。\"陆沉终于走向键盘，\"黎曼猜想至今未证，但这道题用的是已知前一百亿个零点的近似值。单人足够。\"\n\n\"那你为什么——\"\n\n\"我在等。\"\n\n\"等什么？\"\n\n陆沉按下第一个键。全息界面泛起涟漪，他输入的不是数字，而是一段指令代码。\n\n\"等你露出破绽。\"\n\n屏幕炸裂成无数碎片，重组为全新的界面——【管理员模式】。男人的表情凝固了，他冲向键盘，却被陆沉侧身撞开。\n\n\"规则有漏洞。\"陆沉的声音很轻，像在讲解一道习题，\"它说\'解开密码锁\'，没说必须输入正确答案。\"\n\n他敲下回车键。\n\n【系统覆盖。强制晋级。】\n\n男人僵在原地。机械声再次响起，这次带着某种愉悦的变调：\n\n\"检测到规则利用。陆沉，晋级。\"\n\n\"搭档王振，淘汰。\"\n\n地板裂开。不是升降台，是垂直的深渊。四条机械臂从黑暗中伸出，扣住男人的四肢，拖入暗门。他的尖叫被金属闸门切成碎片。\n\n陆沉站在原地，听着那声音越来越远，最后变成管道里的空洞回响。\n\n不是离开。是处理。\n\n---\n\n出口是一条纯白走廊。\n\n陆沉走了十七步，左侧墙壁变成整面屏幕。十个分屏显示着其他密室的实时画面：有人在搏斗，有人在哭泣，有人在最后一刻被队友推下平台。\n\n主屏幕突然切换。\n\n一张脸占据整个画面。六十岁左右，银白鬓角梳得一丝不苟，胸前的徽章是某国际数学联盟的终身荣誉标志。\n\n周牧野。\n\n三年前那场听证会的首席审查委员。就是他，在镜头前说\"陆沉的论文存在系统性造假，建议撤销学位并终身禁入学术界\"。\n\n屏幕里的老人正在微笑，对着某个不在画面中的人说话：\n\n\"……对，他进来了。比预计的更快识破第一层。\"\n\n\"不，我不担心。囚徒困境只是热身。\"\n\n\"真正的游戏，从第二局开始。\"\n\n画面切断。走廊尽头出现一扇门，门上用血红的漆写着：\n\n【海盗分金】\n\n【九人入局。制定方案，投票处决。】\n\n【得票最低者，淘汰。】\n\n陆沉推开门。\n\n里面八张脸同时转向他。有人认出他，低声惊呼：\"那个学术骗子……\"\n\n他径直走向空位坐下，从口袋里摸出那张邀请函，对着灯光再次审视那串数字。\n\n2024071903。\n\n病历号。精准对应。精准到像是……\n\n有人在三年前就开始写这张邀请函了。\n\n\"各位。\"机械声打断他的思绪，\"海盗分金，经典博弈论模型变体。\"\n\n\"九名海盗分一百枚金币，由最资深者提出方案，全体投票。若半数及以上反对，提议者被扔下船，由下一位提议。\"\n\n\"变体规则：方案需包含\'淘汰对象\'。得票最低者，出局。\"\n\n\"限时，三十分钟。\"\n\n陆沉抬起头。八双眼睛里有贪婪，有恐惧，有算计——\n\n还有一双，来自他正对面的年轻女人，正用一种近乎怜悯的目光看着他。\n\n她嘴唇动了动。没有声音，但陆沉读懂了口型：\n\n\"他们针对你。\"\n\n\"方案从你先开始', NULL, '', 0, 0, NULL, NULL, 1, NULL, '2026-03-09 01:27:23', 0);
