INSERT INTO `user_creation` VALUES (2030859672419831810, 2026229317599551489, 'emotion', '情感配音 2026-03-09', '[#用暧昧低沉、若即若离的语气，像在耳边轻声说情话] 你耳朵红了……嗯？别躲。我偏要凑近说——今晚的风，很软。像你。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773029646114.mp3', 12, 0, NULL, NULL, 0, NULL, '2026-03-09 12:14:12', 0);
INSERT INTO `user_creation` VALUES (2030860424005554177, 2026229317599551489, 'emotion', '情感配音 2026-03-09', 'test', 'zh_male_dayi_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773029830922.mp3', 1, 0, NULL, NULL, 0, NULL, '2026-03-09 12:17:11', 0);
INSERT INTO `user_creation` VALUES (2030868539589550082, 2026229317599551489, 'tts', '语音合成 2026-03-09', '大家好，这是我的声音，希望你会喜欢。欢迎来到声读 AI 语音创作平台。', 'BV002_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1773031760512.mp3', 8, 120000, NULL, NULL, 0, NULL, '2026-03-09 12:49:26', 0);
INSERT INTO `user_creation` VALUES (2031008246570995714, 2026229317599551489, 'workshop', '工坊 AI 合成', '*风声呜咽*\n\n你……听见了吗？\n\n那扇老门，又在响了。\n\n不是风。是*她*——那个穿着红绣鞋的女人，正一寸一寸，从楼梯爬上来。你没有锁门，对吧？*你忘了。*\n\n*木板吱呀——吱呀——*\n\n她的脖子……是反的。所以她在笑的时候，你看见的是后脑勺的头发，在月光里，像一团纠缠的黑蛇。\n\n*（压低，近乎耳语）*\n\n她停在你门外了。\n\n三声。她只会敲三声。\n\n*咚。*\n\n*咚。*\n\n——别呼吸。别让她听见', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773065068930.mp3', 75, 0, NULL, NULL, 0, NULL, '2026-03-09 22:04:35', 0);
INSERT INTO `user_creation` VALUES (2031017406607970306, 2026229317599551489, 'workshop', '工坊 AI 合成', '你听，森林里传来细碎的脚步声——是小鹿在落叶上写诗呢。它的眼睛盛着一整个清晨的露水，眨一眨，就落下一颗星星。\n\n兔子小姐抱着蒲公英，正挨家挨户地送小伞。她说：风往哪儿吹，梦就往哪儿飞呀。\n\n而那只总打盹的熊，其实醒着呢。它把蜂蜜藏进树洞，也藏起了整个冬天的甜。每当有人路过，它便翻个身，假装呼噜呼噜——这是森林里最温柔的秘密。\n\n月亮升起来的时候，刺猬会蜷成一颗小小的星球，萤火虫绕着它飞，像一圈不会', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773067258264.mp3', 55, 0, NULL, NULL, 0, NULL, '2026-03-09 22:40:59', 0);
INSERT INTO `user_creation` VALUES (2031052600094355457, 2026229317599551489, 'workshop', '工坊 AI 合成', '城市的灯火渐暗，而你还在路上。我是今晚的声音，陪你走完这一程。\n\n凌晨两点的街道，像一首未完成的诗。有人刚结束加班，有人在等一个不会打来的电话，有人只是……不想睡。没关系，这里不打烊。\n\n你听，窗外偶尔驶过的车声，像远方传来的问候。冰箱的嗡鸣，是家里唯一醒着的存在。这些细碎的声响，都在说：你并不孤单。\n\n今天或许不尽如人意。但此刻，你能听见自己的呼吸，就是一件温柔的事。世界很大，烦恼很小。睡吧，或', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773075649271.mp3', 51, 0, NULL, NULL, 0, NULL, '2026-03-10 01:00:50', 0);
INSERT INTO `user_creation` VALUES (2031073073414856705, 2026229317599551489, 'workshop', '工坊 AI 合成', '城市的灯火一盏盏暗下去，只剩下我这盏，还为你亮着。\n\n此刻的你，或许刚结束加班，或许正独自赶路，或许只是睡不着。没关系，我在这里。\n\n深夜总让人变得柔软。白天的铠甲可以卸下了，那些没说出口的话，那些来不及的想念，都交给这漫长的夜吧。电台里的音乐轻轻淌着，像有人替你掖了掖被角。\n\n你知道吗？此刻城市里还有很多人醒着。有人在急诊室外徘徊，有人在等最后一班地铁，有人只是盯着天花板，数着羊。我们素未谋面，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773080529940.mp3', 56, 0, NULL, NULL, 0, NULL, '2026-03-10 02:22:11', 0);
INSERT INTO `user_creation` VALUES (2031191790790393858, 2026229317599551489, 'tts', '语音合成 2026-03-10', '黑暗从来不是空的。它塞满了秘密，和正在腐烂的真相。你听过那种声音吗？脚步声停在门外，呼吸声却从背后传来。这里没有鬼，只有人。人比鬼更擅长把自己藏起来。画面开始剥落。第一帧是笑容，最后一帧是牙齿。中间发生了什么？没人记得。或者说，记得的人，都已经不能开口了。现在，把灯关掉。不是要你害怕，是要你看清——当所有光都熄灭时，什么东西，正在靠近你的后颈。故事开始了。但你确定，你想知道结局吗？', 'BV056_streaming', 'https://r2.joyoai.xyz/audio/tts1/tts_1773108833992.mp3', 48, 729600, NULL, NULL, 0, NULL, '2026-03-10 10:13:55', 0);
INSERT INTO `user_creation` VALUES (2031192224548536322, 2026229317599551489, 'emotion', '情感配音 2026-03-10', '[#用压低声音、带点气声、语速放缓、偶尔颤音的语气] 你听……那脚步声又停了。它在门外，在呼吸，在等你回头。别动，别眨眼——它最喜欢看猎物……自己转过身来。', 'zh_male_ruyayichen_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773108937960.mp3', 17, 0, NULL, NULL, 0, NULL, '2026-03-10 10:15:39', 0);
INSERT INTO `user_creation` VALUES (2031192306211635201, 2026229317599551489, 'emotion', '情感配音 2026-03-10', '[#用压低声音、带点气声、语速放缓、偶尔颤音的语气] 你听……那脚步声又停了。它在门外，在呼吸，在等你回头。别动，别眨眼——它最喜欢看猎物……自己转过身来。', 'zh_male_ruyayichen_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773108957917.mp3', 17, 0, NULL, NULL, 0, NULL, '2026-03-10 10:15:58', 0);
INSERT INTO `user_creation` VALUES (2031408750677557249, 2026229317599551489, 'workshop', '工坊 AI 合成', '城市的灯火一盏盏暗下去，而你还在听，对吗？\n\n我知道，有些心事只适合在深夜说给自己听。白天的铠甲太沉了，此刻终于可以卸下。那些没说出口的想念，那些努力了却没结果的事，那些笑着说不疼的瞬间——我都懂。\n\n你看窗外，月亮正路过你的窗台。它见过太多孤独的人，却从未嘲笑过任何一个。所以啊，别责怪自己走得慢。深夜不是惩罚，是宇宙偷偷给你的温柔缓冲。\n\n把今天的疲惫放下吧。你已经在尽力了，真的。\n\n我是你的深', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773160556529.mp3', 50, 0, NULL, NULL, 0, NULL, '2026-03-11 00:36:03', 0);
INSERT INTO `user_creation` VALUES (2031414988828049410, 2026229317599551489, 'workshop', '工坊 AI 合成', '愿这一天的阳光，为你停留得久一些。愿所有的美好，都如约而至——不只是今天，而是往后的每一天。生日快乐，愿你被世界温柔以待，也愿你心中永远住着那个相信奇迹的小孩。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773162043683.mp3', 18, 0, NULL, NULL, 0, NULL, '2026-03-11 01:00:50', 0);
INSERT INTO `user_creation` VALUES (2031416562992283650, 2026229317599551489, 'workshop', '工坊 AI 合成', '凌晨三点的台灯记得你倔强的轮廓，跌倒时膝盖的淤青是你最硬的勋章。别怕慢，怕的是停；别惧暗，惧的是不燃。你流的汗不会说谎，你熬的夜终将发光。站起来，这世界的掌声，正等着为你炸响！', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773162419374.mp3', 20, 0, NULL, NULL, 0, NULL, '2026-03-11 01:07:05', 0);
INSERT INTO `user_creation` VALUES (2031421537529147394, 2026229317599551489, 'emotion', '情感配音 2026-03-11', '你有没有发现，最该做的事总是被推到最后一刻。明明焦虑得要命，手指却诚实地刷着手机。这不是懒，是你的大脑在打架。\n\n想象你面前有两块蛋糕。一块是巧克力，现在就能吃。一块是更大的提拉米苏，但要等一小时。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773163609857.mp3', 22, 0, NULL, NULL, 0, NULL, '2026-03-11 01:26:51', 0);
INSERT INTO `user_creation` VALUES (2031421557179461634, 2026229317599551489, 'emotion', '情感配音 2026-03-11', '大多数人会抓起巧克力。这就是延迟折扣——大脑把未来的奖励打骨折出售。明天才交的论文，在今天就变得不值一提。\n\n更狡猾的是，大脑会自我欺骗。它说，我先刷五分钟视频，等下效率更高。这叫计划谬误，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773163615476.mp3', 21, 0, NULL, NULL, 0, NULL, '2026-03-11 01:26:56', 0);
INSERT INTO `user_creation` VALUES (2031421578251644930, 2026229317599551489, 'emotion', '情感配音 2026-03-11', '我们永远高估未来的自己，低估当下的诱惑。那个未来的你，其实和现在的你一样爱拖延。\n\n但拖延也有情绪功能。面对困难任务，焦虑像警报器响个不停。刷手机不是快乐，是逃避痛苦的止痛药。问题是，逃避让焦虑发酵，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773163620542.mp3', 22, 0, NULL, NULL, 0, NULL, '2026-03-11 01:27:01', 0);
INSERT INTO `user_creation` VALUES (2031421597339922434, 2026229317599551489, 'emotion', '情感配音 2026-03-11', '任务变得更可怕，循环就此形成。\n\n怎么破？别靠意志力硬扛。把大目标切成碎片，让大脑看到即时反馈。写报告？先打开文档，只写第一句。行动本身会改变情绪，而不是等情绪好了才行动。\n\n你知道吗，', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773163625122.mp3', 20, 0, NULL, NULL, 0, NULL, '2026-03-11 01:27:05', 0);
INSERT INTO `user_creation` VALUES (2031421615161520130, 2026229317599551489, 'emotion', '情感配音 2026-03-11', '拖延者往往完美主义。不是不想做，是怕做得不够好。接纳粗糙的第一步，比幻想完美的结局更重要。\n\n真相是，拖延不是时间管理问题，是情绪调节问题。理解这一点，你就赢了一半。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773163629393.mp3', 18, 0, NULL, NULL, 0, NULL, '2026-03-11 01:27:10', 0);
INSERT INTO `user_creation` VALUES (2031423855213457410, 2026229317599551489, 'studio_lecture', '为什么我们总是拖延？心理...', '你有没有发现，最该做的事总是被推到最后一刻。明明焦虑得要命，手指却诚实地刷着手机。这不是懒，是你的大脑在打架。\n\n想象你面前有两块蛋糕。一块是巧克力，现在就能吃。一块是更大的提拉米苏，但要等一小时。大多数人会抓起巧克力。这就是延迟折扣——大脑把未来的奖励打骨折出售。明天才交的论文，在今天就变得不值一提。\n\n更狡猾的是，大脑会自我欺骗。它说，我先刷五分钟视频，等下效率更高。这叫计划谬误，我们永远高估未来的自己，低估当下的诱惑。那个未来的你，其实和现在的你一样爱拖延。\n\n但拖延也有情绪功能。面对困难任务，焦虑像警报器响个不停。刷手机不是快乐，是逃避痛苦的止痛药。问题是，逃避让焦虑发酵，任务变得更可怕，循环就此形成。\n\n怎么破？别靠意志力硬扛。把大目标切成碎片，让大脑看到即时反馈。写报告？先打开文档，只写第一句。行动本身会改变情绪，而不是等情绪好了才行动。\n\n你知道吗，拖延者往往完美主义。不是不想做，是怕做得不够好。接纳粗糙的第一步，比幻想完美的结局更重要。\n\n真相是，拖延不是时间管理问题，是情绪调节问题。理解这一点，你就赢了一半。\n\n', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1773163632648.mp3', 104, 0, NULL, NULL, 1, 2031423855381229569, '2026-03-11 01:36:04', 0);
INSERT INTO `user_creation` VALUES (2031602973822373889, 2026229317599551489, 'podcast', 'AI播客 · Ai时代如何学习？', 'Ai时代如何学习？', 'zh_female_mizaitongxue_v2_saturn_bigtts', '', 504, 0, NULL, '{\"roundCount\": 39, \"transcript\": \": \\nzh_female_mizaitongxue_v2_saturn_bigtts: 哈喽大家好欢迎收听我们的播客，然后今天我们想聊一聊在现在这个 AI 飞速发展的这个时代。我们到底应该怎么去学习，嗯对吧因为。这个 AI 确实在改变我们传统的学习方式，也在让我们的教育不断的去创新。甚至说有人说二零二五年会是这个 AI 赋能教育变革的元年。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 是啊这个话题真的很有意思，那我们就直接开始今天的讨论吧。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 咱们今天第一个主题呢就是想聊一聊关于这个 AI 时代学习方式的变革，OK，对然后咱们第一个问题是。AI 到底是？从哪些层面？改变了我们学习的理念，嗯。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就我觉得 AI 让学习变得非常的不一样就是他会根据每个人的兴趣。基础，然后他的这个学习的进度。去推送最适合你的内容，那这个就是以前是没有办法想象的就是。他可以通过你的这个学习数据的画像。自动的去调整。这个难度和任务，对你就感觉像是有一个懂你的私人教练一样全程陪着你。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听上去真的很神奇就感觉学习像是一场为你定制的冒险。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错没错而且就是。AI 它还可以激发你主动去提问，去探索。然后去培养你的批判思维和创新能力对，就它会让你不再是一个被动的接受者。而是真正的成为一个主角，在这个学习的舞台上面。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎我还在想就是 AI 是不是也在悄悄的改变我们学东西的内容，和学东西的方式。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错没错，就是 AI 其实是把。理论和动手，结合的更紧密了，对就他会让你。不光是去啃书本，嗯他会让你直接就面对真实世界的挑战。哦对，比如说他会帮你设计一些跨学科的项目。然后让你去锻炼这种解决复杂问题的能力。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 感觉好像课程内容也变得更丰富了更多元了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对因为，AI 它能够处理，文本图像视频。所以你可以用很多种方式去获取知识，然后它也可以自动的帮你梳理。这个重点难点。帮你去搭建这种个性化的知识结构，OK 对就会让你的学习又高效又有趣。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 哎，那我还在想就是 AI 是不是也在悄悄的改变我们学习的地点和学习的方式？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错，就是 AI 让学习不再局限于教室和课本。对，就他会把学习的场景拓展到。任何你有网络的地方，OK 对就你可以通过线上线下的无缝切换。然后来享受这个全球的优质课程。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就学习变得更自由了，更灵活了。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对而且他会用一些虚拟现实的技术让你有沉浸式的体验。然后也会有这种智能的教辅和这种 AI 的学伴。来跟你进行这种实时的互动，OK 对你就会觉得。学习就像是一个大型的协作游戏。对，你可以自己主导自己的探索和创造。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 那我们来聊一聊第二个大的部分，就是 AI 助力学习的一些具体的途径，嗯啊第一个问题我们就来聊。有哪些主流的 AI 工具可以帮助我们学习，以及它们各自有什么特别的地方？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 嗯其实现在的 AI 学习工具真的是超级多，比如说有一些是拍照。就可以解数学题的，嗯哼然后还有一些是可以。直接给你生成，知识点的总结和笔记的。还有一些是可以，智能的帮你整理，复习资料的。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就像一个，学习小助手的百宝箱。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错没错没错，而且还有那种。可以语音转文字的，做智能测验的。还有那种可以帮你写作润色的，甚至还有那种可以根据你的学习数据帮你定制。学习计划的，反正就是。你能想到的学习的每一个环节几乎都有专门的 AI 工具可以帮你。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 具体来说的话我们怎么样？用这些 AI 工具，来制定学习计划，或者说提升学习效率呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 比如说你可以让 AI 帮你拆分课程大纲。然后帮你安排每天的学习任务，甚至可以根据你的进度自动的帮你调整。难度和节奏，就你相当于有一个。专属的学习管家。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就像私人教练一样贴心。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 没错没错没错而且他还可以。帮你把资料变成思维导图，嗯然后变成知识卡片。你可以用它来做一些互动的测验。来检验你的学习成果，包括你写作的时候它可以帮你直接就是润色或者帮你生成一个初稿。你可以用它来。高效的管理你的时间管理你的专注力，就它其实是一个。全流程都可以帮你提升的一个效率的一个利器。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 既然现在大家都在用这个 AI 来辅助学习那具体用的时候有哪些细节是我们需要特别注意的呢？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 首先就是，呃不要盲目的依赖它的答案吧就还是要自己去思考然后去验证一下它的信息。对，再就是要。选择比较靠谱的安全的工具，对你也要了解一下它背后的一些隐私的规则。不要让自己的信息泄露了，再就是。你要结合自己的学习目标去。灵活的使用不同的 AI 工具，再就是你也要不断的去练习。自己的一些核心的能力这样的话你才能够真正的让 AI 成为你的一个好帮手而不是让你产生依赖。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 我们现在要聊的就是，AI 时代学习的新挑战。对，第一个问题，就是在这个 AI 加速发展的大背景下，我们究竟要培养哪些核心能力？才不至于被时代抛下？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 就我觉得其实现在最核心的就是，你得有系统性的梳理知识的能力。然后有跨学科的整合的能力，这样的话你才能够看得懂这个。复杂的世界，OK 对你要知道怎么去。提出好的问题，要会批判性的去判断信息的真假对错包括。AI 给你生成的一些东西你也要去判断它的逻辑是不是合理有没有什么偏见。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 嗯，感觉好像这些能力都不是说死记硬背能获得的。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对完全没错，就更重要的是你要学会跟 AI 协作。然后用 AI 来拓展你的创造力，嗯还有就是你要持续的有自学的能力。有适应新环境的能力，包括你的沟通协作能力。你的伦理道德的意识，责任感，这些东西其实都是。决定你未来能走多远的一些关键。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 对那我们在享受这个 AI 带来的高效学习的同时，有哪些风险是我们需要警惕的？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 其实如果过度的依赖 AI 的话。你会发现你的很多思考能力会变弱，然后包括你会很容易。陷入那种信息的泡沫里面就你以为你知道了很多但其实你没有经过自己的深度加工。还有就是 AI 生成的一些内容它可能是不准确的甚至是有偏见的。你如果盲目相信的话就会被误导。还有就是你的隐私可能会泄露，会有一些道德伦理上面的问题。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来就好像是，用 AI 学习就像是走钢丝一样，你得时刻保持警觉。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对确实是这样就是。你要经常去训练自己的这种思辨力。然后不要去一味的依赖 AI 的答案，去。多方的验证信息包括你要去了解这个 AI 工具背后的一些运作的原理和。隐私的规则，包括你把你的个人数据保护好。还有就是要让 AI 去做它擅长的事情，你做你擅长的事情，你们两个形成一个互补。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 那你觉得，嗯，就个人也好还是整个社会也好，应该用什么样的方式去？积极的应对这个因为 AI 而带来的学习的变革？\\nzh_male_dayixiansheng_v2_saturn_bigtts: 我觉得就是每个人都应该把。学会学习，当成一个很重要的事情就是你要不断的去主动的接触新的知识。然后去，提升自己的技能。这样的话你可以更好的适应这个快速变化的社会。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 听起来好像是，大家都得成为一个终身学习者。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 对没错没错，然后同时呢我觉得。学校和社会要搭建一个多元的评价体系。鼓励大家去发展那些 AI 没有办法取代的能力。比如创新，比如协作，比如沟通。等等的一些能力，那我们就可以真正的和 AI 形成一个互补，共同进步。\\nzh_female_mizaitongxue_v2_saturn_bigtts: 对今天我们其实聊了很多关于。AI 如何正在改变我们的学习的方式，包括从个性化的体验到。全新的能力的培养，其实我觉得。最重要的还是大家要主动的去拥抱这个变化，然后敢于去尝试，用 AI 来开启属于自己的学习新时代。\\nzh_male_dayixiansheng_v2_saturn_bigtts: 好啦这期播客就到这里啦然后。感谢大家的收听，愿你和 AI 一起成长，我们下次再见拜拜拜拜！\"}', 0, NULL, '2026-03-11 13:27:49', 0);
INSERT INTO `user_creation` VALUES (2031604401680896002, 2026229317599551489, 'studio_podcast', 'Ai时代如何学习？', '咪仔：哈喽大家好欢迎收听我们的播客，然后今天我们想聊一聊在现在这个 AI 飞速发展的这个时代。我们到底应该怎么去学习，嗯对吧因为。这个 AI 确实在改变我们传统的学习方式，也在让我们的教育不断的去创新。甚至说有人说二零二五年会是这个 AI 赋能教育变革的元年。\n\n大一先生：是啊这个话题真的很有意思，那我们就直接开始今天的讨论吧。\n\n咪仔：咱们今天第一个主题呢就是想聊一聊关于这个 AI 时代学习方式的变革，OK，对然后咱们第一个问题是。AI 到底是？从哪些层面？改变了我们学习的理念，嗯。\n\n大一先生：就我觉得 AI 让学习变得非常的不一样就是他会根据每个人的兴趣。基础，然后他的这个学习的进度。去推送最适合你的内容，那这个就是以前是没有办法想象的就是。他可以通过你的这个学习数据的画像。自动的去调整。这个难度和任务，对你就感觉像是有一个懂你的私人教练一样全程陪着你。\n\n咪仔：听上去真的很神奇就感觉学习像是一场为你定制的冒险。\n\n大一先生：没错没错没错而且就是。AI 它还可以激发你主动去提问，去探索。然后去培养你的批判思维和创新能力对，就它会让你不再是一个被动的接受者。而是真正的成为一个主角，在这个学习的舞台上面。\n\n咪仔：哎我还在想就是 AI 是不是也在悄悄的改变我们学东西的内容，和学东西的方式。\n\n大一先生：没错没错没错，就是 AI 其实是把。理论和动手，结合的更紧密了，对就他会让你。不光是去啃书本，嗯他会让你直接就面对真实世界的挑战。哦对，比如说他会帮你设计一些跨学科的项目。然后让你去锻炼这种解决复杂问题的能力。\n\n咪仔：感觉好像课程内容也变得更丰富了更多元了。\n\n大一先生：对因为，AI 它能够处理，文本图像视频。所以你可以用很多种方式去获取知识，然后它也可以自动的帮你梳理。这个重点难点。帮你去搭建这种个性化的知识结构，OK 对就会让你的学习又高效又有趣。\n\n咪仔：哎，那我还在想就是 AI 是不是也在悄悄的改变我们学习的地点和学习的方式？\n\n大一先生：对没错，就是 AI 让学习不再局限于教室和课本。对，就他会把学习的场景拓展到。任何你有网络的地方，OK 对就你可以通过线上线下的无缝切换。然后来享受这个全球的优质课程。\n\n咪仔：听起来就学习变得更自由了，更灵活了。\n\n大一先生：对而且他会用一些虚拟现实的技术让你有沉浸式的体验。然后也会有这种智能的教辅和这种 AI 的学伴。来跟你进行这种实时的互动，OK 对你就会觉得。学习就像是一个大型的协作游戏。对，你可以自己主导自己的探索和创造。\n\n咪仔：那我们来聊一聊第二个大的部分，就是 AI 助力学习的一些具体的途径，嗯啊第一个问题我们就来聊。有哪些主流的 AI 工具可以帮助我们学习，以及它们各自有什么特别的地方？\n\n大一先生：嗯其实现在的 AI 学习工具真的是超级多，比如说有一些是拍照。就可以解数学题的，嗯哼然后还有一些是可以。直接给你生成，知识点的总结和笔记的。还有一些是可以，智能的帮你整理，复习资料的。\n\n咪仔：听起来就像一个，学习小助手的百宝箱。\n\n大一先生：对没错没错没错，而且还有那种。可以语音转文字的，做智能测验的。还有那种可以帮你写作润色的，甚至还有那种可以根据你的学习数据帮你定制。学习计划的，反正就是。你能想到的学习的每一个环节几乎都有专门的 AI 工具可以帮你。\n\n咪仔：具体来说的话我们怎么样？用这些 AI 工具，来制定学习计划，或者说提升学习效率呢？\n\n大一先生：比如说你可以让 AI 帮你拆分课程大纲。然后帮你安排每天的学习任务，甚至可以根据你的进度自动的帮你调整。难度和节奏，就你相当于有一个。专属的学习管家。\n\n咪仔：听起来就像私人教练一样贴心。\n\n大一先生：没错没错没错而且他还可以。帮你把资料变成思维导图，嗯然后变成知识卡片。你可以用它来做一些互动的测验。来检验你的学习成果，包括你写作的时候它可以帮你直接就是润色或者帮你生成一个初稿。你可以用它来。高效的管理你的时间管理你的专注力，就它其实是一个。全流程都可以帮你提升的一个效率的一个利器。\n\n咪仔：既然现在大家都在用这个 AI 来辅助学习那具体用的时候有哪些细节是我们需要特别注意的呢？\n\n大一先生：首先就是，呃不要盲目的依赖它的答案吧就还是要自己去思考然后去验证一下它的信息。对，再就是要。选择比较靠谱的安全的工具，对你也要了解一下它背后的一些隐私的规则。不要让自己的信息泄露了，再就是。你要结合自己的学习目标去。灵活的使用不同的 AI 工具，再就是你也要不断的去练习。自己的一些核心的能力这样的话你才能够真正的让 AI 成为你的一个好帮手而不是让你产生依赖。\n\n咪仔：我们现在要聊的就是，AI 时代学习的新挑战。对，第一个问题，就是在这个 AI 加速发展的大背景下，我们究竟要培养哪些核心能力？才不至于被时代抛下？\n\n大一先生', 'zh_female_mizaitongxue_v2_saturn_bigtts', 'https://r2.joyoai.xyz/audio/tts1/podcast_1773207197390.mp3', 693, 0, NULL, NULL, 1, 2031604412061798402, '2026-03-11 13:33:29', 0);
INSERT INTO `user_creation` VALUES (2031691930814947330, 2031691539389915138, 'workshop', '工坊 AI 合成', '雨又落下来了。\n\n我数着窗上的水痕，像数着这些年漏掉的时光。台灯把影子钉在墙上，很轻，像谁叹息的尾音。\n\n楼下有人跑过，伞花开了一半又收住。我始终没有起身关窗——让潮气进来吧，让这房间学会发霉，学会像我这样，把心事腌成沉默。\n\n凌晨三点十七分。雨还在替我说话。', 'zh_female_vv_uranus_bigtts', 'https://r2.joyoai.xyz/audio/tts2/tts_v2_1773228076828.mp3', 29, 0, NULL, NULL, 0, NULL, '2026-03-11 19:21:18', 0);
