INSERT INTO `work` VALUES (2030288389353246722, 2026229317599551489, 2030288389323886594, 'studio', 'audio', '霍总装穷追妻被女主打脸', '林知夏：放门口就行，不用敲门。\n\n霍沉舟：林小姐，这箱是生鲜，需要当面签收。\n\n林知夏：你们快递员现在话这么多？上次那个直接扔门口就走了。\n\n霍沉舟：……公司有规定。\n\n林知夏：什么公司？这制服怎么没见过。\n\n霍沉舟：新成立的，叫……速达。\n\n林知夏：速达？没听过。你们老板谁啊，这么不会起名。\n\n霍沉舟：……可能确实不太会。\n\n林知夏：算了，笔给我。等等，你这手表——\n\n霍沉舟：假的，仿品。\n\n林', 0, 0, 30, NULL, 'story', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772893394294.mp3', 159, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030308058122493953, 2026229317599551489, 2030308058084745218, 'studio', 'audio', '给深夜失眠的你，一段温暖...', '夜深了。\n\n你还没睡。\n\n窗帘漏进一点银白，像谁悄悄铺了层薄霜。风很轻，轻得只敢碰一碰窗纱。\n\n我知道你今天很累。\n\n那些没说出口的话，没做完的事，还在脑子里转。像洗衣机最后一分钟的脱水，轰隆隆响。\n\n停了吧。\n\n你已经很努力了。真的。\n\n此刻什么都不用想。被子裹紧一点，想象自己是只蜷着的猫。毛茸茸的，暖烘烘的，谁也不用讨好。\n\n明天的事，交给明天的太阳。\n\n现在，只负责呼吸。\n\n吸气……呼气……', 0, 0, 37, NULL, 'emotion', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772898119127.mp3', 47, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030314198327664642, 2026229317599551489, 2030314198239584258, 'studio', 'audio', '如果太阳突然消失，地球会...', '如果我们想象太阳在某一瞬间凭空消失，地球并不会立刻陷入黑暗。光需要时间传播，所以我们还能看见太阳八分二十秒——那只是一场延迟播放的幽灵影像。\n\n真正的变化从引力开始。爱因斯坦告诉我们，引力不是瞬间作用的力，而是以光速传播的时空涟漪。所以地球会继续沿轨道飞行八分二十秒，像一头蒙眼奔跑的野兽，浑然不知牵引它的绳索已经断裂。然后——轨道切线方向飞离，成为星际流浪者。\n\n但问题其实很难。太阳消失的瞬间，核', 0, 0, 38, NULL, 'latest', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772899342049.mp3', 115, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030318700002824194, 2026229317599551489, 2030318699935715329, 'studio', 'audio', '一件轻薄羽绒服从办公室到...', '去年公司年会，我穿了件厚棉袄去。结果会议室暖气开到二十八度，我像个粽子一样坐在那，汗顺着后背往下淌。旁边同事倒好，外套一脱，里面是件薄毛衣，轻盈得像刚下班。\n\n中场休息我追出去问，她指了指椅背。一件叠成豆腐块的轻薄羽绒服，还没我的化妆包大。她说早上零下五度穿着骑车来的，进公司塞包里，下班再拿出来。\n\n我当时不信。直到今年深秋，我在地铁口被冷风刮透，冲进优衣库买了件同款。早上通勤穿着挡风，到办公室脱', 0, 0, 40, NULL, 'latest', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772900662616.mp3', 89, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030323943411306497, 2026229317599551489, 2030323943352586242, 'studio', 'audio', '小熊今天很生气，妈妈教他...', '小熊布布今天很生气，气得耳朵都在发抖。\n\n早上，他搭了整整一上午的积木城堡，轰隆——被跑过的梅花鹿撞倒了。布布的脸涨得通红，像熟透的苹果，他握紧拳头，好想好想大喊大叫。\n\n\"坏梅花鹿！我讨厌你！\"布布的声音把树上的小鸟都吓飞了。\n\n熊妈妈走过来，没有说\"别生气\"，而是蹲下来，轻轻抱住布布发抖的肩膀。\n\n\"布布，你的肚子里是不是有一团火在烧？咕噜咕噜，越烧越旺？\"\n\n布布愣了一下，点点头。真的呢，胸', 0, 0, 42, NULL, 'latest', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772901789193.mp3', 175, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030332730637664258, 2026229317599551489, 2030332730566361089, 'studio', 'audio', '最新AI芯片突破：算力提...', '国产新一代AI芯片今日正式发布。单芯片算力达到每秒千万亿次运算，较前代产品提升整整十倍。这一突破标志着我国在人工智能核心硬件领域迈出关键一步。\n\n据悉，该芯片采用全新架构设计，能耗比同步优化百分之四十。这意味着同等算力下，电费成本降至原有水平的六成。对于数据中心运营商而言，这直接转化为每年数亿元的运营开支削减。\n\n算力提升十倍，相当于把一座大型图书馆的信息检索时间，从数小时压缩到几分钟。在医疗影像', 0, 0, 43, NULL, 'news', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772903932925.mp3', 131, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030528580076716035, 2026229317599551489, 2030528580076716034, 'studio', 'audio', '霍总装穷追妻被女主打脸', '[纸张翻动声]\n\n沈知意：苏小姐，这是城西新开的梨园，头牌小生会唱十八摸。\n\n苏晚晴：……沈姑娘，你可知我是太子未婚妻？\n\n沈知意：知道啊，所以送你这个。太子不如戏子，至少戏子卖艺不卖身。\n\n苏晚晴：你疯了？我若告诉太子——\n\n沈知意：去告啊，就说沈家嫡女给你塞了男倌馆的名帖。你看太子信谁。\n\n[茶盏轻磕声]\n\n苏晚晴：你到底想要什么？\n\n沈知意：想要你活着。原书里你嫁太子，三年后被做成人彘。\n\n', 0, 0, 44, NULL, 'story', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1772950666960.mp3', 152, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-08 14:33:41', 0);
INSERT INTO `work` VALUES (2030698340559171586, 2026229317599551489, 2030698340454313985, 'studio', 'novel', '高智商死亡游戏博弈', '落魄数学天才陆沉为偿还妹妹天价医疗费,被迫参加神秘组织\"奥林匹斯\"举办的死亡博弈游戏。十名玩家需在七天内通过六轮高智商对决淘汰对手,最终胜者独揽十亿奖金。陆沉发现游戏背后隐藏着三年前导致自己学术身败名裂的阴谋,必须在生死边缘揭开真相、完成复仇与救赎。', 12359, 5, 45, NULL, 'novel', NULL, '', 0, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-09 01:33:08', 0);
