INSERT INTO `work` VALUES (2031423855381229569, 2026229317599551489, 2031423855213457410, 'studio', 'audio', '为什么我们总是拖延？心理...', '你有没有发现，最该做的事总是被推到最后一刻。明明焦虑得要命，手指却诚实地刷着手机。这不是懒，是你的大脑在打架。\n\n想象你面前有两块蛋糕。一块是巧克力，现在就能吃。一块是更大的提拉米苏，但要等一小时。大多数人会抓起巧克力。这就是延迟折扣——大脑把未来的奖励打骨折出售。明天才交的论文，在今天就变得不值一提。\n\n更狡猾的是，大脑会自我欺骗。它说，我先刷五分钟视频，等下效率更高。这叫计划谬误，我们永远高估', 0, 0, 46, NULL, 'latest', NULL, 'https://r2.joyoai.xyz/audio/tts1/studio_concat_1773163632648.mp3', 104, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-11 01:36:04', 0);
INSERT INTO `work` VALUES (2031604412061798402, 2026229317599551489, 2031604401680896002, 'studio', 'podcast', 'Ai时代如何学习？', '咪仔：哈喽大家好欢迎收听我们的播客，然后今天我们想聊一聊在现在这个 AI 飞速发展的这个时代。我们到底应该怎么去学习，嗯对吧因为。这个 AI 确实在改变我们传统的学习方式，也在让我们的教育不断的去创新。甚至说有人说二零二五年会是这个 AI 赋能教育变革的元年。\n\n大一先生：是啊这个话题真的很有意思，那我们就直接开始今天的讨论吧。\n\n咪仔：咱们今天第一个主题呢就是想聊一聊关于这个 AI 时代学习方式', 0, 0, 50, NULL, 'podcast', NULL, 'https://r2.joyoai.xyz/audio/tts1/podcast_1773207197390.mp3', 693, 0, 0, 0, 0, NULL, NULL, 'published', 'approved', NULL, NULL, NULL, 0, 0.00, '2026-03-11 13:33:32', 0);
